int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation always has the same fingerprint.
        // If the original permutation is not a palindrome, its reverse is a different permutation.
        // The problem guarantees a solution always exists.
        // Since n >= 2, a permutation of length n can only be a palindrome if p_i = p_{n-i+1}.
        // For n=2, p=[1,2], p_rev=[2,1]. These are different.
        // For n=3, p=[1,2,3], p_rev=[3,2,1]. These are different.
        // In general, for p to be a palindrome, p_i must be equal to p_{n-i+1}.
        // For example, if n=3, p=[1,2,1] is not a permutation.
        // A permutation cannot be a palindrome unless n=1 (which is not allowed here, n>=2).
        // For n >= 2, p_i = p_{n-i+1} for all i implies that if p_1 = k, then p_n = k.
        // But elements in a permutation must be distinct. So p_1 cannot be equal to p_n unless n=1.
        // Therefore, for n >= 2, p_1 != p_n.
        // This means p cannot be equal to its reverse p_rev.
        // So, reversing the permutation always yields a different permutation with the same fingerprint.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

