#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = k + 1; // Initialize with a value larger than any possible a_i
    int min_idx = -1;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_operations = 0;

    // Iterate through all piles except the one with the minimum value
    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue; // Skip the pile with the minimum value itself
        }

        // For each other pile a[i], add min_val to it as many times as possible
        // The number of times min_val can be added to a[i] is (k - a[i]) / min_val
        // This is integer division, which correctly counts how many full min_val can fit.
        total_operations += (k - a[i]) / min_val;
    }

    std::cout << total_operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

