        long long ans = 0;

        // First, use as many +5 or -5 operations as possible
        ans += diff / 5;
        diff %= 5;

        // Now diff is 0, 1, 2, 3, or 4
        if (diff == 0) {
            // No remaining difference
        } else if (diff == 1) {
            // Can be 1 (+1) or 2 (-2, +1, +1) or 2 (-5, +2, +2)
            // Optimal is 1 (+1)
            ans += 1;
        } else if (diff == 2) {
            // Optimal is 1 (+2)
            ans += 1;
        } else if (diff == 3) {
            // Can be 2 (+1, +2) or 2 (-2, +5)
            // Optimal is 2 (+1, +2)
            ans += 2;
        } else if (diff == 4) {
            // Can be 2 (-1, +5) or 2 (+2, +2)
            // Optimal is 2 (-1, +5) or (+2, +2)
            ans += 2;
