int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        if (n == 1) {
            std::cout << -1 << "\n";
        } else {
            // For n >= 2, we can construct a number.
            // The first digit is 2.
            // The last digit is 3.
            // All intermediate digits are 7.
            // This number will be 277...73 (n-2 sevens).
            //
            // Divisibility by 2: The number ends in 3, so it's not divisible by 2.
            // Divisibility by 3: The sum of digits is 2 + (n-2)*7 + 3 = 5 + 7n - 14 = 7n - 9.
            // For n=2, sum = 7*2 - 9 = 14 - 9 = 5. Not div by 3.
            // For n=3, sum = 7*3 - 9 = 21 - 9 = 12. Div by 3. This construction fails for n=3.
            //
            // Let's use a simpler construction:
            // First digit 2.
            // All other n-1 digits are 3.
            // Number is 233...3.
            // Divisibility by 2: Ends in 3, not div by 2.
            // Divisibility by 3: Sum of digits is 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
            // This sum is never divisible by 3 (since 3n is div by 3, 3n-1 is not).
            // So, this number is not divisible by 2 or 3.
            // All digits are 2 or 3.
            // Thus, this number is not divisible by any of its digits.
            // This works for all n >= 2.

            std::cout << '2';
            for (int i = 0; i < n - 1; ++i) {
                std::cout << '3';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

