void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<int> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;

    int current_color_for_T_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Assign to white (c)
        } else if (a[i] > T_half) {
            p[i] = 1; // Assign to black (d)
        } else { // a[i] == T_half
            if (T_is_even) {
                p[i] = current_color_for_T_half;
                current_color_for_T_half = 1 - current_color_for_T_half; // Alternate color
            } else {
                // T is odd, so T_half is not an integer.
                // a[i] == T_half is impossible for integer a[i].
                // This branch should not be reached if a[i] is integer and T is odd.
                // However, if T_half is calculated as integer division, it might be T/2.
                // But the problem states a_i are non-negative integers.
                // If T is odd, T/2 is not an integer, so a_i cannot be exactly T/2.
                // So this 'else' branch implies a[i] == T_half only if T is even.
                // For safety, if T is odd and a[i] somehow equals T/2 (e.g., T=5, a[i]=2.5, not possible),
                // we would treat it like < T/2 or > T/2.
                // But given integer constraints, this case only happens for even T.
                // So the logic for T_is_even is correct here.
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

