#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags for has_pos_one and has_neg_one should reflect elements
            // *before* index i that can be used to modify a[i].
            // So, if a[i] is 1 or -1, it contributes to the flags for elements j < i.
            // But we are iterating backwards, so we update flags *after* checking a[i].
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires adding 1.
            // A 1 must exist at some index k < i.
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires adding -1.
            // A -1 must exist at some index k < i.
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update flags for elements at indices < i.
        // If a[i] was 1 or -1, it can no longer be used for elements at indices < i
        // because operations are only i < j.
        // So, we remove its contribution to the flags.
        if (a[i] == 1) {
            // This 1 is no longer available for elements to its left.
            // We don't need to explicitly count, just know if *any* exist.
            // The flags `has_pos_one` and `has_neg_one` should represent
            // if there is a 1 or -1 in `a[0...i-1]`.
            // Since we iterate backwards, `has_pos_one` and `has_neg_one`
            // are already correctly representing `a[0...i-1]` when we check `a[i]`.
            // After checking `a[i]`, we effectively "remove" `a[i]` from consideration
            // for future elements (which are to its left).
            // So, if `a[i]` was the *only* 1 or -1, the flag should become false.
            // This requires counting, which is more complex.
            // A simpler approach is to maintain the flags for `a[0...i-1]`
            // *before* processing `a[i]`.
            // Let's re-think the flag logic.
        }
    }

    // Corrected flag logic:
    // `has_pos_one` and `has_neg_one` should track if there's a 1 or -1
    // in `a[0...i-1]` when we are processing `a[i]`.
    // So, we iterate from left to right to build these flags.

    has_pos_one = false;
    has_neg_one = false;
    possible = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] < b[i]) {
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else if (a[i] > b[i]) {
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }
        // If a[i] == b[i], no operation is needed for a[i].
        // But a[i] itself might be 1 or -1, which can be used for a[j] where j > i.
        // So, we update the flags *after* checking a[i] against b[i].
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }


    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
