            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed)
                // The previous 'R' or start was at last_R_pos
                // The current 'R' is at i+1
                // The gap is (i+1) - last_R_pos
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1;
            }
        }

        // After iterating through the string, consider the jump from the last 'R' to n+1
        // Or if no 'R's, from 0 to n+1
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C's stdio and disables synchronization,
    // which can significantly speed up I/O operations.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Declare a vector to store prices.
        // Using std::vector is flexible and handles dynamic sizing.
        // For competitive programming, it's often preferred over raw arrays.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices into the vector
        }

        if (n == 0) { // Edge case: if no days, no bad prices
            std::cout << 0 << "\n";
            continue;
        }
        if (n == 1) { // Edge case: if only one day, no later prices to compare with
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_price_suffix with the price of the last day.
        // This variable will keep track of the minimum price encountered
        // from the current position to the end of the array (suffix minimum).
        int min_price_suffix = a[n - 1];

        // Iterate from the second-to-last day backwards to the first day.
        // We start from n-2 because a[n-1] cannot be a bad price
        // (there are no days after it).
        for (int i = n - 2; i >= 0; --i) {
            // If the current day's price is greater than the minimum price
            // found in any subsequent day (min_price_suffix),
            // then the current day's price is considered "bad".
            if (a[i] > min_price_suffix) {
                bad_prices_count++;
            } else {
                // If the current day's price is not bad, it means it's
                // less than or equal to min_price_suffix.
                // This price now becomes the new minimum for the suffix
                // starting from this day.
                min_price_suffix = a[i];
            }
        }

        // Print the total count of bad prices for the current test case,
        // followed by a newline character.
        std::cout << bad_prices_count << "\n";
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by:
        // 1. The total number of students divided by 3 (since each team needs 3 members).
        // 2. The number of coders (since each team needs at least 1 coder).
        // 3. The number of mathematicians (since each team needs at least 1 mathematician).
        // So, an initial upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'low' for binary search.
        // The actual answer can be at most min(c, m) because each team needs at least one of each.
        // The total number of students is c + m + x.
        // The maximum possible teams is (c + m + x) / 3.
        // So, the absolute maximum is min(c, m, (c + m + x) / 3).
        // We can binary search for the answer 'k'.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound
        long long ans = 0;

        while (low <= high) {
            long long k = low + (high - low) / 2;

            // To form k teams:
            // We need k coders and k mathematicians as minimum.
            // The remaining students are (c - k) coders, (m - k) mathematicians, and x no-specialization students.
            // The total number of remaining students is (c - k) + (m - k) + x.
            // Each of the k teams needs 3 members. We've already accounted for 1 coder and 1 mathematician for each team.
            // So, each team still needs 1 more member.
            // This means we need k additional members in total from the remaining students.
            // If (c - k) + (m - k) + x >= k, then it's possible to form k teams.

            if (k <= c && k <= m && (c - k) + (m - k) + x >= k) {
                ans = k;
                low = k + 1;
            } else {
                high = k - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

