int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use in the alternating sequence to generate k differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right ends of the range [1, k+1]
    // Example: k=2, range [1,3]. Sequence: 1, 3, 2
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}. Count = 2.
    // Example: k=3, range [1,4]. Sequence: 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}. Count = 3.

    bool use_left = true;
    for (int i = 0; i < k + 1; ++i) {
        if (use_left) {
            std::cout << left << " ";
            left++;
        } else {
            std::cout << right << " ";
            right--;
        }
        use_left = !use_left;
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these numbers in increasing order.
    // This will only introduce the difference 1, which is already among the k distinct differences.
    // Example: if k=2, n=5. Sequence so far: 1, 3, 2. Remaining: 4, 5.
    // Append: 1, 3, 2, 4, 5.
    // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1. Distinct: {1,2}. Count = 2.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

