        }

        // The number of full cycles of 10 multiples
        long long full_cycles = num_multiples / 10;
        long long total_sum = full_cycles * sum_cycle;

        // The remaining multiples after full cycles
        long long remaining_multiples = num_multiples % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
