}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i+1]
    // This marks the end of the non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now `a[i...n-1]` is a non-increasing suffix.
    // If i is 0, the whole array is non-increasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the non-decreasing suffix (from the right)
    // and the start of the "valley" or "peak"
    int j = i; // Start search from `i`
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now `a[j...n-1]` is the candidate suffix.
    // `a[j...i-1]` is non-decreasing, `a[i...n-1]` is non-increasing.
    // The prefix to erase is `a[0...j-1]`.
    // The length of this prefix is `j`.

    std::cout << j << std::endl;
}

