void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment [1] is always a permutation of {1}.
    // This subsegment is p[pos[1]...pos[1]].
    ans[0] = '1';

    // min_idx and max_idx will track the minimum and maximum indices
    // encountered so far for numbers 1 to current_m.
    // Initially, for m=1, both are the index of 1.
    int min_idx = pos[1];
    int max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update min_idx and max_idx to include the position of 'm'
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // For the current 'm', the subsegment p[min_idx ... max_idx]
        // contains all numbers from 1 to 'm' (and possibly others).
        // Its length is (max_idx - min_idx + 1).
        // If this length is equal to 'm', it means this subsegment
        // contains exactly the numbers 1 to 'm' and nothing else.
        // (Because it contains 1 to 'm', and its length is 'm',
        // and all numbers in p are distinct).
        if (max_idx - min_idx + 1 == m) {
            ans[m - 1] = '1';
        } else {
            ans[m - 1] = '0';
        }
    }
    std::cout << ans << "\n";
}

