int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (the 'b' array elements)
    int right_ptr = 0; // Pointer for original array elements (the 'a' array elements)

    // We iterate through the sorted array 'a'.
    // 'left_ptr' points to the current element we are trying to place (from the sorted 'a').
    // 'right_ptr' points to the current position in the original sorted array 'a'
    // that we are trying to "beat".
    // We want to find an element a[left_ptr] such that a[left_ptr] > a[right_ptr].
    // If we find such a pair, we increment count and advance both pointers.
    // If a[left_ptr] is not greater than a[right_ptr], it means a[left_ptr] is too small
    // to beat a[right_ptr]. So, we try the next larger element for placement by advancing 'left_ptr'.
    while (left_ptr < n && right_ptr < n) {
        if (a[left_ptr] > a[right_ptr]) {
            // Found an element a[left_ptr] that can be placed at a position
            // where a[right_ptr] originally stood, and a[left_ptr] > a[right_ptr].
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // a[left_ptr] is not greater than a[right_ptr].
            // This means a[left_ptr] cannot beat a[right_ptr].
            // We need a larger element to beat a[right_ptr], so we advance left_ptr.
            // a[right_ptr] still needs to be beaten, so right_ptr stays.
            left_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops: minimum value a[i] can be reduced to
    // to satisfy a[0] < a[1] < ... < a[i]
    // This means a[i] must be at least i.
    // So, a[i] must be >= i.
    // If original a[i] < i, it's impossible for this prefix.
    // We need to find the first index `i` where `a[i] < i`.
    // If such an `i` exists, then no `k >= i+1` can be a peak.
    // The peak `k` must satisfy `a_k >= k-1`.
    // The condition `a_i >= i-1` for `i=0..k-1` (0-indexed)
    // is equivalent to `a_i >= i` for `i=0..k-1` if we consider the values
    // `a_0, a_1, ..., a_{k-1}` must be `0, 1, ..., k-1` at minimum.
    // So, `a[i]` must be at least `i` for `i` from `0` to `k-1`.
    // Let's find the first `i` such that `a[i] < i`.
    // If `a[i] < i`, then it's impossible to make `a[i]` equal to `i` or more.
    // So, any peak `k` must be such that `k-1 < i`.
    // This means `k <= i`.
    // If `a[i] < i`, then `i` cannot be part of a strictly increasing prefix `0, 1, ..., i`.
