    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // The number of 'a's currently to the left of this 'b'
            // is `count_a`.
            // Each such 'a' will cause `count_a` operations involving this 'b'.
            // Specifically, when an 'a' moves past this 'b', it creates a new 'b'.
            // The 'a' then needs to move past this new 'b' as well.
            // The total number of operations this 'b' contributes is `count_a`.
            // After this 'b' is processed, it effectively doubles the number of 'a's
            // that will interact with subsequent 'b's to its left.
            // This is because each 'a' that passes this 'b' creates a new 'b',
            // and this new 'b' will also need to be passed by 'a's further left.
            // The number of 'a's effectively doubles for the next 'b' to the left.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are currently to the right of any 'b's we've processed so far.
            // These 'a's will interact with 'b's further to their left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

