// Function to check if a subarray is a permutation
bool is_permutation(const std::vector<int>& arr, int start_idx, int length) {
    if (length == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem implies length >= 1
    }
    if (length > arr.size() - start_idx) {
        return false; // Not enough elements
    }

    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = 0; i < length; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > length || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == length;
}

