long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // n is odd
            chanek_coins += 1;
            n -= 1;
        } else { // n is even
            // Option 1: Take 1 coin
            // Remaining coins: n-1. Next turn, opponent takes 1.
            // Chanek gets 1. Opponent gets 1.
            // This is always an option.

            // Option 2: Take n/2 coins
            // Remaining coins: n/2.
            // This is only an option if n is even.

            // If n is a power of 2 (and n > 2), say n = 2^k (k > 1)
            // Taking 1: n-1 coins. Opponent takes 1. Chanek gets 1.
            // Taking n/2: n/2 coins. Opponent takes n/4 (if n/2 is even), or 1 (if n/2 is odd).
            // If n is a power of 2, n/2 is also a power of 2.
            // The opponent will take n/4, then n/8, etc.
            // This means the opponent will take all remaining coins in subsequent turns if n is a power of 2.
            // Example: n=8. Chanek takes 4. Remaining 4. Opponent takes 2. Remaining 2. Chanek takes 1. Remaining 1. Opponent takes 1.
            // Chanek: 4+1=5. Opponent: 2+1=3.
            // If Chanek takes 1: Remaining 7. Opponent takes 1. Remaining 6. Chanek takes 3. Remaining 3. Opponent takes 1. Remaining 2. Chanek takes 1. Remaining 1. Opponent takes 1.
            // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
            // In this case, taking n/2 is better for Chanek.

            // If n is even but not a power of 2, it has an odd factor.
            // Let n = 2^k * M, where M is odd and M > 1.
            // If Chanek takes n/2: n/2 = 2^(k-1) * M.
            // If Chanek takes 1: n-1. This is odd. Opponent takes 1. Remaining n-2.
            // The key insight is that if n is even, taking n/2 leaves n/2 coins.
            // If n/2 is odd, the opponent is forced to take 1.
            // If n/2 is even, the opponent has a choice.

            // Consider the opponent's turn. If they face an even number of coins, they will also try to maximize their share.
            // If n is even, and we take n/2, the opponent faces n/2.
            // If n is even, and we take 1, the opponent faces n-1 (odd). They take 1. Then we face n-2.

            // The strategy is: if n is even, and n is not a power of 2, take 1.
            // Why? If n is even and not a power of 2, then n = 2^k * M where M > 1 and M is odd.
            // If we take n/2, we get n/2. The opponent faces n/2 = 2^(k-1) * M.
            // If we take 1, we get 1. The opponent faces n-1 (odd). They take 1. We face n-2.
            // This is a greedy approach.
            // If n is a power of 2, say n = 2^k, then taking n/2 is always optimal for the current player.
            // Because if you take 1, the opponent gets to take 1, and then you face 2^k-2.
            // If you take n/2, you get n/2, and the opponent faces n/2.
            // The opponent will then take n/4, and so on.
            // This means if n is a power of 2, the current player takes n/2, then the next player takes n/4, etc.
            // The current player gets n/2 + n/8 + n/32 + ...
            // The opponent gets n/4 + n/16 + n/64 + ...
            // Total for current player: n * (1/2 + 1/8 + ...) = n * ( (1/2) / (1 - 1/4) ) = n * ( (1/2) / (3/4) ) = n * (2/3)
            // Total for opponent: n * (1/4 + 1/16 + ...) = n * ( (1/4) / (1 - 1/4) ) = n * ( (1/4) / (3/4) ) = n * (1/3)
            // So if n is a power of 2, taking n/2 yields 2/3 of coins for the current player.
            // If n is a power of 2 and we take 1, we get 1. Opponent gets 1. We face n-2.
            // This is clearly worse than taking n/2.

            // So, if n is a power of 2, take n/2.
            // Otherwise (n is even but not a power of 2), take 1.
            // This is because if n is even and not a power of 2, it means n has an odd factor M > 1.
            // If we take n/2, the opponent faces n/2. If n/2 is odd, opponent takes 1. If n/2 is even, opponent might take n/4.
            // If we take 1, opponent faces n-1 (odd), takes 1. We face n-2.
            // The strategy is to avoid giving the opponent a large even number if possible.
            // If n is even and not a power of 2, then n/2 is also not a power of 2 (unless n=2*M, M odd, M>1, then n/2=M is odd).
            // If n/2 is odd, opponent takes 1.
            // If n/2 is even and not a power of 2, opponent takes 1.
            // If n/2 is a power of 2, opponent takes n/4.

            // Let's simplify:
            // If n is even:
            //   If n is a power of 2 (n = 2^k):
            //     Chanek takes n/2. Opponent faces n/2.
            //     Chanek gets n/2 + n/8 + n/32 + ...
            //     Opponent gets n/4 + n/16 + n/64 + ...
            //     Chanek gets 2/3 of n.
            //   If n is even but not a power of 2:
            //     Chanek takes 1. Opponent faces n-1 (odd). Opponent takes 1. Chanek faces n-2.
            //     This seems to be the optimal strategy for Chanek.
            //     By taking 1, Chanek ensures the opponent faces an odd number, forcing them to take 1.
            //     This effectively makes it a game where players take 1 coin each turn until an even number is reached.
            //     If Chanek takes n/2, the opponent might get a good opportunity.

            // Let's test this hypothesis.
            // N=6.
            // Chanek's turn, N=6 (even, not power of 2).
            //   Option 1: Take 1. Chanek gets 1. N=5.
            //     Opponent's turn, N=5 (odd). Opponent takes 1. N=4.
            //     Chanek's turn, N=4 (even, power of 2). Chanek takes 4/2=2. N=2.
            //     Opponent's turn, N=2 (even, power of 2). Opponent takes 2/2=1. N=1.
            //     Chanek's turn, N=1 (odd). Chanek takes 1. N=0.
            //     Chanek total: 1 + 2 + 1 = 4. Opponent total: 1 + 1 = 2.
            //   Option 2: Take 6/2=3. Chanek gets 3. N=3.
            //     Opponent's turn, N=3 (odd). Opponent takes 1. N=2.
            //     Chanek's turn, N=2 (even, power of 2). Chanek takes 2/2=1. N=1.
            //     Opponent's turn, N=1 (odd). Opponent takes 1. N=0.
            //     Chanek total: 3 + 1 = 4. Opponent total: 1 + 1 = 2.
            // Both options yield 4 for Chanek. The example output for N=6 is 4.
            // This suggests that for N=6, both options are equally good for Chanek.
            // The strategy "if N is even and not a power of 2, take 1" works for N=6.

            // N=5.
            // Chanek's turn, N=5 (odd). Chanek takes 1. N=4. Chanek gets 1.
            // Opponent's turn, N=4 (even, power of 2). Opponent takes 4/2=2. N=2. Opponent gets 2.
            // Chanek's turn, N=2 (even, power of 2). Chanek takes 2/2=1. N=1. Chanek gets 1.
            // Opponent's turn, N=1 (odd). Opponent takes 1. N=0. Opponent gets 1.
            // Chanek total: 1 + 1 = 2. Opponent total: 2 + 1 = 3.
            // Example output for N=5 is 2. This matches.

            // The strategy seems to be:
            // If N is odd: take 1.
            // If N is even:
            //   If N is a power of 2: take N/2.
            //   If N is even but not a power of 2: take 1.

            // Let's implement this.
            // How to check if N is a power of 2? (N > 0) && ((N & (N - 1)) == 0).
            if ((n & (n - 1)) == 0) { // n is a power of 2
                chanek_coins += n / 2;
                n /= 2;
            } else { // n is even but not a power of 2
                chanek_coins += 1;
                n -= 1;
            }
        }
    }
    return chanek_coins;
}

