// Function to convert an integer to its parity pattern string
// The pattern is always 18 characters long, padded with '0's (even) from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This effectively pads with '0's from the left in the original number's representation
    // because we built the string from right to left digits.
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

