            // Pad the query pattern 's' with '0's from the left to make it 18 characters long.
            // This is equivalent to padding with '0's from the right in the string representation
            // because the pattern matching rule considers digits from right to left.
            while (s.length() < 18) {
                s = '0' + s; // Prepend '0'
            }
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

