// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must be divisible by f_i^a_i for all i.
        // To make x not divisible by q, we must remove at least one factor f_i from x
        // such that x is no longer divisible by f_i^a_i.
        // We want to maximize x, so we should remove as few factors as possible.
        // This means for some prime factor f_i of q, we need to reduce the power of f_i in x
        // to be less than a_i.
        // The best strategy is to take p, and for each prime factor f_i of q,
        // divide p by f_i until p is no longer divisible by q.
        // More precisely, for each prime factor f_i of q, calculate p' = p / f_i^k where f_i^k is the highest power of f_i that divides p.
        // Then, p' * f_i^(k-1) would be a candidate for x.
        // We want to find the maximum such candidate.

        std::vector<long long> prime_factors_of_q = get_prime_factors(q);
        long long max_x = 1; // Since p >= 1, there's always at least 1.

        for (long long f : prime_factors_of_q) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q.
            // This means we divide current_p by f until (current_p / f) % q != 0.
            // Or, more simply, divide current_p by f until current_p is no longer divisible by q.
            // No, this is not correct. We need to find the largest divisor of p that is not divisible by q.
            // If p is divisible by q, we need to remove factors from p.
            // For each prime factor f of q, we can try to remove all factors of f from p.
            // Let p = P * f^k where P is not divisible by f.
            // If we want x not divisible by q, and f is a prime factor of q,
            // then we can try x = p / f. If p/f is still divisible by q, then try p/f^2, etc.
            // The largest divisor of p that is not divisible by q, and is formed by removing factors of f,
            // would be p / f^k where f^k is the highest power of f that divides p, AND p / f^k is not divisible by q.
            // This is equivalent to finding the largest m such that p / m is not divisible by q, and m is a power of f.
            // The largest such x would be p / (f * (highest power of f that divides p/q)).
            // Let's rephrase:
            // We have p. We know p % q == 0.
            // For each prime factor f of q:
            //   Calculate p_temp = p.
            //   While p_temp is divisible by q:
            //     p_temp /= f;
            //   The resulting p_temp is a candidate for x.
            //   We take the maximum among all such candidates.

            long long temp_p = p;
            while (temp_p % q == 0) {
                temp_p /= f;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum_k = sum_{k=1 to a} k
    // Sum_k = a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = sum_k * ((MOD + 1) / 2) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum_r = sum_{r=1 to b-1} r
    // Sum_r = (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = sum_r * ((MOD + 1) / 2) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // The total sum is (sum_k * b + a) * sum_r
    // Let's calculate (sum_k * b + a) first
    long long term1 = (sum_k * (b % MOD)) % MOD;
    term1 = (term1 + (a % MOD)) % MOD;

    long long ans = (term1 * sum_r) % MOD;

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<int> degree(26, 0);
    std::vector<bool> in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        in_s[s[i] - 'a'] = true;
        if (i > 0) {
            char c1 = s[i-1];
            char c2 = s[i];
            if (adj[c1 - 'a'].find(c2) == adj[c1 - 'a'].end()) {
                adj[c1 - 'a'].insert(c2);
                adj[c2 - 'a'].insert(c1);
                degree[c1 - 'a']++;
                degree[c2 - 'a']++;
            }
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (degree[i] > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && degree[i] <= 1 && !visited[i]) { // Start a path from an endpoint or isolated char in s
            char current_char = (char)('a' + i);

            // Traverse forward
            while (current_char != 0 && !visited[current_char - 'a']) {
                layout += current_char;
                visited[current_char - 'a'] = true;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                current_char = next_char;
            }
        }
    }

    // Check if all characters from s are included in the layout
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && !visited[i]) {
            // This means there's a cycle or a path that wasn't started from an endpoint
            // For example, if s="abc", degree of 'b' is 2, 'a' and 'c' are 1.
            // If we start from 'a', we get "abc". 'b' is visited.
            // If s="abacaba", 'a' has degree 2, 'b' has degree 2, 'c' has degree 2.
            // This case is handled by the degree check.
            // The only remaining case for unvisited `in_s` characters would be if `s` forms a cycle,
            // which is impossible with degree <= 2 and no self-loops.
            // Or if `s` forms a path but we didn't start from an endpoint.
            // The current logic should cover all paths.
            // If `in_s[i]` is true and `visited[i]` is false, it implies an issue.
            // However, with degree <= 2, all components are paths or isolated vertices.
            // We iterate through all `i` from 0 to 25. If `in_s[i]` is true and `degree[i] <= 1`,
            // we start a traversal. This should cover all paths.
            // If `in_s[i]` is true and `degree[i] == 2`, it must be part of a path.
            // If it's not visited, it means the path it belongs to wasn't fully traversed.
            // This can only happen if the path was not started from one of its endpoints.
            // But we iterate through all possible starting points (degree <= 1).
            // So, if `in_s[i]` is true and `visited[i]` is false, it's an error.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));

    // If n is a perfect square, k*k = n.
    // We want to construct a permutation where LIS = k and LDS = k.
    // This can be done by dividing the numbers 1 to n into k blocks of size k.
    // For example, for n=9, k=3:
    // Block 1: 1 2 3
    // Block 2: 4 5 6
    // Block 3: 7 8 9
    // Permutation: [3 2 1, 6 5 4, 9 8 7]
    // LIS: [1, 4, 7] (length 3)
    // LDS: [3, 2, 1] (length 3)
    // Sum = 6.
    // This construction gives LIS = k and LDS = k.

    // If n is not a perfect square, k*k < n.
    // We can still use blocks.
    // Let k = floor(sqrt(n)).
    // We want LIS and LDS to be close to sqrt(n).
    // A construction that achieves LIS = ceil(n/k) and LDS = k is as follows:
    // Divide numbers 1 to n into blocks of size k.
    // The last block might be smaller.
    // For each block, reverse the order of elements.
    // Example: n=4, k=2
    // Blocks: [1,2], [3,4]
    // Permutation: [2,1,4,3]
    // LIS: [2,4] or [1,3] (length 2)
    // LDS: [2,1] or [4,3] (length 2)
    // Sum = 4.
    // Here, ceil(n/k) = ceil(4/2) = 2. LIS = 2, LDS = 2.

    // Example: n=5, k=2
    // Blocks: [1,2], [3,4], [5]
    // Permutation: [2,1,4,3,5]
    // LIS: [2,4,5] or [1,3,5] (length 3)
    // LDS: [2,1] or [4,3] (length 2)
    // Sum = 5.
    // Here, ceil(n/k) = ceil(5/2) = 3. LIS = 3, LDS = 2.

    // The general construction:
    // Iterate from i = 0 to n-1.
    // The number at index i in the permutation will be part of block (i / k).
    // The numbers in block j (0-indexed) are from (j*k + 1) to min((j+1)*k, n).
    // To reverse the block, for an element at index i, its value is
    // (j*k + k) - (i % k).
    // Or more simply, for each block starting at `start_val`, print `start_val + k - 1`, `start_val + k - 2`, ..., `start_val`.
    // But we need to handle the last block which might be smaller.

    // Let's refine the block construction.
    // We want to print numbers in groups of `k`.
    // For each group, print them in decreasing order.
    // The groups are `1..k`, `k+1..2k`, etc.
    // The last group will be `(num_blocks-1)*k + 1 .. n`.

    int current_val = n;
    while (current_val > 0) {
        int start_of_block = std::max(1, current_val - k + 1);
        for (int i = current_val; i >= start_of_block; --i) {
            std::cout << i << " ";
        }
        current_val = start_of_block - 1;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> next_char_pos(n, std::vector<int>(26, n));
    for (int i = n - 1; i >= 0; --i) {
        if (i < n - 1) {
            next_char_pos[i] = next_char_pos[i + 1];
        }
        next_char_pos[i][s[i] - 'a'] = i;
    }

    std::vector<std::vector<int>> prev_char_pos(n, std::vector<int>(26, -1));
    for (int i = 0; i < n; ++i) {
        if (i > 0) {
            prev_char_pos[i] = prev_char_pos[i - 1];
        }
        prev_char_pos[i][s[i] - 'a'] = i;
    }

    std::vector<std::vector<int>> count_pairs(26, std::vector<int>(26, 0));
    std::vector<int> count_first_char(26, 0);

    for (int k = 0; k < n; ++k) {
        count_first_char[s[k] - 'a']++;
        for (int p = 1; p < n; ++p) {
            count_pairs[s[k] - 'a'][s[(k + p) % n] - 'a']++;
        }
    }

    double total_win_prob = 0.0;

    for (int first_char_val = 0; first_char_val < 26; ++first_char_val) {
        if (count_first_char[first_char_val] == 0) {
            continue;
        }

        double max_win_prob_for_char = 0.0;

        for (int p = 1; p < n; ++p) {
            int current_p_win_count = 0;
            for (int second_char_val = 0; second_char_val < 26; ++second_char_val) {
                int count = 0;
                for (int k = 0; k < n; ++k) {
                    if (s[k] - 'a' == first_char_val && s[(k + p) % n] - 'a' == second_char_val) {
                        count++;
                    }
                }
                if (count == 1) {
                    current_p_win_count++;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)current_p_win_count / count_first_char[first_char_val]);
        }
        total_win_prob += max_win_prob_for_char * count_first_char[first_char_val];
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total difference
    int initial_diff = 0;
    for (int x : a) {
        if (x == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Precompute prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s) - (count of 2s) among jars n, n-1, ..., n-k+1
    // This is equivalent to jars a[n-1], a[n-2], ..., a[n-k]
    std::vector<int> diff_L(n + 1, 0);
    for (int k = 0; k < n; ++k) {
        int val = (a[n - 1 - k] == 1) ? 1 : -1;
        diff_L[k + 1] = diff_L[k] + val;
    }

    // Precompute prefix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s) - (count of 2s) among jars n+1, n+2, ..., n+k
    // This is equivalent to jars a[n], a[n+1], ..., a[n+k-1]
    std::vector<int> diff_R(n + 1, 0);
    for (int k = 0; k < n; ++k) {
        int val = (a[n + k] == 1) ? 1 : -1;
        diff_R[k + 1] = diff_R[k] + val;
    }

    // Store minimum k_L for each diff_L value
    std::map<int, int> min_kL_for_diff;
    for (int kL = 0; kL <= n; ++kL) {
        int current_diff_L = diff_L[kL];
        if (min_kL_for_diff.find(current_diff_L) == min_kL_for_diff.end()) {
            min_kL_for_diff[current_diff_L] = kL;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate over all possible k_R values
    for (int kR = 0; kR <= n; ++kR) {
        int current_diff_R = diff_R[kR];
        // The target difference for the remaining jars is 0.
        // The total difference of all jars is initial_diff.
        // If we remove kL jars from left and kR jars from right,
        // the difference of removed jars is diff_L[kL] + diff_R[kR].
        // The difference of remaining jars is initial_diff - (diff_L[kL] + diff_R[kR]).
        // We want this to be 0.
        // So, we need initial_diff - diff_L[kL] - diff_R[kR] = 0
        // which means diff_L[kL] = initial_diff - diff_R[kR].

        int target_diff_L = initial_diff - current_diff_R;

        if (min_kL_for_diff.count(target_diff_L)) {
            int kL = min_kL_for_diff[target_diff_L];
            min_removed_jars = std::min(min_removed_jars, kL + kR);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

