    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        bool possible = true;
        long long prev_b = 0; // The smallest possible value for b_i, given b_{i-1}

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];
            long long current_b;

            // Case 1: current_a + mid >= prev_b
            // This means current_a can be incremented to current_a + x, where x <= mid.
            // We want to find the smallest current_b >= prev_b.
            // If current_a >= prev_b, we can choose current_b = current_a.
            // The number of increments needed is 0, which is <= mid.
            // If current_a < prev_b, we must increment current_a.
            // The smallest value current_a can take that is >= prev_b is prev_b itself.
            // The number of increments needed is (prev_b - current_a + m) % m.
            // If (prev_b - current_a + m) % m <= mid, then we can achieve prev_b.
            // In this case, current_b = prev_b.
            // Otherwise, we cannot achieve prev_b. The smallest value we can achieve
            // is current_a (if current_a >= prev_b) or current_a + (prev_b - current_a + m) % m
            // (if current_a < prev_b and (prev_b - current_a + m) % m <= mid).
            // The logic below simplifies this:
            // We need b_i >= prev_b.
            // If a_i >= prev_b:
            //   We can choose b_i = a_i. This requires 0 operations.
            //   0 <= mid is always true. So we can set b_i = a_i.
            //   The smallest possible b_i is a_i.
            //   However, we can also choose b_i = prev_b if prev_b >= a_i.
            //   If a_i >= prev_b, we can choose b_i = a_i.
            //   If a_i < prev_b:
            //     We need to increment a_i. The target value must be >= prev_b.
            //     The smallest target value is prev_b.
            //     The number of increments needed is (prev_b - a_i + m) % m.
            //     If this is <= mid, then we can achieve prev_b. So b_i = prev_b.
            //     Otherwise, we cannot achieve prev_b. The smallest value we can achieve
            //     is a_i + mid. This value must be >= prev_b.
            //     If a_i + mid < prev_b, then it's impossible.
            //     This means we need to check if a_i + mid >= prev_b.
            //     If a_i + mid < prev_b, then it's impossible to make b_i >= prev_b
            //     with at most `mid` operations.
            //     So, if a_i < prev_b, we check if (prev_b - a_i + m) % m <= mid.
            //     If it is, we set current_b = prev_b.
            //     If it is not, then it's impossible.
            //
            // Let's rephrase: we need to find b_i such that b_i >= prev_b and (b_i - a_i + m) % m <= mid.
            //
            // If a_i >= prev_b:
            //   We can choose b_i = a_i. This requires 0 operations, which is <= mid.
            //   So, the smallest possible b_i is prev_b.
            //   We can set current_b = prev_b.
            //   Example: a_i=5, prev_b=3, mid=1. We can choose b_i=5. But we need b_i >= prev_b.
            //   The smallest b_i we can choose is prev_b=3.
            //   If we choose b_i=3, (3-5+m)%m. If m=7, (3-5+7)%7 = 5. If mid=1, this is not allowed.
            //   So if a_i >= prev_b, we can choose b_i = a_i (0 ops).
            //   Or we can choose b_i = prev_b if (prev_b - a_i + m) % m <= mid.
            //   We want to make b_i as small as possible, so we prefer prev_b.
            //   If a_i >= prev_b:
            //     If (a_i + mid) % m >= prev_b (this means we can reach prev_b by incrementing a_i, or a_i itself is >= prev_b)
            //     and (a_i + mid) % m is "after" a_i in modular arithmetic,
            //     and prev_b is "before" a_i + mid.
            //     This is getting complicated.
            //
            // Let's use the condition: we need to find x_i such that (a_i + x_i) % m >= prev_b and x_i <= mid.
            // We want to minimize (a_i + x_i) % m.
            //
            // If a_i >= prev_b:
            //   We can choose x_i = 0, so b_i = a_i. This satisfies b_i >= prev_b and x_i <= mid.
            //   We can also potentially choose a smaller b_i, specifically prev_b.
            //   To get b_i = prev_b, we need x_i = (prev_b - a_i + m) % m.
            //   If this x_i <= mid, then we can set b_i = prev_b.
            //   Otherwise, we must set b_i = a_i (since we can't reach prev_b with <= mid ops, and a_i is the next smallest valid value).
            //   So, if a_i >= prev_b:
            //     If (prev_b - a_i + m) % m <= mid, then current_b = prev_b.
            //     Else, current_b = a_i.
            // Else (a_i < prev_b):
            //   We must increment a_i.
            //   The smallest value we can target is prev_b.
            //   To get b_i = prev_b, we need x_i = (prev_b - a_i + m) % m.
            //   If this x_i <= mid, then current_b = prev_b.
            //   Else, it's impossible to make b_i >= prev_b with <= mid ops. So possible = false.

            if (current_a >= prev_b) {
                // Option 1: Don't increment current_a, so b_i = current_a. This is valid (0 ops <= mid).
                // Option 2: Increment current_a to prev_b. This requires (prev_b - current_a + m) % m operations.
                // If (prev_b - current_a + m) % m <= mid, then we can choose b_i = prev_b.
                // We want to make b_i as small as possible, so we prefer prev_b if possible.
                if ((prev_b - current_a + m) % m <= mid) {
                    current_b = prev_b;
                } else {
                    current_b = current_a;
                }
            } else { // current_a < prev_b
                // We must increment current_a to at least prev_b.
                // The number of operations needed to reach prev_b is (prev_b - current_a + m) % m.
                if ((prev_b - current_a + m) % m <= mid) {
                    current_b = prev_b;
                } else {
                    possible = false;
                    break;
                }
            }
            prev_b = current_b;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

