        // For each bit i:
        // (s0, s1)
        // 1. (0,0) (always 0):
        //    x & 0 = 0. So A_i=0.
        //    x | 0 = x. So O_i=0.
        //    x ^ 0 = x. So X_i=0.
        //    To get (0,0):
        //    A_i=0, O_i=0, X_i=0.
        //    (x & 0) | 0 ^ 0 = 0.
        //    (x | 0) & 0 ^ 0 = 0.
        //    (x ^ 0) & 0 | 0 = 0.
        //    This means for (0,0), we need A_i=0, O_i=0, X_i=0.
        //    This means final_and_val_i = 0, final_or_val_i = 0, final_xor_val_i = 0.

        // 2. (0,1) (identity):
        //    x & 1 = x. So A_i=1.
        //    x | 0 = x. So O_i=0.
        //    x ^ 0 = x. So X_i=0.
        //    To get (0,1):
        //    A_i=1, O_i=0, X_i=0.
        //    (x & 1) | 0 ^ 0 = x.
        //    (x | 0) & 1 ^ 0 = x.
        //    (x ^ 0) & 1 | 0 = x.
        //    This means for (0,1), we need A_i=1, O_i=0, X_i=0.
        //    This means final_and_val_i = 1, final_or_val_i = 0, final_xor_val_i = 0.

        // 3. (1,0) (flip):
        //    x & 0 = 0.
        //    x | 1 = 1.
        //    x ^ 1 = x_i ^ 1.
        //    To get (1,0):
        //    A_i=1, O_i=0, X_i=1.
        //    (x & 1) | 0 ^ 1 = x ^ 1.
        //    (x | 0) & 1 ^ 1 = x ^ 1.
        //    (x ^ 1) & 1 | 0 = x ^ 1.
        //    This means for (1,0), we need A_i=1, O_i=0, X_i=1.
        //    This means final_and_val_i = 1, final_or_val_i = 0, final_xor_val_i = 1.

        // 4. (1,1) (always 1):
        //    x & 1 = x.
        //    x | 1 = 1.
        //    x ^ 1 = x_i ^ 1.
        //    To get (1,1):
        //    A_i=1, O_i=1, X_i=0.
        //    (x & 1) | 1 ^ 0 = x | 1 = 1.
        //    (x | 1) & 1 ^ 0 = 1 & 1 ^ 0 = 1.
        //    (x ^ 0) & 1 | 1 = x & 1 | 1 = 1.
        //    This means for (1,1), we need A_i=1, O_i=1, X_i=0.
        //    This means final_and_val_i = 1, final_or_val_i = 1, final_xor_val_i = 0.

        // Let's define the target values for A, O, X based on these.
        // A_val: bits that should be 1 for identity/flip/always1, 0 for always0.
        // O_val: bits that should be 1 for always1, 0 otherwise.
        // X_val: bits that should be 1 for flip, 0 otherwise.

        // Initialize A_val to all 1s (1023), O_val to all 0s, X_val to all 0s.
        // Then for each bit i:
        // If (s0, s1) is (0,0):
        //   A_i must be 0. O_i must be 0. X_i must be 0.
        //   final_and_val &= ~(1 << i);
        //   final_or_val &= ~(1 << i); // Already 0
        //   final_xor_val &= ~(1 << i); // Already 0
        // If (s0, s1) is (0,1):
        //   A_i must be 1. O_i must be 0. X_i must be 0.
        //   final_and_val |= (1 << i); // Already 1
        //   final_or_val &= ~(1 << i); // Already 0
        //   final_xor_val &= ~(1 << i); // Already 0
        // If (s0, s1) is (1,0):
        //   A_i must be 1. O_i must be 0. X_i must be 1.
        //   final_and_val |= (1 << i); // Already 1
        //   final_or_val &= ~(1 << i); // Already 0
        //   final_xor_val |= (1 << i);
        // If (s0, s1) is (1,1):
        //   A_i must be 1. O_i must be 1. X_i must be 0.
        //   final_and_val |= (1 << i); // Already 1
        //   final_or_val |= (1 << i);
        //   final_xor_val &= ~(1 << i); // Already 0

        // Let's re-initialize:
        final_and_val = 1023; // A_i=1 for identity, flip, always1.
        final_or_val = 0;     // O_i=1 for always1.
        final_xor_val = 0;    // X_i=1 for flip.

        for (int i = 0; i < 10; ++i) {
            int s0 = bit_state[i][0];
            int s1 = bit_state[i][1];

            if (s0 == 0 && s1 == 0) { // Always 0
                final_and_val &= ~(1 << i); // A_i = 0
                // O_i = 0, X_i = 0 (already)
            } else if (s0 == 0 && s1 == 1) { // Identity
                // A_i = 1 (already)
                // O_i = 0, X_i = 0 (already)
            } else if (s0 == 1 && s1 == 0) { // Flip
                // A_i = 1 (already)
                // O_i = 0 (already)
                final_xor_val |= (1 << i); // X_i = 1
            } else { // (s0 == 1 && s1 == 1) Always 1
                // A_i = 1 (already)
                final_or_val |= (1 << i); // O_i = 1
                // X_i = 0 (already)
            }
        }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_val != 1023) { // If A is not all 1s
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If O is not all 0s
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) { // If X is not all 0s
        result_ops.push_back({'^', final_xor_val});
    }

    // Special case for identity: if A=1023, O=0, X=0, then it's identity.
    // My logic would produce no ops if A=1023, O=0, X=0.
    // But if A=1023, O=0, X=0, then result_ops would be empty.
    // This is correct for the example.

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n); // a_suffix[k] stores a_{k+1}
    for (int k = 0; k < n - 1; ++k) {
        std::cin >> a_suffix[k];
    }

    // dp_x[k] stores the final x value if we start at index k+1 with a_k+1
    // dp_y[k] stores the final y value if we start at index k+1 with a_k+1
    // dp_x[k] = 0 means it terminates at x <= 0
    // dp_x[k] = n+1 means it terminates at x > n
    // dp_x[k] = -1 means it's part of a cycle (non-terminating)
    std::vector<long long> dp_x(n + 1);
    std::vector<long long> dp_y(n + 1);
    std::vector<bool> visited(n + 1, false); // For cycle detection

    // Base cases:
    // If x + a_x <= 0, then x becomes <= 0.
    // If x + a_x > n, then x becomes > n.
    // In these cases, the program terminates after step_add.
    // The y value is just a_x.
    // The final x value is 0 or n+1 respectively.
    //
    // If x - a_x <= 0, then x becomes <= 0.
    // If x - a_x > n, then x becomes > n.
    // In these cases, the program terminates after step_sub.
    // The y value is a_x + a_x = 2*a_x.
    // The final x value is 0 or n+1 respectively.

    // Iterate backwards from n to 1
    for (int k = n; k >= 1; --k) {
        long long current_a_val = a_suffix[k - 1]; // a_k

        long long next_x_after_add = k + current_a_val;
        long long next_x_after_sub = k - current_a_val;

        if (next_x_after_add <= 0) { // Terminates after step_add
            dp_x[k] = 0;
            dp_y[k] = current_a_val;
        } else if (next_x_after_add > n) { // Terminates after step_add
            dp_x[k] = n + 1;
            dp_y[k] = current_a_val;
        } else { // Continues to step_sub
            if (next_x_after_sub <= 0) { // Terminates after step_sub
                dp_x[k] = 0;
                dp_y[k] = current_a_val + current_a_val;
            } else if (next_x_after_sub > n) { // Terminates after step_sub
                dp_x[k] = n + 1;
                dp_y[k] = current_a_val + current_a_val;
            } else { // Continues to next iteration
                // This is where we use DP. The next state is (next_x_after_sub, current_a_val + current_a_val + dp_y[next_x_after_sub])
                // We need to handle cycles.

                // Simulate the path from k to detect cycles or find a known state
                std::vector<int> path;
                int current_pos = k;
                long long current_total_y = 0;

                while (current_pos >= 1 && current_pos <= n && !visited[current_pos] && dp_x[current_pos] == 0) { // dp_x[current_pos] == 0 means not yet computed
                    visited[current_pos] = true;
                    path.push_back(current_pos);

                    long long val_at_pos = a_suffix[current_pos - 1];
                    current_total_y += val_at_pos; // y after step_add

                    long long next_x_after_add_path = current_pos + val_at_pos;
                    if (next_x_after_add_path <= 0 || next_x_after_add_path > n) {
                        current_pos = (next_x_after_add_path <= 0) ? 0 : n + 1;
                        break;
                    }

                    current_total_y += val_at_pos; // y after step_sub
                    current_pos = next_x_after_add_path - val_at_pos; // x after step_sub
                }

                if (current_pos <= 0 || current_pos > n) { // Terminated
                    for (int p_idx = 0; p_idx < path.size(); ++p_idx) {
                        int p = path[p_idx];
                        dp_x[p] = current_pos;
                        dp_y[p] = current_total_y;
                        current_total_y -= (2 * a_suffix[p - 1]); // Subtract 2*a_p to get y for previous state
                    }
                } else if (dp_x[current_pos] == -1) { // Cycle detected
                    for (int p : path) {
                        dp_x[p] = -1;
                        dp_y[p] = -1;
                    }
                } else { // Reached a previously computed state
                    long long final_x_from_known = dp_x[current_pos];
                    long long final_y_from_known = dp_y[current_pos];

                    for (int p_idx = path.size() - 1; p_idx >= 0; --p_idx) {
                        int p = path[p_idx];
                        dp_x[p] = final_x_from_known;
                        dp_y[p] = final_y_from_known + (2 * a_suffix[p - 1]);
                        final_y_from_known = dp_y[p]; // Update for the next iteration (previous state in path)
                    }
                }

                // Reset visited for the current path
                for (int p : path) {
                    visited[p] = false;
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        long long a1_val = i;
        long long current_y = 0;
        int current_x = 1;

        // First step_add
        current_y += a1_val;
        int next_x_after_add = current_x + a1_val;

        if (next_x_after_add <= 0 || next_x_after_add > n) {
            std::cout << current_y << "\n";
        } else {
            // First step_sub
            current_y += a1_val;
            int next_x_after_sub = next_x_after_add - a1_val;

            if (next_x_after_sub <= 0 || next_x_after_sub > n) {
                std::cout << current_y << "\n";
            } else {
                // Now we are at state (next_x_after_sub, current_y) and need to continue
                // This is where we use the precomputed DP values
                if (dp_x[next_x_after_sub] == -1) { // Cycle detected
                    std::cout << -1 << "\n";
                } else {
                    std::cout << current_y + dp_y[next_x_after_sub] << "\n";
                }
            }
        }
    }

    return 0;
}

#include <iostream>
