int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        long long count = 0;
        int n = s.length();

        // Precompute prefix sums of '0's
        std::vector<int> prefix_zeros(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            prefix_zeros[i + 1] = prefix_zeros[i] + (s[i] == '0');
        }

        for (int i = 0; i < n; ++i) {
            if (s[i] == '0') {
                continue; // A good substring must start with '1' to have a value >= 1
                          // The only exception is f(0) = 0, which means length 0.
                          // But length must be >= 1. So, if s[i] == '0', it cannot be the start of a good substring.
                          // Wait, f(000) = 0. If length is 3, value is 0. 3 != 0.
                          // So, a good substring must have value >= 1.
                          // This implies it must contain at least one '1'.
                          // If it starts with '0', say s_l...s_r, then f(s_l...s_r) is the value of the suffix starting with the first '1'.
                          // Example: f(00101) = 5.
                          // If s[i] == '0', then s[i...r] will have value f(s[i...r]) which is the same as f(s[k...r]) where k is the first index >= i with s[k] == '1'.
                          // The length is r-i+1.
                          // If s[i] == '0', then f(s[i...r]) will be smaller than if s[i] == '1' (for the same suffix).
                          // The condition is length = value.
                          // If s[i] == '0', then the value of s[i...r] is at most (r-i) bits.
                          // The maximum value for a substring of length L is 2^L - 1.
                          // The minimum value for a substring of length L is 0.
                          // If s[i] == '0', then the value of s[i...r] is at most 2^(r-i) - 1.
                          // We need r-i+1 = value.
                          // If s[i] == '0', then value <= 2^(r-i) - 1.
                          // So r-i+1 <= 2^(r-i) - 1.
                          // Let L = r-i+1. Then L <= 2^(L-1) - 1.
                          // This inequality holds for L >= 4.
                          // L=1: 1 <= 2^0 - 1 = 0 (false)
                          // L=2: 2 <= 2^1 - 1 = 1 (false)
                          // L=3: 3 <= 2^2 - 1 = 3 (true, only if value is 3, i.e., 011)
                          // So, if s[i] == '0', we only need to check for small lengths.
                          // Specifically, if s[i] == '0', and it's a good substring, its value must be 3, and its length must be 3.
                          // This means s[i...i+2] must be "011".
                          // Let's re-evaluate.
                          // If s[i] == '0', then the actual binary value is determined by the first '1' after s[i].
                          // Let k be the first index >= i such that s[k] == '1'. If no such k exists, the value is 0.
                          // If value is 0, then length must be 0, which is impossible.
                          // So there must be a '1'.
                          // The value of s[i...r] is f(s[k...r]).
                          // The length is r-i+1.
                          // The value f(s[k...r]) is at most 2^(r-k+1) - 1.
                          // So we need r-i+1 = f(s[k...r]) <= 2^(r-k+1) - 1.
                          // Let L = r-i+1. Let L' = r-k+1.
                          // Then L = f(s[k...r]) <= 2^(L') - 1.
                          // Since k >= i, L' <= L.
                          // If L' < L, then L <= 2^(L') - 1 < 2^L - 1.
                          // The maximum possible value for L' is around 20 (since 2^20 is approx 10^6, and max length is 2*10^5).
                          // So L' can be at most around 18-19 for L to be around 2*10^5.
                          // If s[i] == '0', then k > i. So L' < L.
                          // The maximum value of L' is about 18-19.
                          // So we only need to check substrings starting with '0' if their length L is small enough,
                          // such that L <= 2^(L-1) - 1.
                          // This is true for L >= 3.
                          // For L=3, s[i...i+2] = "011", value is 3, length is 3. This is a good substring.
                          // For L=4, s[i...i+3] = "0xxx", value is at most 2^3-1 = 7. Length is 4.
                          // If value is 4, then s[k...i+3] must be "100".
                          // If s[i] == '0', we can iterate up to a certain maximum length for the substring.
                          // The maximum length of a substring is N = 2*10^5.
                          // The maximum value of a binary string of length L is 2^L - 1.
                          // If length = value, then L = value.
                          // If s[i] == '0', then the actual value is determined by s[k...r] where k is the first '1'.
                          // The length of s[k...r] is r-k+1.
                          // The value is at most 2^(r-k+1) - 1.
                          // We need r-i+1 = value.
                          // So r-i+1 <= 2^(r-k+1) - 1.
                          // Let L = r-i+1. Let num_leading_zeros = k-i.
                          // Then L <= 2^(L - num_leading_zeros) - 1.
                          // Since num_leading_zeros >= 1, L <= 2^(L-1) - 1.
                          // This inequality holds for L >= 3.
                          // So for s[i] == '0', we only need to check substrings of length up to about 20 (since 2^20 is large).
                          // For L=3, s[i...i+2] = "011" is good.
                          // For L=4, s[i...i+3] = "0100" is good (value 4, length 4).
                          // For L=5, s[i...i+4] = "00101" is good (value 5, length 5).
                          // For L=6, s[i...i+5] = "000110" is good (value 6, length 6).
                          // The maximum value of L for which L <= 2^(L-1)-1 is relevant is when L-1 is small.
                          // If L-1 = 18, L=19. 19 <= 2^18 - 1. This is true.
                          // So we can iterate for j from i up to min(n-1, i + MAX_LEN_TO_CHECK - 1).
                          // MAX_LEN_TO_CHECK can be around 20.
                          // This means for each '0', we check about 20 substrings. Total N * 20.
                          // This is efficient enough.

                // Case 1: Substrings starting with '0'
                // Iterate for small lengths, up to about 20.
                // The maximum value of L for which L <= 2^(L-1)-1 is relevant is when L-1 is small.
                // For L=1, 1 <= 0 (false)
                // For L=2, 2 <= 1 (false)
                // For L=3, 3 <= 3 (true, 011)
                // For L=4, 4 <= 7 (true, 0100)
                // For L=5, 5 <= 15 (true, 00101)
                // For L=19, 19 <= 2^18-1 (true)
                // For L=20, 20 <= 2^19-1 (true)
                // For L=21, 21 <= 2^20-1 (true)
                // The maximum length of a substring is N = 2*10^5.
                // If L = 2*10^5, then L-1 is also large.
                // L <= 2^(L-num_leading_zeros) - 1.
                // If num_leading_zeros is large, say L/2, then L <= 2^(L/2) - 1.
                // This is true for L >= 1.
                // The constraint is that the value must be equal to the length.
                // The value of a binary string of length L' is at most 2^L' - 1.
                // If s[i] == '0', let k be the first index >= i with s[k] == '1'.
                // The value of s[i...r] is f(s[k...r]).
                // The length is r-i+1.
                // We need r-i+1 = f(s[k...r]).
                // The length of s[k...r] is r-k+1.
                // So r-i+1 = f(s[k...r]) <= 2^(r-k+1) - 1.
                // Let L = r-i+1. Let L_prime = r-k+1.
                // L <= 2^(L_prime) - 1.
                // Since k > i, L_prime < L.
                // The maximum L_prime we need to consider is about 19-20, because 2^20 is about 10^6, which is larger than N.
                // If L_prime >= 20, then 2^(L_prime) - 1 is much larger than N.
                // So L must be at most N.
                // If L_prime is small, say L_prime = 1, then L <= 2^1 - 1 = 1.
                // But L_prime = r-k+1. If L_prime = 1, then r=k.
                // So L = k-i+1. We need k-i+1 = f(s[k]) = 1.
                // This means k-i+1 = 1, so k=i. But we are in the s[i]=='0' case, so k must be > i.
                // So L_prime cannot be 1.
                // If L_prime = 2, then L <= 2^2 - 1 = 3.
                // If L_prime = 2, then s[k...r] is "10" or "11".
                // If s[k...r] = "10", value is 2. Then L = 2. So k-i+1 = 2. k-i=1. So s[i...i+1] = "010" (length 3, value 2, not good).
                // If s[k...r] = "11", value is 3. Then L = 3. So k-i+1 = 3. k-i=2. So s[i...i+2] = "0011" (length 4, value 3, not good).
                // This logic is getting complicated. Let's simplify.
                // For each i, iterate j from i up to min(n-1, i + 20).
                // Calculate value of s[i...j]. If value == j-i+1, increment count.
                // This covers all cases where the length of the substring is small (up to 21).
                // The maximum length of a substring is N = 2*10^5.
                // If a substring s[i...j] has length L = j-i+1, and its value is V.
                // If V = L, then L must be at most N.
                // If L is large, say L > 20, then V must also be large.
                // If s[i] == '0', then the actual value is f(s[k...j]) where k is the first '1'.
                // The length of s[k...j] is L' = j-k+1.
                // The value V is at most 2^L' - 1.
                // We need L = V. So L <= 2^L' - 1.
                // Since k > i, L' < L.
                // If L' is small, say L' <= 20, then V <= 2^20 - 1.
                // So L <= 2^20 - 1.
                // This means if L > 2^20 - 1 (which is approx 10^6), then it cannot be a good substring.
                // But N is 2*10^5. So L can be up to 2*10^5.
                // If L > 20, then L' must be large enough such that 2^L' - 1 >= L.
                // For example, if L = 2*10^5, then L' must be at least 18 (since 2^17 < 2*10^5 < 2^18).
                // So L' can be L-1, L-2, ..., L-18.
                // This means num_leading_zeros = L-L' can be 1, 2, ..., 18.
                // So for s[i] == '0', we need to check substrings s[i...j] where j-i+1 = L, and the number of leading zeros is small (up to 18).
                // This means k-i is small.
                // So for each i, we find the first '1' at index k.
                // Then we iterate j from k up to min(n-1, k + 19).
                // For each such j, calculate value of s[k...j]. Let it be V.
                // Then check if V = (j-i+1).
                // This is the correct approach for s[i] == '0'.

                int first_one_idx = -1;
                for (int k = i; k < n; ++k) {
                    if (s[k] == '1') {
                        first_one_idx = k;
                        break;
                    }
                }
                if (first_one_idx == -1) { // All zeros from i to n-1
                    // f(00...0) = 0. Length is at least 1. So no good substrings.
                    continue;
                }

                long long current_val = 0;
                // Iterate j from first_one_idx up to min(n-1, first_one_idx + 19)
                // The maximum length of the binary number part (s[first_one_idx...j]) is about 20.
                // This means current_val will be at most 2^20 - 1.
                // The total length of the substring s[i...j] is j-i+1.
                // We need j-i+1 = current_val.
                // Since current_val <= 2^20 - 1, j-i+1 must also be <= 2^20 - 1.
                // This means j-i+1 can be up to 2*10^5.
                // The number of leading zeros is first_one_idx - i.
