                // L_prime = 2: 2+1 <= 2^2-1 = 3 (true, 011)
                // L_prime = 3: 3+1 <= 2^3-1 = 7 (true, 0100)
                // The maximum L_prime we need to check is when 2^L_prime - 1 is roughly N.
                // 2^17 approx 1.3*10^5, 2^18 approx 2.6*10^5.
                // So L_prime can be up to about 18.
                // So we iterate j from first_one_idx up to min(n-1, first_one_idx + 18).
                // This means the length of the binary part (s[first_one_idx...j]) is at most 19.
                // This is a small constant number of iterations for each i.
                // Total complexity N * 19. This is efficient.

                for (int j = first_one_idx; j < n; ++j) {
                    int len_binary_part = j - first_one_idx + 1;
                    if (len_binary_part > 19) { // Max value 2^19-1 is approx 5*10^5.
