                // }
                // Let's re-evaluate the maximum length for s[i] == '1'.
                // We need L = V. Since s[i] == '1', V >= 2^(L-1).
                // So L >= 2^(L-1).
                // This is true for L=1 (1 >= 1) and L=2 (2 >= 2).
                // For L=3, 3 < 4. For L >= 3, L < 2^(L-1).
                // So, if s[i] == '1', good substrings can only have length 1 or 2.
                // Length 1: s[i] = '1'. Value 1, length 1. Good.
                // Length 2: s[i...i+1].
                // If s[i...i+1] = "10", value 2, length 2. Good.
                // If s[i...i+1] = "11", value 3, length 2. Not good.
                // So, for s[i] == '1', we only need to check s[i] and s[i...i+1].
                // The loop `for (int j = i; j < n; ++j)` with `if (len > 19) break;` covers this.
                // It will check len=1 and len=2.
                // So the logic for s[i] == '1' is correct and sufficient.
            }
        }
        std::cout << count << "\n";
    }
    return 0;
