struct Child {
    long long v, d, p;
    int original_idx;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_in_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_in_line.push_back({v_val, d_val, p_val, i + 1});
    }

    std::vector<int> cured_children_indices;

    while (!children_in_line.empty()) {
        Child current_child = children_in_line.front();
        children_in_line.pop_front();
        cured_children_indices.push_back(current_child.original_idx);

        long long office_cry_effect = current_child.v;
        long long hall_cry_total_effect = 0;

        auto it = children_in_line.begin();
        while (it != children_in_line.end()) {
            // Apply hall cry effect from previous children
            if (hall_cry_total_effect > 0) {
                it->p -= hall_cry_total_effect;
            }

            // Apply office cry effect from current_child
            if (office_cry_effect > 0) {
                it->p -= office_cry_effect;
                office_cry_effect--;
            }

            if (it->p < 0) {
                hall_cry_total_effect += it->d;
                it = children_in_line.erase(it);
            } else {
                ++it;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

