#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // delta_sum[i] stores the sum of d values applied to index i by all type 1 operations.
    // This is used to calculate the final value of a[i] if initial a_0[i] was 0.
    std::vector<long long> delta_sum(n, 0);

    // initial_a[i] stores the value of a_0[i] that we are trying to find.
    // Initialize with a very small value to ensure max constraints are met.
    // The problem states |a_i| <= 10^9, so -10^9 is a valid initial value.
    std::vector<long long> initial_a(n, -1000000000LL); 

    // Process operations in reverse to determine initial_a values.
    // For type 2 operations (max constraint), we need to ensure that
    // initial_a[j] + delta_sum[j] <= m_i for all j in [l_i, r_i].
    // This means initial_a[j] <= m_i - delta_sum[j].
    // We take the minimum of these upper bounds for each initial_a[j].
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (add d), it means this d was applied
            // to elements in [l, r] *before* this point in time.
            // So, for future calculations (which are effectively earlier in time),
            // this d should be subtracted from the running delta_sum.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                delta_sum[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a type 2 operation (max query), it means max(a[j]) = m_i
            // for j in [l, r] at this point in time.
            // The current value of a[j] is initial_a[j] + delta_sum[j].
            // So, initial_a[j] + delta_sum[j] <= ops[i].val (m_i) for all j in [l, r].
            // This implies initial_a[j] <= ops[i].val - delta_sum[j].
            // We update initial_a[j] with the minimum of its current value and this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - delta_sum[j]);
            }
        }
    }

    // Check if the found initial_a satisfies all constraints by simulating operations.
    // current_a will store the array values as operations are applied.
    std::vector<long long> current_a = initial_a;

    // current_delta_prefix_sum[i] stores the sum of d values applied to index i
    // by type 1 operations up to the current point in the forward simulation.
    // This is used to efficiently calculate current_a[j] for type 2 checks.
    std::vector<long long> current_delta_prefix_sum(n + 1, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Apply the range add operation to the prefix sum array.
            current_delta_prefix_sum[ops[i].l] += ops[i].val;
            if (ops[i].r + 1 < n) {
                current_delta_prefix_sum[ops[i].r + 1] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_val = LLONG_MIN;
            long long current_delta_val = 0; // Actual delta for current index
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_val += current_delta_prefix_sum[j];
                max_val = std::max(max_val, initial_a[j] + current_delta_val);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array.
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

