    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Use 5s
        presses += diff / 5;
        diff %= 5;

        // Remaining diff can be 0, 1, 2, 3, 4
        if (diff == 0) {
            // No more presses needed
        } else if (diff == 1 || diff == 2) {
            // 1 needs one +1 or -1
            // 2 needs one +2 or -2
            presses += 1;
        } else if (diff == 3 || diff == 4) {
            // 3 can be 5-2 (2 presses) or 1+1+1 (3 presses)
            // 4 can be 5-1 (2 presses) or 2+2 (2 presses) or 1+1+1+1 (4 presses)
            // In both cases, 2 presses are optimal (e.g., 5-2 for 3, 5-1 for 4)
            presses += 2;
        }

        std::cout << presses << "\n";
    }
    return 0;
}

