void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, which is not allowed, or p is a palindrome, which is rare)
    // and always results in the same set of adjacent sums.
    // The sums for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The sums for p_reversed are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These two sets of sums are identical, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // Since n >= 2, p_reversed is always different from p unless p is a palindrome.
    // However, the problem guarantees a solution exists, and reversing is the simplest.
    // If p is a palindrome, e.g., [1,2,1] (not a permutation), or [1,2,3,2,1] (not a permutation),
    // then p_reversed would be identical to p.
    // But for permutations, palindromes are rare. For example, for n=3, [1,2,3] reversed is [3,2,1].
    // For n=4, [1,2,3,4] reversed is [4,3,2,1].
    // The only way p_reversed could be equal to p is if p_i = p_{n-1-i} for all i.
    // For example, if n=2, p=[1,2], p_reversed=[2,1]. They are different.
    // The problem guarantees a solution exists, and reversing is a valid strategy.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

