    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of a_i * (i-1) can exceed int
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 is i days
            long long cost_per_haybale = i; 

            if (d >= cost_per_haybale) {
                // Calculate how many haybales can be moved from pile i
                // We have 'a[i]' haybales in this pile.
                // We have 'd' days remaining.
                // Each haybale costs 'cost_per_haybale' days.
                long long max_haybales_from_this_pile = a[i];
                long long haybales_movable_by_days = d / cost_per_haybale;

                long long haybales_to_move = std::min(max_haybales_from_this_pile, haybales_movable_by_days);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile
                // or any further piles, so we can stop.
                break;
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric> // For std::iota in C++23, though not strictly needed here
#include <set>

void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // If s and t are already equal, it's possible.
    if (s == t) {
        std::cout << "YES\n";
        return;
    }

    // The operation allows any character present in a string to propagate
    // to any other position in that string.
    // For example, if 'a' is in s, we can make s entirely 'a's.
    // If 'b' is in t, we can make t entirely 'b's.
    //
    // To make s equal to t, they must eventually become some common string X.
    // If s can become X, it means all characters in X must be present in s.
    // If t can become X, it means all characters in X must be present in t.
    //
    // The simplest common string X they can both become is a string of a single character.
    // For example, if s contains 'a' and t contains 'a',
    // s can be transformed to "aaa...a" and t can be transformed to "aaa...a".
    // Thus, they can be made equal.
    //
    // Therefore, the problem reduces to checking if there is at least one common character
    // between string s and string t.

    std::set<char> s_chars;
    for (char c : s) {
        s_chars.insert(c);
    }

    for (char c : t) {
        if (s_chars.count(c)) {
            // Found a common character
            std::cout << "YES\n";
            return;
        }
    }

    // No common characters found
    std::cout << "NO\n";
}

