    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        std::map<int, int> counts;
        for (int i = 0; i < n; ++i) {
            int s_val;
            std::cin >> s_val;
            if (s_val <= 2048) {
                counts[s_val]++;
            }
        }

        int current_sum = 0;
        for (auto const& [val, count] : counts) {
            // Add the contribution of 'val' to the current_sum.
            // Each 'val' contributes 'val * count' to the total sum
            // that can be potentially merged into larger powers of two.
            // However, we only care about the sum up to 2048.
            // If current_sum + val * count exceeds 2048, we cap it at 2048.
            // This is because any excess beyond 2048 cannot be used to form 2048.
            // For example, if we have 1024 and 1024, current_sum becomes 2048.
            // If we then have another 1024, it doesn't help us get *another* 2048,
            // nor does it help us get *the* 2048 if we already have it.
            // The problem asks if 2048 *belongs* to the multiset.
            // So we just need to accumulate the sum of numbers less than or equal to 2048.
            // If this sum is >= 2048, we can form 2048.
            // This is because any power of two can be combined with an equal power of two
            // to form the next higher power of two.
            // This process can be thought of as summing up all values.
            // If the total sum of numbers <= 2048 is >= 2048, then we can always
            // combine them to form 2048.
            // Example: {1, 1, 1, 1, ..., 1} (2048 times) -> 2048
            // Example: {1024, 512, 512} -> {1024, 1024} -> {2048}
            // The total sum is 1024 + 512 + 512 = 2048.
            // The logic is that if we have enough "value" (sum of powers of two),
            // we can always combine them to reach 2048, as long as we don't
            // exceed 2048 with any single number.
            // Numbers greater than 2048 are ignored.
            current_sum += val * count;
            if (current_sum >= 2048) {
                break; // No need to process further if we already have enough sum
            }
        }

        if (current_sum >= 2048) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }
    return 0;
}

