    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and all other elements are less than n-1.
    // If so, it means the actual value for that p[i] should be n.
    // This happens if p[i] was originally n, and all other p[j] < n.
    // In that case, min(p[i], p[j]) = p[j], and max_val_in_row would be n-1.
    // If there are multiple such elements, it's an issue, but the problem guarantees a solution.
    // If there is exactly one element in p that is n-1, and all others are smaller,
    // then that element must be n.

    int count_n_minus_1 = 0;
    for (int val : p) {
        if (val == n - 1) {
            count_n_minus_1++;
        }
    }

    if (count_n_minus_1 == 1) {
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
