#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int current_dist = 0;

        // The frog starts at cell 0.
        // The first 'R' character is at index 0 (cell 1).
        // The distance from 0 to the first 'R' is 1.
        // If s[0] is 'L', the frog must jump over it.
        // The effective "gap" starts from cell 0.

        // We can think of this as finding the maximum distance between consecutive 'R's,
        // including the distance from cell 0 to the first 'R', and from the last 'R' to cell n+1.

        // Let's use 'last_r_pos' to track the position of the last 'R' encountered.
        // Initialize it to -1, representing cell 0 (the starting point before any string character).
        int last_r_pos = -1; 

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we find an 'R' at index i (which corresponds to cell i+1),
                // the distance from the last 'R' (or cell 0) to this 'R' is (i+1) - (last_r_pos + 1) + 1
                // which simplifies to (i+1) - last_r_pos.
                // Example: last_r_pos = -1 (cell 0), current 'R' at i=0 (cell 1). Distance = (0+1) - (-1) = 2.
                // Example: last_r_pos = 2 (cell 3), current 'R' at i=4 (cell 5). Distance = (4+1) - 2 = 3.
                max_dist = std::max(max_dist, (i + 1) - (last_r_pos + 1) + 1); // Distance between cells
                last_r_pos = i; // Update last_r_pos to current 'R's index
            }
        }

        // After iterating through the string, we need to consider the distance from the last 'R'
        // to the target cell n+1.
        // The last 'R' was at index 'last_r_pos' (cell 'last_r_pos + 1').
        // The target is cell n+1.
        // Distance = (n+1) - (last_r_pos + 1) + 1.
        // Example: last_r_pos = -1 (cell 0), n=6. Distance = (6+1) - (-1+1) + 1 = 7 - 0 + 1 = 8.
        // Example: last_r_pos = 4 (cell 5), n=6. Distance = (6+1) - (4+1) + 1 = 7 - 5 + 1 = 3.
        max_dist = std::max(max_dist, (n + 1) - (last_r_pos + 1) + 1);

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
