#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices for each day
        }

        if (n <= 1) {
            std::cout << 0 << "\n"; // If n is 0 or 1, no price can be bad
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price, as it's the minimum for the last element
        int min_suffix = a[n - 1]; 

        // Iterate from the second to last element backwards
        // For a price a[i] to be bad, it must be greater than some price a[j] where j > i.
        // This is equivalent to a[i] being greater than the minimum price encountered so far
        // when scanning from right to left (i.e., min_suffix).
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                bad_prices_count++; // Current price a[i] is bad
            } else {
                // If a[i] is not greater than min_suffix, it means a[i] is
                // either equal to or less than min_suffix.
                // In this case, a[i] becomes the new minimum for elements
                // from i onwards.
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0;
}

#include <iostream>
