int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' must satisfy:
        // 1. k <= c (at least k coders needed)
        // 2. k <= m (at least k mathematicians needed)
        // 3. 3k <= c + m + x (total students needed)
        // Combining 1 and 2: k <= min(c, m)
        // Combining all: k <= min(c, m, (c + m + x) / 3)
        // The maximum possible value for k is min(c, m, (c + m + x) / 3).
        // This is because if we form k teams, we need at least k coders and k mathematicians.
        // The remaining (c - k) coders, (m - k) mathematicians, and x unspecalized students
        // can be used to fill the remaining 3k - k - k = k slots in the teams.
        // The total number of students available for these k remaining slots is (c - k) + (m - k) + x.
        // We need to ensure that (c - k) + (m - k) + x >= k.
        // This simplifies to c + m + x >= 3k.
        // So, the number of teams k is limited by the minimum of the available coders,
        // available mathematicians, and the total number of students divided by 3.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for n=1 staircase
        long long sum_of_costs = 0;

        while (true) {
            if (sum_of_costs + current_cost <= x) {
                sum_of_costs += current_cost;
                count++;
                // Calculate the cost for the next staircase.
                // If current_cost is for n, next_cost is for 2n+1.
                // Cost for n is (2^k - 1) * (2^k) / 2.
                // Cost for 2n+1 is (2^(k+1) - 1) * (2^(k+1)) / 2.
                // This is equivalent to current_cost * 2 + (2^k)^2.
                // The (2^k)^2 part is (2*current_n + 1) * (2*current_n + 2) / 2 - current_n * (current_n + 1) / 2
                // No, it's simpler: the next staircase has 2*n_prev + 1 stairs.
                // The cost for n stairs is n*(n+1)/2.
                // The cost for 2n+1 stairs is (2n+1)*(2n+2)/2 = (2n+1)*(n+1).
                // The cost for n=1 is 1.
                // The cost for n=3 is 6.
                // The cost for n=7 is 28.
                // The cost for n=15 is 120.
                // The pattern is: cost_k = cost_{k-1} * 4 + 2.
                // Or, cost_k = (2^(k+1)-1) * (2^(k+1))/2.
                // Let's use the derived recurrence: next_cost = current_cost * 2 + (2^k)^2.
                // Where current_cost is for n = 2^k - 1.
                // So (2^k)^2 = (n+1)^2.
                // next_cost = current_cost * 2 + (n+1)^2.
                // This is equivalent to current_cost * 2 + (2 * (n_prev_stairs + 1) / 2 + 1)^2
                // No, the recurrence is `cost(2n+1) = 2 * cost(n) + (n+1)^2`.
                // Let `n_stairs` be the number of stairs for `current_cost`.
                // `n_stairs` starts at 1.
                // `next_n_stairs = 2 * n_stairs + 1`.
                // `next_cost = (next_n_stairs * (next_n_stairs + 1)) / 2`.
                // This is `(2*n_stairs + 1) * (2*n_stairs + 2) / 2 = (2*n_stairs + 1) * (n_stairs + 1)`.
                // This is `2 * n_stairs * (n_stairs + 1) + (n_stairs + 1)`.
                // `current_cost = n_stairs * (n_stairs + 1) / 2`.
                // So `n_stairs * (n_stairs + 1) = 2 * current_cost`.
                // `next_cost = 2 * current_cost + (n_stairs + 1)`. This is wrong.
                // `next_cost = (2*n_stairs + 1) * (n_stairs + 1)`.
                // `next_cost = 2 * n_stairs * (n_stairs + 1) + (n_stairs + 1)`.
                // `next_cost = 4 * current_cost + (n_stairs + 1)`.
                // `n_stairs` is not directly available.
                // Let's use the powers of 2.
                // The number of stairs are 1, 3, 7, 15, ... which are 2^k - 1.
                // For k=1, n=1, cost=1.
                // For k=2, n=3, cost=6.
                // For k=3, n=7, cost=28.
                // For k=4, n=15, cost=120.
                // The cost for n = 2^k - 1 is (2^k - 1) * 2^k / 2.
                // Let `p = 2^k`.
                // `current_cost = (p - 1) * p / 2`.
                // `next_p = 2 * p`.
                // `next_cost = (next_p - 1) * next_p / 2`.
                // `next_cost = (2p - 1) * 2p / 2 = (2p - 1) * p`.
                // `next_cost = 2p^2 - p`.
                // `current_cost = p^2/2 - p/2`.
                // `p^2 = 2 * current_cost + p`.
                // `next_cost = 2 * (2 * current_cost + p) - p = 4 * current_cost + 2p - p = 4 * current_cost + p`.
                // So, `p` is the `2^k` value.
                // `p` starts at 2 (for n=1, which is 2^1-1).
                long long p = 2; // p = 2^k, starts with k=1 for n=1
                long long temp_cost = 1; // cost for n=1
                while (temp_cost < current_cost) { // Find p for current_cost
                    p *= 2;
                    temp_cost = (p - 1) * p / 2;
                }
                // Now p is 2^k for current_cost.
                current_cost = 4 * current_cost + p;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

