#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a non-increasing suffix
    // This is the first element from the right that breaks the non-increasing order
    // i.e., a[i] > a[i+1]
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-increasing.
    // If i=0, the whole array is non-increasing.

    // Find the rightmost peak of a non-decreasing suffix
    // This is the first element from the right that breaks the non-decreasing order
    // i.e., a[j] < a[j+1]
    int j = i; // Start search from i, as elements to the right of i are already non-increasing
               // and thus potentially part of a non-decreasing sequence if we pick from left.
               // More precisely, we need to find the first element from the right that breaks
               // the non-decreasing order of the suffix a[0...j].
               // The elements a[j...n-1] must be non-decreasing.
               // So we look for the first element a[k] such that a[k] < a[k+1]
               // starting from k=i-1 and going left.
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...n-1] is non-decreasing.
    // If j=0, the whole array is non-decreasing.

    std::cout << j << std::endl;
}

