#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subsegment [1] is always a permutation of {1}.
    // It's at p[pos[1]]. So l=r=pos[1].
    result[0] = '1';

    int min_idx = pos[1];
    int max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update min_idx and max_idx to include the position of 'm'
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // For the subsegment p[min_idx ... max_idx] to be a permutation of {1, ..., m},
        // it must contain all numbers from 1 to m, and its length must be m.
        // Since we are expanding min_idx and max_idx to always include 1, ..., m,
        // the subsegment p[min_idx ... max_idx] contains all numbers 1, ..., m.
        // It also contains no numbers greater than m (because we only consider up to m).
        // The only condition left is that its length must be exactly m.
        // Length of subsegment is (max_idx - min_idx + 1).
        if (max_idx - min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << "\n";
}

