int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;

    // Precompute sums of last digits for 10 cycles for each possible last digit of m
    // sums_of_last_digits[m_last_digit][k] stores (k*m)%10 for m_last_digit = m%10
    // This is not needed, as the pattern is always the same for any m_last_digit.
    // The pattern is (1*m)%10, (2*m)%10, ..., (10*m)%10.
    // The sum of these 10 digits is what we need.

    // Let's precompute the sum of last digits for one full cycle (10 terms)
    // for each possible last digit of m (0-9).
    // cycle_sums[i] will store the sum of (k*X)%10 for k=1 to 10, where X%10 = i.
    // Example: if m%10 = 3, the sequence is 3, 6, 9, 2, 5, 8, 1, 4, 7, 0. Sum = 45.
    // This is always 45 for any non-zero m%10.
    // If m%10 = 0, the sequence is 0, 0, ..., 0. Sum = 0.

    std::vector<long long> cycle_sums(10);
    for (int m_last_digit = 0; m_last_digit < 10; ++m_last_digit) {
        long long current_sum = 0;
        for (int k = 1; k <= 10; ++k) {
            current_sum += (static_cast<long long>(k) * m_last_digit) % 10;
        }
        cycle_sums[m_last_digit] = current_sum;
    }

    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) { // Should not happen based on constraints 1 <= m
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m; // Number of pages divisible by m

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        int m_last_digit = m % 10;

        long long full_cycles = count / 10;
        long long remaining_terms = count % 10;

        long long total_sum = full_cycles * cycle_sums[m_last_digit];

        // Add sum for remaining terms
        for (long long k = 1; k <= remaining_terms; ++k) {
            total_sum += (k * m_last_digit) % 10;
        }

        std::cout << total_sum << "\n";
    }

    return 0;
}

