#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops
    // prefix_min_ops[i] stores the minimum value a[i] must have
    // to satisfy a[0] < a[1] < ... < a[i]
    // If a[i] < i, it's impossible to satisfy a[0] < ... < a[i]
    // because a[0] must be at least 0, a[1] at least 1, ..., a[i] at least i.
    std::vector<long long> prefix_min_val(n);
    prefix_min_val[0] = 0; // a[0] must be at least 0
    for (int i = 1; i < n; ++i) {
        prefix_min_val[i] = prefix_min_val[i-1] + 1;
    }

    // Check if it's possible to satisfy a[0] < ... < a[i] for each i
    // by decreasing elements.
    // This means original a[i] must be >= prefix_min_val[i]
    for (int i = 0; i < n; ++i) {
        if (a[i] < prefix_min_val[i]) {
            std::cout << "No\n";
            return;
        }
    }

    // Calculate suffix_min_ops
    // suffix_min_ops[i] stores the minimum value a[i] must have
    // to satisfy a[i] > a[i+1] > ... > a[n-1]
    // If a[i] < (n-1-i), it's impossible to satisfy a[i] > ... > a[n-1]
    // because a[n-1] must be at least 0, a[n-2] at least 1, ..., a[i] at least (n-1-i).
    std::vector<long long> suffix_min_val(n);
    suffix_min_val[n-1] = 0; // a[n-1] must be at least 0
    for (int i = n - 2; i >= 0; --i) {
        suffix_min_val[i] = suffix_min_val[i+1] + 1;
    }

    // Now, for each possible peak k (0-indexed), we need to check if it's possible.
    // For a peak at index k, we need:
    // 1. a[0] < ... < a[k] (left side strictly increasing)
    // 2. a[k] > a[k+1] > ... > a[n-1] (right side strictly decreasing)
    //
    // To satisfy condition 1, a[k] must be at least prefix_min_val[k].
    // To satisfy condition 2, a[k] must be at least suffix_min_val[k].
    // So, a[k] must be at least max(prefix_min_val[k], suffix_min_val[k]).
    // If the original a[k] is less than this required minimum, then k cannot be the peak.
    // If there is any k for which original a[k] >= max(prefix_min_val[k], suffix_min_val[k]),
    // then it's possible.

    for (int k = 0; k < n; ++k) {
        long long required_val_at_k = std::max(prefix_min_val[k], suffix_min_val[k]);
        if (a[k] >= required_val_at_k) {
            std::cout << "Yes\n";
            return;
        }
    }

    std::cout << "No\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (the 'b' array elements)
    // We iterate through the sorted 'a' array using 'i' as the pointer for the original positions.
    // For each a[i], we try to find the smallest a[j] such that a[j] > a[i].
    // If we find such an a[j], we increment count and move to the next a[j].
    // If a[j] is not greater than a[i], we need a larger element for a[i], so we advance j.
    for (int i = 0; i < n; ++i) {
        // If j has gone past the end of the array, we can't find any more elements.
        // Or if i catches up to j, it means we've used all elements up to j-1,
        // and a[j] is the next candidate.
        // We must ensure j is always ahead of or equal to i.
        // If j is less than or equal to i, we advance j to i+1 to ensure we are looking for a distinct element.
        // However, the logic below naturally handles this: if a[j] <= a[i], j increments.
        // The key is that we are trying to match a[i] with a[j] where j >= i.
        // If a[j] > a[i], we found a match. We increment count and advance j to look for the next match.
        // If a[j] <= a[i], then a[j] cannot be placed at position i. We need a larger element for position i,
        // so we advance j to consider the next available element.
        // The elements a[0...i-1] have already been matched or skipped.
        // The elements a[j...n-1] are available to be placed.
        // We are trying to place an element from a[j...n-1] at position i (which corresponds to a[i]).
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in 'b' array for the next potential match
        } else {
            // If j reaches n, it means no more elements are available that are greater than a[i]
            // or any subsequent a[k] (since a is sorted). So we can break.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

