int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
        b_indexed[i] = {b[i], i};
    }

    // Sort A in ascending order
    std::sort(a.begin(), a.end());

    // Sort B in ascending order, keeping original indices
    std::sort(b_indexed.begin(), b_indexed.end());

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Fill A' by pairing largest A with largest B, second largest A with second largest B, etc.
    // This is equivalent to pairing a[i] with b_indexed[i].first
    // The original index of b_indexed[i].first is b_indexed[i].second
    for (int i = 0; i < m; ++i) {
        a_prime[b_indexed[i].second] = a[i];
    }

    // Output the rearranged array A'
    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

