#include <set>

bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
    if (len > arr.size()) return false; // Not enough elements

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] < 1 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix max and suffix max
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i+1], a[i]);
    }

    // Check for each possible split point l1
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Optimization: Check if max element in p1 is l1 and max element in p2 is l2
        // If not, it cannot be a permutation.
        if (prefix_max[l1-1] != l1 || suffix_max[l1] != l2) {
            continue;
        }

        // Check if p1 is a permutation of length l1
        std::vector<bool> seen1(l1 + 1, false);
        bool p1_is_perm = true;
        for (int i = 0; i < l1; ++i) {
            if (a[i] < 1 || a[i] > l1 || seen1[a[i]]) {
                p1_is_perm = false;
                break;
            }
            seen1[a[i]] = true;
        }
        if (!p1_is_perm) {
            continue;
        }

        // Check if p2 is a permutation of length l2
        std::vector<bool> seen2(l2 + 1, false);
        bool p2_is_perm = true;
        for (int i = l1; i < n; ++i) {
            if (a[i] < 1 || a[i] > l2 || seen2[a[i]]) {
                p2_is_perm = false;
                break;
            }
            seen2[a[i]] = true;
        }
        if (p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

