char beats(char opponent_move) {
    if (opponent_move == 'R') return 'P';
    if (opponent_move == 'S') return 'R';
    if (opponent_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char move : s) {
            counts[move]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though any tie-breaking is fine as per problem statement.
        // R, P, S is a common order.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        // If all counts are 0 (empty string, though n >= 1), or if there's a tie,
        // the choice of most_frequent_bot_move doesn't matter as long as it's one of R, P, S.
        // The problem guarantees n >= 1, so max_count will be at least 1.

        char my_optimal_move = beats(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << my_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 != 1) { // N/2 is odd and N/2 > 1
                    // Taking N/2 leaves an odd number for opponent, which is good for opponent.
                    // Taking 1 leaves an even number for opponent.
                    // If N/2 is odd and N/2 > 1, opponent will take 1, leaving N/2-1 (even) for Chanek.
                    // If Chanek takes 1, opponent gets N-1 (odd). Opponent takes 1, leaving N-2 (even) for Chanek.
                    // This logic is tricky. Let's re-evaluate.
                    // If N is even:
                    // Option 1: Take 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
                    // Option 2: Take N/2. Remaining N/2 (even or odd).
                    //
                    // If N/2 is odd (and N > 2):
                    //   Option 1: Take 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
                    //   Option 2: Take N/2. Remaining N/2 (odd). Opponent takes 1. Remaining N/2-1 (even).
                    //   In this case, taking 1 is better for Chanek.
                    //   Example: N=6. N/2=3 (odd).
                    //     Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    //     Chanek: 1+2+1=4. Opponent: 1+1=2.
                    //     Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    //     Chanek: 3+1=4. Opponent: 1+1=2.
                    //   It seems taking N/2 is also good.
                    //   The key is that if N/2 is odd, the opponent will be left with an odd number (N/2) if Chanek takes N/2.
                    //   If Chanek takes 1, the opponent is left with N-1 (odd).
                    //   In both cases, the opponent is left with an odd number.
                    //   The opponent will take 1 coin.
                    //   So, if N/2 is odd, Chanek should take N/2 to get more coins.
                    //   Example N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    //   Chanek: 3+1=4. Opponent: 1+1=2.
                    //   This matches the example.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // If N/2 is even, taking N/2 leaves an even number for opponent.
                    // Opponent can then take (N/2)/2 = N/4.
                    // If Chanek takes 1, opponent is left with N-1 (odd). Opponent takes 1.
                    // This is the greedy choice: take N/2 if it's even.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 != 1) { // N/2 is odd and N/2 > 1
                    // Opponent wants to maximize their coins.
                    // If opponent takes N/2, they get N/2 coins. Chanek gets N/2-1 (if N/2 is odd, Chanek takes 1).
                    // If opponent takes 1, they get 1 coin. Chanek gets N-2.
                    // Opponent will take N/2.
                    n /= 2;
                } else { // N/2 is even
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum and X = current_xor_sum.
    // We want S' = 2X'.
    // The problem guarantees a solution exists with at most 3 elements.

    // Strategy: Append two elements.
    // Let the two elements be X and S.
    // New sum S' = S_old + X + S_old = 2 * S_old + X
    // New XOR sum X' = X_old ^ X ^ S_old
    // This doesn't seem to simplify nicely.

    // Let's try a different strategy for 2 elements.
    // We want to find b1, b2 such that (S + b1 + b2) = 2 * (X ^ b1 ^ b2).
    // A common trick for XOR problems is to make the XOR sum 0 or some specific value.
    // If we append X, the XOR sum becomes X ^ X = 0.
    // Let's try to append X and then some other value.
    // If we append X, the new XOR sum is X_old ^ X_old = 0.
    // Let's call this new XOR sum X_new = 0.
    // The new sum is S_new = S_old + X_old.
    // Now we need to append one more element, say b.
    // The total sum will be S_new + b.
    // The total XOR sum will be X_new ^ b = 0 ^ b = b.
    // We need S_new + b = 2 * b.
    // S_new = b.
    // So, b = S_old + X_old.
    // The two elements to append are X_old and (S_old + X_old).

    // Let's verify this strategy:
    // Initial sum: S_old
    // Initial XOR sum: X_old
    // Append b1 = X_old
    // Append b2 = S_old + X_old
    // New total sum S' = S_old + X_old + (S_old + X_old) = 2 * S_old + 2 * X_old
    // New total XOR sum X' = X_old ^ X_old ^ (S_old + X_old) = 0 ^ (S_old + X_old) = S_old + X_old
    // We need S' = 2 * X'.
    // Is (2 * S_old + 2 * X_old) = 2 * (S_old + X_old)?
    // Yes, it is.
    // So, we can always append two elements: X_old and (S_old + X_old).

    // The problem states "at most 3 elements".
    // If the array is already good, we can append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // Append two elements using the strategy derived above.
        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;
        std::cout << 2 << std::endl;
        std::cout << b1 << " " << b2 << std::endl;
    }
}

