int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> count_x;
    std::map<int, long long> count_y;
    std::map<std::pair<int, int>, long long> count_xy;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        count_x[x]++;
        count_y[y]++;
        count_xy[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : count_x) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : count_y) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., identical points)
    // These pairs were counted twice: once for same x, once for same y.
    // They should only be counted once.
    for (auto const& [point, count] : count_xy) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
