// Function to convert an integer to its parity pattern string
// For example, 241 -> "001" (2 is even, 4 is even, 1 is odd)
// The pattern is always 18 characters long, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding the number with '0's from the left
    // for comparison purposes.
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each 18-digit parity pattern string.
    // The key is the 18-digit pattern string, value is its count.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;

            // The query pattern 's' needs to be normalized to an 18-digit pattern.
            // The problem states: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we effectively compare 18-digit representations.
            // Our `get_parity_pattern` function generates a string where the rightmost char is the parity of the rightmost digit,
            // and it's padded with '0's to the right to make it 18 chars.
            // So, for a query pattern 's', we need to reverse it and then pad with '0's to the right.

            std::string query_pattern_normalized = "";
            // Reverse 's' to match the right-to-left digit processing
            std::reverse(s.begin(), s.end());
            query_pattern_normalized = s;

            // Pad with '0's to the right to make it 18 characters long
            while (query_pattern_normalized.length() < 18) {
                query_pattern_normalized += '0';
            }

            std::cout << pattern_counts[query_pattern_normalized] << "\n";
        }
    }

    return 0;
}

