int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n - i' items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;
        int items_left_taken = i;
        int items_right_taken = n - i;

        // Calculate energy for items taken from left
        current_energy += prefix_sum[items_left_taken] * l;

        // Calculate energy for items taken from right
        // The items taken from the right are w[n - items_right_taken] ... w[n-1]
        // Sum of these items is prefix_sum[n] - prefix_sum[n - items_right_taken]
        current_energy += (prefix_sum[n] - prefix_sum[n - items_right_taken]) * r;

        // Add penalty for imbalance
        if (items_left_taken > items_right_taken) {
            current_energy += (long long)(items_left_taken - items_right_taken - 1) * Ql;
        } else if (items_right_taken > items_left_taken) {
            current_energy += (long long)(items_right_taken - items_left_taken - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

