// Function to find prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means we need to remove some prime factors from p such that the resulting x is no longer divisible by q.
        // To maximize x, we should remove as few factors as possible, or rather, remove factors such that the resulting x is largest.
        // This implies we should divide p by the smallest possible power of a prime factor of q that makes x not divisible by q.

        std::vector<long long> prime_factors_q = get_prime_factors(q);
        long long max_x = 0;

        for (long long r : prime_factors_q) {
            long long current_p = p;
            // Divide current_p by r until it's no longer divisible by q
            // Or until current_p is no longer divisible by r
            while (current_p % q == 0) {
                current_p /= r;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

