#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::vector<int> colors(n);
        int last1 = -1; // Last digit colored 1
        int last2 = -1; // Last digit colored 2
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                // Must be color 1
                if (d[i] < last1) {
                    possible_p = false;
                    break;
                }
                colors[i] = 1;
                last1 = d[i];
            } else if (d[i] > p) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_p = false;
                    break;
                }
                colors[i] = 2;
                last2 = d[i];
            } else { // d[i] == p
                // Can be color 1 or 2.
                // If it can be color 2 (i.e., last2 <= p), prefer color 2 to keep last1 small.
                // If it must be color 1 (i.e., last2 > p), then it must be color 1.
                // If it can be color 1 (i.e., last1 <= p), then it can be color 1.

                // Strategy: If d[i] == p, assign it to color 2 if possible (d[i] >= last2).
                // Otherwise, assign it to color 1 if possible (d[i] >= last1).
                // This strategy tries to put 'p's into color 2 to keep color 1's max value low.
                if (d[i] >= last2) { // Can be color 2
                    colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) { // Must be color 1
                    colors[i] = 1;
                    last1 = d[i];
                } else { // Cannot be either
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            // Final check: last digit of S1 <= first digit of S2
            // This is implicitly handled by `last1 <= p` and `p <= last2` for digits equal to p.
            // If all digits are < p, last1 is max of those, last2 is -1.
            // If all digits are > p, last1 is -1, last2 is min of those.
            // If there are digits equal to p, they are split.
            // The logic `d[i] >= last1` and `d[i] >= last2` ensures internal sortedness.
            // The split point `p` ensures `max(S1) <= p <= min(S2)`.
            // If a digit `d[i] == p` is colored 1, it means `last1 <= p`.
            // If a digit `d[i] == p` is colored 2, it means `last2 <= p`.
            // The choice for `d[i] == p` is crucial.
            // Let's re-evaluate the `d[i] == p` case.
            // We want to find a `p` such that all `d_i < p` go to S1, all `d_i > p` go to S2.
            // For `d_i = p`, some go to S1, some go to S2.
            // All `p`s in S1 must appear before all `p`s in S2.
            // And `max(S1_digits_less_than_p)` <= `p` <= `min(S2_digits_greater_than_p)`.
            // This is guaranteed by the `p` value itself.
            // The only remaining condition is that `max(S1)` <= `min(S2)`.
            // If `last1` is the maximum digit in S1 and `first2` is the minimum digit in S2,
            // we need `last1 <= first2`.
            // Our current construction ensures `last1 <= p` and `p <= first2` (if `first2` is a digit `>p`).
            // If `first2` is a digit `==p`, then `last1 <= p` and `p <= p` is fine.
            // If `last1` is a digit `==p`, then `p <= first2` is fine.

            // The current logic for `d[i] == p`:
            // If `d[i] >= last2`, assign to 2. This means `p >= last2`.
            // Else if `d[i] >= last1`, assign to 1. This means `p >= last1`.
            // This ensures `last1` is always `p` or less, and `last2` is always `p` or less.
            // The critical point is that all digits colored 1 must be <= all digits colored 2.
            // This means `max(S1) <= min(S2)`.
            // With our current coloring, `max(S1)` will be `last1` (from the loop).
            // `min(S2)` will be `first2` (the first digit assigned to color 2).
            // We need to find `first2`.
            int actual_last1 = -1;
            int actual_first2 = 10;
            bool s1_empty = true;
            bool s2_empty = true;

            for(int i=0; i<n; ++i) {
                if (colors[i] == 1) {
                    actual_last1 = std::max(actual_last1, d[i]);
                    s1_empty = false;
                } else { // colors[i] == 2
                    actual_first2 = std::min(actual_first2, d[i]);
                    s2_empty = false;
                }
            }

            if (s1_empty || s2_empty || actual_last1 <= actual_first2) {
                for (int color : colors) {
                    std::cout << color;
                }
                std::cout << "\n";
                return;
            }
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<int> degree(26, 0);
    std::vector<bool> in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        in_s[s[i] - 'a'] = true;
        if (i > 0) {
            char c1 = s[i-1];
            char c2 = s[i];
            if (adj[c1 - 'a'].find(c2) == adj[c1 - 'a'].end()) {
                adj[c1 - 'a'].insert(c2);
                adj[c2 - 'a'].insert(c1);
                degree[c1 - 'a']++;
                degree[c2 - 'a']++;
            }
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (degree[i] > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && degree[i] <= 1 && !visited[i]) { // Start a path from an endpoint or isolated char in s
            char current_char = (char)('a' + i);

            // Traverse forward
            while (current_char != 0 && !visited[current_char - 'a']) {
                layout += current_char;
                visited[current_char - 'a'] = true;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                current_char = next_char;
            }
        }
    }

    // Check if all characters from s are included in the layout
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && !visited[i]) {
            // This means there's a cycle or a path that wasn't started from an endpoint
            // For example, if s="abc", degree of 'b' is 2, 'a' and 'c' are 1.
            // If we start from 'a', we get "abc". 'b' is visited.
            // If s="abacaba", 'a' has degree 2, 'b' has degree 2, 'c' has degree 2.
            // This case is handled by the degree check.
            // The only remaining case for unvisited `in_s` characters would be if `s` forms a cycle,
            // which is impossible with degree <= 2 and no self-loops.
            // Or if `s` forms a path but we didn't start from an endpoint.
            // The current logic should cover all paths.
            // If `in_s[i]` is true and `visited[i]` is false, it implies an issue.
            // However, with degree <= 2, all components are paths or isolated vertices.
            // We iterate through all `i` from 0 to 25. If `in_s[i]` is true and `degree[i] <= 1`,
            // we start a traversal. This should cover all paths.
            // If `in_s[i]` is true and `degree[i] == 2`, it must be part of a path.
            // If it's not visited, it means the path it belongs to wasn't fully traversed.
            // This can only happen if the path was not started from one of its endpoints.
            // But we iterate through all possible starting points (degree <= 1).
            // So, if `in_s[i]` is true and `visited[i]` is false, it's an error.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_part = (b-1) * b * inv(2) mod MOD
    // If b-1 is 0, sum_r_part is 0.
    long long sum_r_part = 0;
    if (b > 1) {
        long long b_minus_1 = b - 1;
        long long b_val = b;

        // (b-1) * b might be even or odd.
        // If b-1 is even, (b-1)/2 * b
        // If b is even, (b)/2 * (b-1)
        // One of them is always even, so (b-1)*b is always divisible by 2.
        // We need to compute (b-1) * b / 2 % MOD.
        // Since MOD is prime and > 2, we can use modular inverse for 2.
        // inv(2) mod MOD = (MOD + 1) / 2
        long long inv2 = (MOD + 1) / 2;

        sum_r_part = (b_minus_1 % MOD * (b_val % MOD)) % MOD;
        sum_r_part = (sum_r_part * inv2) % MOD;
    }

    // Sum of (k*b + 1) from k=1 to a:
    // sum_{k=1 to a} (k*b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    // This is sum_k_part = (b * (a * (a+1) * inv(2)) + a) mod MOD
    long long sum_k_part = 0;
    long long a_val = a;
    long long a_plus_1 = a + 1;
    long long inv2 = (MOD + 1) / 2; // inv(2) mod MOD

    long long sum_k_series = (a_val % MOD * (a_plus_1 % MOD)) % MOD;
    sum_k_series = (sum_k_series * inv2) % MOD; // (a * (a+1) / 2) % MOD

    long long term1 = (b % MOD * sum_k_series) % MOD; // (b * (a * (a+1) / 2)) % MOD
    long long term2 = a_val % MOD; // a % MOD

    sum_k_part = (term1 + term2) % MOD;

    // Total sum = (sum_r_part * sum_k_part) % MOD
    long long total_sum = (sum_r_part * sum_k_part) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));

    // If n is a perfect square, k*k = n.
    // We want to construct a permutation where LIS = k and LDS = k.
    // This can be done by dividing the numbers 1 to n into k blocks of size k.
    // For example, for n=9, k=3:
    // Block 1: 1 2 3
    // Block 2: 4 5 6
    // Block 3: 7 8 9
    // Permutation: [3 2 1, 6 5 4, 9 8 7]
    // LIS: [1, 4, 7] (length 3)
    // LDS: [3, 2, 1] (length 3)
    // Sum = 6.
    // This construction gives LIS = k and LDS = k.

    // If n is not a perfect square, k*k < n.
    // We can still use blocks.
    // Let k = floor(sqrt(n)).
    // We want LIS and LDS to be close to sqrt(n).
    // A construction that achieves LIS = ceil(n/k) and LDS = k is as follows:
    // Divide numbers 1 to n into blocks of size k.
    // The last block might be smaller.
    // For each block, reverse the order of elements.
    // Example: n=4, k=2
    // Blocks: [1,2], [3,4]
    // Permutation: [2,1,4,3]
    // LIS: [2,4] or [1,3] (length 2)
    // LDS: [2,1] or [4,3] (length 2)
    // Sum = 4.
    // Here, ceil(n/k) = ceil(4/2) = 2. LIS = 2, LDS = 2.

    // Example: n=5, k=2
    // Blocks: [1,2], [3,4], [5]
    // Permutation: [2,1,4,3,5]
    // LIS: [2,4,5] or [1,3,5] (length 3)
    // LDS: [2,1] or [4,3] (length 2)
    // Sum = 5.
    // Here, ceil(n/k) = ceil(5/2) = 3. LIS = 3, LDS = 2.

    // The general construction:
    // Iterate from i = 0 to n-1.
    // The number at index i in the permutation will be part of block (i / k).
    // The numbers in block j (0-indexed) are from (j*k + 1) to min((j+1)*k, n).
    // To reverse the block, for an element at index i, its value is
    // (j*k + k) - (i % k).
    // Or more simply, for each block starting at `start_val`, print `start_val + k - 1`, `start_val + k - 2`, ..., `start_val`.
    // But we need to handle the last block which might be smaller.

    // Let's refine the block construction.
    // We want to print numbers in groups of `k`.
    // For each group, print them in decreasing order.
    // The groups are `1..k`, `k+1..2k`, etc.
    // The last group will be `(num_blocks-1)*k + 1 .. n`.

    int current_val = n;
    while (current_val > 0) {
        int start_of_block = std::max(1, current_val - k + 1);
        for (int i = current_val; i >= start_of_block; --i) {
            std::cout << i << " ";
        }
        current_val = start_of_block - 1;
    }
    std::cout << std::endl;

    return 0;
