    // `right_balance[0]` = 0 (no jars removed from right)
    // `right_balance[1]` = balance of `a[n]`
    // `right_balance[k]` = balance of `a[n]`...`a[n+k-1]`
    std::map<int, int> right_balance_to_k; // maps balance_val -> min_k_R
    right_balance_to_k[0] = 0; // 0 jars removed from right, balance is 0

    int current_balance_R = 0;
    for (int k_R = 1; k_R <= n; ++k_R) {
        int jar_idx = n + k_R - 1; // The jar being "removed" from the right side
        if (a[jar_idx] == 1) {
            current_balance_R++;
        } else {
            current_balance_R--;
        }
        if (right_balance_to_k.find(current_balance_R) == right_balance_to_k.end()) {
            right_balance_to_k[current_balance_R] = k_R;
        }
    }

    // Calculate initial total balance (all 2n jars)
    int total_initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            total_initial_balance++;
        } else {
            total_initial_balance--;
        }
    }

    int min_jars_removed = 2 * n; // Max possible jars removed

    // Iterate through all possible balances achieved by removing jars from the left
    // For each `k_L` jars removed from the left, the balance of these `k_L` jars is `bal_L`.
    // The remaining jars have a balance of `total_initial_balance - bal_L`.
    // We need to remove `k_R` jars from the right such that their balance `bal_R`
    // makes the final remaining balance zero.
    // So, `total_initial_balance - bal_L - bal_R = 0`
    // This means `bal_R = total_initial_balance - bal_L`.
    // We need to find if `total_initial_balance - bal_L` exists in `right_balance_to_k`.

    for (auto const& [bal_L, k_L] : left_balance_to_k) {
        int target_bal_R = total_initial_balance - bal_L;
        if (right_balance_to_k.count(target_bal_R)) {
            int k_R = right_balance_to_k[target_bal_R];
            min_jars_removed = std::min(min_jars_removed, k_L + k_R);
        }
    }

    std::cout << min_jars_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive 0s ending at i
    if (a[0] == 0) L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R[i]: length of consecutive 0s starting at i
    if (a[n - 1] == 0) R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros == 0 && right_zeros == 0) {
                // 1 surrounded by 1s, or at boundary
                // This 1 will never change to 0
            } else if (left_zeros == 0) { // 1...0
                max_k = std::max(max_k, (right_zeros + 1) / 2);
            } else if (right_zeros == 0) { // 0...1
                max_k = std::max(max_k, (left_zeros + 1) / 2);
            } else { // 0...1...0
                max_k = std::max(max_k, std::min(left_zeros, right_zeros));
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1) {
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros == 0 && right_zeros == 0) {
                // 1 surrounded by 1s, or at boundary
                // Stays 1
            } else if (left_zeros == 0) { // 1...0
                if (right_zeros < 2 * max_k) {
                    b[i] = 0;
                }
            } else if (right_zeros == 0) { // 0...1
                if (left_zeros < 2 * max_k) {
                    b[i] = 0;
                }
            } else { // 0...1...0
                if (left_zeros < max_k || right_zeros < max_k) {
                    b[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // The number of 'a's currently to the left of this 'b'
            // is `count_a`.
            // Each such 'a' will cause `count_a` operations involving this 'b'.
            // Specifically, when an 'a' moves past this 'b', it creates a new 'b'.
            // The 'a' then needs to move past this new 'b' as well.
            // The total number of operations this 'b' contributes is `count_a`.
            // After this 'b' is processed, it effectively doubles the number of 'a's
            // that will interact with subsequent 'b's to its left.
            // This is because each 'a' that passes this 'b' creates a new 'b',
            // and this new 'b' will also need to be passed by 'a's further left.
            // The number of 'a's effectively doubles for the next 'b' to the left.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are currently to the right of any 'b's we've processed so far.
            // These 'a's will interact with 'b's further to their left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n); // a_suffix[k] stores a_{k+1}
    for (int k = 0; k < n - 1; ++k) {
        std::cin >> a_suffix[k];
    }

    // dp_x[k] stores the final x value if we start at index k+1 with a_k+1
    // dp_y[k] stores the final y value if we start at index k+1 with a_k+1
    // dp_x[k] = 0 means it terminates at x <= 0
    // dp_x[k] = n+1 means it terminates at x > n
    // dp_x[k] = -1 means it's part of a cycle (non-terminating)
    std::vector<long long> dp_x(n + 1);
    std::vector<long long> dp_y(n + 1);
    std::vector<bool> visited(n + 1, false); // For cycle detection

    // Base cases:
    // If x + a_x <= 0, then x becomes <= 0.
    // If x + a_x > n, then x becomes > n.
    // In these cases, the program terminates after step_add.
    // The y value is just a_x.
    // The final x value is 0 or n+1 respectively.
    //
    // If x - a_x <= 0, then x becomes <= 0.
    // If x - a_x > n, then x becomes > n.
    // In these cases, the program terminates after step_sub.
    // The y value is a_x + a_x = 2*a_x.
    // The final x value is 0 or n+1 respectively.

    // Iterate backwards from n to 1
    for (int k = n; k >= 1; --k) {
        long long current_a_val = a_suffix[k - 1]; // a_k

        long long next_x_after_add = k + current_a_val;
        long long next_x_after_sub = k - current_a_val;

        if (next_x_after_add <= 0) { // Terminates after step_add
            dp_x[k] = 0;
            dp_y[k] = current_a_val;
        } else if (next_x_after_add > n) { // Terminates after step_add
            dp_x[k] = n + 1;
            dp_y[k] = current_a_val;
        } else { // Continues to step_sub
            if (next_x_after_sub <= 0) { // Terminates after step_sub
                dp_x[k] = 0;
                dp_y[k] = current_a_val + current_a_val;
            } else if (next_x_after_sub > n) { // Terminates after step_sub
                dp_x[k] = n + 1;
                dp_y[k] = current_a_val + current_a_val;
            } else { // Continues to next iteration
                // This is where we use DP. The next state is (next_x_after_sub, current_a_val + current_a_val + dp_y[next_x_after_sub])
                // We need to handle cycles.

                // Simulate the path from k to detect cycles or find a known state
                std::vector<int> path;
                int current_pos = k;
                long long current_total_y = 0;

                while (current_pos >= 1 && current_pos <= n && !visited[current_pos] && dp_x[current_pos] == 0) { // dp_x[current_pos] == 0 means not yet computed
                    visited[current_pos] = true;
                    path.push_back(current_pos);

                    long long val_at_pos = a_suffix[current_pos - 1];
                    current_total_y += val_at_pos; // y after step_add

                    long long next_x_after_add_path = current_pos + val_at_pos;
                    if (next_x_after_add_path <= 0 || next_x_after_add_path > n) {
                        current_pos = (next_x_after_add_path <= 0) ? 0 : n + 1;
                        break;
                    }

                    current_total_y += val_at_pos; // y after step_sub
                    current_pos = next_x_after_add_path - val_at_pos; // x after step_sub
                }

                if (current_pos <= 0 || current_pos > n) { // Terminated
                    for (int p_idx = 0; p_idx < path.size(); ++p_idx) {
                        int p = path[p_idx];
                        dp_x[p] = current_pos;
                        dp_y[p] = current_total_y;
                        current_total_y -= (2 * a_suffix[p - 1]); // Subtract 2*a_p to get y for previous state
                    }
                } else if (dp_x[current_pos] == -1) { // Cycle detected
                    for (int p : path) {
                        dp_x[p] = -1;
                        dp_y[p] = -1;
                    }
                } else { // Reached a previously computed state
                    long long final_x_from_known = dp_x[current_pos];
                    long long final_y_from_known = dp_y[current_pos];

                    for (int p_idx = path.size() - 1; p_idx >= 0; --p_idx) {
                        int p = path[p_idx];
                        dp_x[p] = final_x_from_known;
                        dp_y[p] = final_y_from_known + (2 * a_suffix[p - 1]);
                        final_y_from_known = dp_y[p]; // Update for the next iteration (previous state in path)
                    }
                }

                // Reset visited for the current path
                for (int p : path) {
                    visited[p] = false;
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        long long a1_val = i;
        long long current_y = 0;
        int current_x = 1;

        // First step_add
        current_y += a1_val;
        int next_x_after_add = current_x + a1_val;

        if (next_x_after_add <= 0 || next_x_after_add > n) {
            std::cout << current_y << "\n";
        } else {
            // First step_sub
            current_y += a1_val;
            int next_x_after_sub = next_x_after_add - a1_val;

            if (next_x_after_sub <= 0 || next_x_after_sub > n) {
                std::cout << current_y << "\n";
            } else {
                // Now we are at state (next_x_after_sub, current_y) and need to continue
                // This is where we use the precomputed DP values
                if (dp_x[next_x_after_sub] == -1) { // Cycle detected
                    std::cout << -1 << "\n";
                } else {
                    std::cout << current_y + dp_y[next_x_after_sub] << "\n";
                }
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type; // 1 for add, 2 for max
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[i] to a very large value.
    // This represents a_0[i] - sum_of_deltas_up_to_current_op_k_for_i
    // For type 2 operations, we have a_0[j] + current_delta_sum[j] <= m_k
    // which means a_0[j] <= m_k - current_delta_sum[j].
    // We want to find the minimum possible a_0[j] that satisfies all constraints.
    // So, a_0[j] <= min(m_k - current_delta_sum[j]) over all relevant type 2 ops.
    // We initialize a_0[j] to a large value and update it with min.
    std::vector<long long> initial_a(n, 2000000000LL); // Max possible value for a_0[j] is 10^9 + 5*10^7 (max m) + 5000*10^4 (max delta sum) ~ 1.5*10^8.
                                                      // 2*10^9 is safe.

    // Iterate operations in reverse to calculate the required initial_a values.
    // When processing an operation k, we need the sum of deltas from operations k+1 to m-1.
    // Let's call this `suffix_delta_sum`.
    std::vector<long long> suffix_delta_sum(n, 0);

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1: Add d to a[l...r].
            // This operation affects future operations.
            // For elements j in [l, r], their `suffix_delta_sum` increases by `d`.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                suffix_delta_sum[j] += ops[i].val;
            }
        } else {
            // Type 2: max(a[l...r]) = m.
            // This means a_0[j] + (sum of all deltas up to op i) <= m for j in [l, r].
            // The sum of all deltas up to op i is (sum of deltas from op 0 to i-1) + (delta from op i itself if type 1).
            // Here, we are working with `suffix_delta_sum`, which is sum of deltas from op i+1 to m-1.
            // So, a_0[j] + (sum of deltas from op 0 to i-1) <= m.
            // Let `current_delta_sum_at_op_i[j]` be the sum of deltas from ops 0 to i-1 that affect j.
            // Then `a_0[j] + current_delta_sum_at_op_i[j] <= ops[i].val`.
            // We know `current_delta_sum_at_op_i[j] + suffix_delta_sum[j]` is the total sum of deltas from ops 0 to m-1.
            // This is not quite right. Let's redefine.
            // Let `A_k[j]` be the value of `a[j]` just before operation `k`.
            // `A_k[j] = a_0[j] + \sum_{p=0}^{k-1} \text{delta_p_if_affects_j}`.
            // For a type 2 op `k` with `l, r, m_k`:
            // `A_k[j] <= m_k` for `j \in [l, r]`.
            // So `a_0[j] + \sum_{p=0}^{k-1} \text{delta_p_if_affects_j} <= m_k`.
            // `a_0[j] <= m_k - \sum_{p=0}^{k-1} \text{delta_p_if_affects_j}`.
            // We want to find the minimum `a_0[j]` that satisfies all these.
            // So `a_0[j] = \min_{k \text{ s.t. type 2 op } k \text{ affects } j} (m_k - \sum_{p=0}^{k-1} \text{delta_p_if_affects_j})`.

            // Let `current_delta_sum[j]` be the sum of `d` values from operations `0` to `i-1` that affect `j`.
            // The `suffix_delta_sum` we are maintaining is actually `\sum_{p=i+1}^{m-1} \text{delta_p_if_affects_j}`.
            // So, `\sum_{p=0}^{i-1} \text{delta_p_if_affects_j}` is `total_delta_sum_from_0_to_m-1[j] - suffix_delta_sum[j]`.
            // This is getting complicated. Let's simplify.

            // Let `a_0[j]` be the initial value.
            // Let `D_k[j]` be the sum of `d` values from operations `0` to `k-1` that affect index `j`.
            // At operation `k`, the value of `a[j]` is `a_0[j] + D_k[j]`.
            // If operation `k` is type 2 (`l_k, r_k, m_k`):
            // For all `j \in [l_k, r_k]`, we must have `a_0[j] + D_k[j] <= m_k`.
            // This implies `a_0[j] <= m_k - D_k[j]`.
            // So, for each `j`, `a_0[j]` must be less than or equal to `m_k - D_k[j]` for all type 2 operations `k` where `j \in [l_k, r_k]`.
            // Therefore, `a_0[j] = \min_{k \text{ s.t. type 2 op } k \text{ affects } j} (m_k - D_k[j])`.
            // If `j` is not affected by any type 2 op, `a_0[j]` can be anything, say 0.

            // We can compute `D_k[j]` by iterating forward.
            // Or, we can compute `m_k - D_k[j]` by iterating backward.
            // Let `current_delta_sum[j]` be `\sum_{p=0}^{i-1} \text{delta_p_if_affects_j}`.
            // When we process operation `i` (from `m-1` down to `0`):
            // If `ops[i]` is type 1: `l, r, d`. This `d` is part of `D_{i+1}[j]`, `D_{i+2}[j]`, etc.
            // So, for `j \in [l, r]`, `D_i[j]` is `D_{i+1}[j] - d`.
            // If `ops[i]` is type 2: `l, r, m`.
            // For `j \in [l, r]`, we have `a_0[j] <= m - D_i[j]`.
            // So we update `initial_a[j] = min(initial_a[j], m - D_i[j])`.

            // Let `current_delta_sum[j]` be `D_i[j]` (sum of deltas from ops 0 to i-1).
            // When we iterate `i` from `m-1` down to `0`:
            // If `ops[i]` is type 1 (`l, r, d`):
            // This `d` is part of `D_{i+1}[j]`, `D_{i+2}[j]`, etc.
            // So, for `j \in [l, r]`, `current_delta_sum[j]` (which is `D_i[j]`) should be `D_{i+1}[j] - d`.
            // This means we should subtract `d` from `current_delta_sum[j]` for `j \in [l, r]` *after* processing op `i`.
            // If `ops[i]` is type 2 (`l, r, m`):
            // For `j \in [l, r]`, `a_0[j] <= m - current_delta_sum[j]`.
            // So, `initial_a[j] = min(initial_a[j], m - current_delta_sum[j])`.

            // Let's use `current_delta_sum[j]` to store `D_i[j]` for the current `i`.
            // Initialize `current_delta_sum` to all zeros.
            // Iterate `i` from `0` to `m-1`.
            // If `ops[i]` is type 1: `l, r, d`.
            // For `j \in [l, r]`, `current_delta_sum[j]` increases by `d`.
            // If `ops[i]` is type 2: `l, r, m`.
            // For `j \in [l, r]`, `a_0[j] <= m - current_delta_sum[j]`.
            // This means `initial_a[j]` should be updated with `min(initial_a[j], m - current_delta_sum[j])`.
            // This approach requires `initial_a` to be initialized to a large value.

            // This is the correct approach:
            // `initial_a[j]` stores `min(m_k - D_k[j])` over all type 2 ops `k` affecting `j`.
            // `D_k[j]` is the sum of `d` values from ops `0` to `k-1` that affect `j`.
            // We can compute `D_k[j]` by iterating `k` from `0` to `m-1`.
            // `current_delta_sum[j]` will store `D_k[j]`.
            // `initial_a[j]` will store the minimum `m_k - D_k[j]` encountered so far.

            // Initialize `initial_a` to a large value (e.g., 2*10^9).
            // Initialize `current_delta_sum` to all zeros.
            // Loop `k` from `0` to `m-1`:
            //   If `ops[k]` is type 1 (`l, r, d`):
            //     For `j` from `l` to `r`: `current_delta_sum[j] += d`.
            //   If `ops[k]` is type 2 (`l, r, m`):
            //     For `j` from `l` to `r`: `initial_a[j] = min(initial_a[j], m - current_delta_sum[j])`.

            // After this loop, `initial_a[j]` will hold the maximum possible value for `a_0[j]`
            // that satisfies all `a_0[j] + D_k[j] <= m_k` constraints.
            // If `initial_a[j]` is still 2*10^9, it means `j` was not constrained by any type 2 operation.
            // In this case, we can set `a_0[j] = 0` (or any value within bounds).
            // Let's set it to 0.
        }
    }

    // Re-initialize `initial_a` for the forward pass.
    std::fill(initial_a.begin(), initial_a.end(), 2000000000LL); // Use a large value to represent unconstrained
    std::vector<long long> current_delta_sum(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_sum[j] += ops[i].val;
            }
        } else {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta_sum[j]);
            }
        }
    }

    // Set unconstrained initial_a values to 0.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == 2000000000LL) {
            initial_a[i] = 0;
        }
    }

    // Now, verify the solution.
    // Simulate all operations with the found `initial_a` and check if all conditions are met.
    std::vector<long long> a = initial_a;
    std::vector<long long> current_prefix_delta(n, 0); // Sum of deltas from ops 0 to i-1

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a[j] += ops[i].val;
                current_prefix_delta[j] += ops[i].val;
            }
        } else {
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int i = 0; i < n; ++i) {
        if (std::abs(initial_a[i]) > 1000000000LL) {
            // This should ideally not happen if the logic is correct and a solution exists.
            // The max value for m_k is 5*10^7. Max delta sum is 5000 * 10^4 = 5*10^7.
            // So m_k - D_k[j] can be around 5*10^7 - (-5*10^7) = 10^8.
            // Or -5*10^7 - (5*10^7) = -10^8.
            // So initial_a[i] should be within [-10^8, 10^8], which is well within [-10^9, 10^9].
            // This check is mostly for robustness.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0; // Value if input is 0
    int current_val_1023 = 1023; // Value if input is 1023 (all 1s for 10 bits)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    int final_and_mask = 1023; // All 1s
    int final_or_mask = 0;     // All 0s
    int final_xor_mask = 0;    // All 0s

    for (int bit = 0; bit < 10; ++bit) {
        int bit_val_0 = (current_val_0 >> bit) & 1;
        int bit_val_1023 = (current_val_1023 >> bit) & 1;

        if (bit_val_0 == 0 && bit_val_1023 == 0) {
            // Input bit 0 -> Output bit 0
            // Input bit 1 -> Output bit 0
            // This means the bit is always 0, regardless of input.
            // Achieved by ANDing with 0 at this bit position.
            final_and_mask &= ~(1 << bit);
        } else if (bit_val_0 == 1 && bit_val_1023 == 1) {
            // Input bit 0 -> Output bit 1
            // Input bit 1 -> Output bit 1
            // This means the bit is always 1, regardless of input.
            // Achieved by ORing with 1 at this bit position.
            final_or_mask |= (1 << bit);
        } else if (bit_val_0 == 0 && bit_val_1023 == 1) {
            // Input bit 0 -> Output bit 0
            // Input bit 1 -> Output bit 1
            // This means the bit is unchanged (x_i -> x_i).
            // Achieved by ANDing with 1 and XORing with 0.
            // No change needed for this bit in final_and_mask or final_xor_mask.
        } else if (bit_val_0 == 1 && bit_val_1023 == 0) {
            // Input bit 0 -> Output bit 1
            // Input bit 1 -> Output bit 0
            // This means the bit is flipped (x_i -> !x_i).
            // Achieved by XORing with 1 at this bit position.
            final_xor_mask |= (1 << bit);
        }
    }

    if (final_and_mask != 1023) { // If any bit was forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit was forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit was flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int current_parity_a = calculate_parity(a);

    // The maximum length string we might need to generate from 'a'
    // is 'a' extended until its length is equal to 'b' plus the maximum
    // possible number of '1's in 'a' (which is its length).
    // This is a loose upper bound, but sufficient.
    // A tighter bound is |b| + 1, because if |a| < |b|, we need to extend 'a'
    // until it's at least |b|. If |a| >= |b|, we don't need to extend 'a'
    // to match length, but we might need to extend it to change its parity.
    // The maximum length of 'a' we need to consider is |b| + 1.
    // If |a| is already longer than |b|, we can just check suffixes.
    // If |a| is shorter than |b|, we need to extend it.
    // The maximum length of 'a' we need to consider is max(|a|, |b|) + 1.
    // Since |a|, |b| <= 1000, max length is around 1001.
    // Let's just generate up to |b| + 1 characters.
    // The string 'a' can grow up to length |b| + 1.
    // If |a| is already longer than |b|, we don't need to extend it.
    // If |a| is shorter than |b|, we need to extend it until it's at least |b|.
    // The maximum length of 'a' we need to consider is |b| + 1.
    // This is because if we need to match 'b', and 'b' has length L,
    // we need to generate a string 'a_prime' of length at least L.
    // If 'a_prime' has length L, its parity is calculated.
    // If we append this parity, 'a_prime' becomes length L+1.
    // This new string of length L+1 might be a candidate.
    // So, we need to consider strings up to length |b|+1.
    // The original string 'a' can have length up to 1000.
    // The target string 'b' can have length up to 1000.
    // So, we need to generate 'a' up to length 1001.

    std::string current_a_str = a;
    std::vector<int> parities; // Stores parities of prefixes of current_a_str
    parities.push_back(0); // Parity of empty string is 0 (convention for sum of ones)

    // Calculate parities for initial 'a'
    for (char c : a) {
        parities.push_back(parities.back() ^ (c - '0'));
    }

    // Extend 'a' by appending parities until its length is |b| + 1
    // or until it's long enough to cover all possible suffixes of 'b'.
    // We need to generate 'a' up to length |b| + 1.
    // If original 'a' is already longer than |b|+1, we don't need to extend.
    while (current_a_str.length() < b.length() + 1) {
        int next_parity = parities.back(); // Parity of current_a_str
        current_a_str += (next_parity == 1 ? '1' : '0');
        parities.push_back(parities.back() ^ next_parity);
    }

    // Now, current_a_str contains the original 'a' followed by some appended parities.
    // Its length is at least |b|+1 (unless original |a| was already >= |b|+1).
    // We need to check if 'b' is a suffix of any string that can be formed.
    // A string 's' can be formed if it's a suffix of current_a_str, AND
    // the parity of 's' matches the parity of 'b'.
    // The parity of 's' is parities[end_index] ^ parities[start_index].
    // Here, end_index is current_a_str.length(), and start_index is current_a_str.length() - s.length().

    int parity_b = calculate_parity(b);

    // Iterate through all possible starting positions for 'b' within current_a_str.
    // The starting position `i` means `b` starts at `current_a_str[i]`.
    // So, `current_a_str.substr(i, b.length())` is a candidate for `b`.
    // This candidate string must have length `b.length()`.
    // The loop should go from `0` up to `current_a_str.length() - b.length()`.
    for (size_t i = 0; i <= current_a_str.length() - b.length(); ++i) {
        // Check if the substring matches 'b'
        if (current_a_str.substr(i, b.length()) == b) {
            // If it matches, we need to check if its parity is correct.
            // The parity of current_a_str.substr(i, b.length()) is
            // parities[i + b.length()] ^ parities[i].
            if ((parities[i + b.length()] ^ parities[i]) == parity_b) {
                std::cout << "YES\n";
                return 0;
            }
        }
    }

    std::cout << "NO\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    int id;
    long long v, d, p;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_line.push_back({i + 1, v_val, d_val, p_val});
    }

    std::vector<int> cured_children_ids;

    while (!children_line.empty()) {
        Child current_child = children_line.front();
        children_line.pop_front();
        cured_children_ids.push_back(current_child.id);

        long long current_v_cry = current_child.v;
        long long total_d_cry_from_runners = 0;

        auto it = children_line.begin();
        while (it != children_line.end()) {
            // Apply cry from current_child (v_i)
            if (current_v_cry > 0) {
                it->p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated cry from runners (d_j)
            it->p -= total_d_cry_from_runners;

            if (it->p < 0) {
                total_d_cry_from_runners += it->d;
                it = children_line.erase(it); // Child runs away
            } else {
                ++it;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_val_all_same = elements[0].value + elements[1].value;
    long long max_val_all_same = elements[n - 1].value + elements[n - 2].value;

    long long min_goodness = max_val_all_same - min_val_all_same;
    std::vector<int> best_partition(n, 1); // Default to all in partition 1

    // Case 1: All elements in one partition (e.g., all 1s).
    // f values are a_i + a_j.
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    // This is already covered by initializing min_goodness and best_partition.

    // Case 2: At least one element in each partition.
    // This means there will be f values of type a_i + a_j and a_k + a_l + h.
    // The minimum possible f value is min(a_i + a_j, a_k + a_l + h).
    // The maximum possible f value is max(a_i + a_j, a_k + a_l + h).

    // Consider putting elements[0] in S1 and elements[1] in S2.
    // The smallest possible sum is elements[0].value + elements[1].value.
    // If elements[0] and elements[1] are in different partitions, f(elements[0], elements[1]) = elements[0].value + elements[1].value + h.
    // If elements[0] and elements[1] are in the same partition, f(elements[0], elements[1]) = elements[0].value + elements[1].value.

    // Let's try a specific partition: elements[0] in S1, elements[1]...elements[n-1] in S2.
    // This is a common strategy for problems involving min/max and two groups.
    // The smallest element elements[0] is in S1.
    // All other elements elements[1]...elements[n-1] are in S2.
    //
    // Pairs within S1: None (if S1 has only one element) or elements[0].value + elements[0].value (if n=1, not possible here)
    // Pairs within S2:
    //   min_S2_sum = elements[1].value + elements[2].value
    //   max_S2_sum = elements[n-1].value + elements[n-2].value
    // Pairs between S1 and S2:
    //   min_S1S2_sum = elements[0].value + elements[1].value + h
    //   max_S1S2_sum = elements[0].value + elements[n-1].value + h

    // Overall min_f:
    //   If n=2: S1={elements[0]}, S2={elements[1]}. Only one pair: elements[0].value + elements[1].value + h.
    //           min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    //   If n > 2:
    //     min_f = std::min(min_S2_sum, min_S1S2_sum)
    //     min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // Overall max_f:
    //   If n=2: max_f = elements[0].value + elements[1].value + h.
    //   If n > 2:
    //     max_f = std::max(max_S2_sum, max_S1S2_sum)
    //     max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)

    if (n >= 2) { // This condition is always true based on constraints (n >= 2)
        long long current_min_f, current_max_f;
        if (n == 2) {
            current_min_f = elements[0].value + elements[1].value + h;
            current_max_f = elements[0].value + elements[1].value + h;
        } else { // n > 2
            current_min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
            current_max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            std::fill(best_partition.begin(), best_partition.end(), 2); // All in partition 2
            best_partition[elements[0].original_index] = 1; // elements[0] in partition 1
        }
    }

    // Consider another specific partition: elements[0]...elements[n-2] in S1, elements[n-1] in S2.
    // The largest element elements[n-1] is in S2.
    // All other elements elements[0]...elements[n-2] are in S1.
    //
    // Pairs within S1:
    //   min_S1_sum = elements[0].value + elements[1].value
    //   max_S1_sum = elements[n-2].value + elements[n-3].value (if n-1 >= 2, i.e., n >= 3)
    // Pairs between S1 and S2:
    //   min_S1S2_sum = elements[0].value + elements[n-1].value + h
    //   max_S1S2_sum = elements[n-2].value + elements[n-1].value + h

    if (n >= 2) {
        long long current_min_f, current_max_f;
        if (n == 2) {
            current_min_f = elements[0].value + elements[1].value + h;
            current_max_f = elements[0].value + elements[1].value + h;
        } else { // n > 2
            current_min_f = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
            current_max_f = std::max(elements[n-2].value + elements[n-3].value, elements[n-2].value + elements[n-1].value + h);
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            std::fill(best_partition.begin(), best_partition.end(), 1); // All in partition 1
            best_partition[elements[n-1].original_index] = 2; // elements[n-1] in partition 2
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

