// Z-algorithm implementation
std::vector<int> calculate_z_function(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-functions for all suffixes of s
    // z_functions[i] stores the Z-array for s.substr(i)
    std::vector<std::vector<int>> z_functions(L);
    for (int i = 0; i < L; ++i) {
        z_functions[i] = calculate_z_function(s.substr(i));
    }

    // For each possible first character t_0 (which is s_k)
    // Calculate the probability of winning given t_0
    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char t0_char = s[k_actual];

        // Find all possible initial shifts k' such that s[k'] == t0_char
        std::vector<int> possible_k_indices;
        for (int i = 0; i < L; ++i) {
            if (s[i] == t0_char) {
                possible_k_indices.push_back(i);
            }
        }

        if (possible_k_indices.size() == 1) {
            // If only one k' matches t0_char, Vasya wins immediately.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p to reveal t_p
        // to maximize the chance of uniquely identifying k_actual.
        // We iterate through all possible p from 1 to L-1.
        // For each p, we count how many k' in possible_k_indices
        // would be uniquely identified if t_p was revealed.
        // Vasya chooses p that maximizes this count.

        int max_unique_count_for_t0 = 0;

        for (int p = 1; p < L; ++p) {
            // For a fixed p, we want to find how many k' in possible_k_indices
            // would be uniquely identified if t_p was revealed.
            // t_p = s[(k_actual + p) % L]
            char tp_char = s[(k_actual + p) % L];

            // Count how many k' in possible_k_indices match t_p
            // and also match t_0.
            std::vector<int> matching_k_for_p;
            for (int k_prime : possible_k_indices) {
                if (s[(k_prime + p) % L] == tp_char) {
                    matching_k_for_p.push_back(k_prime);
                }
            }

            if (matching_k_for_p.size() <= 1) {
                // If only one or zero k' match t_0 and t_p, Vasya wins.
                // This means k_actual is uniquely identified among the initial candidates.
                max_unique_count_for_t0 = std::max(max_unique_count_for_t0, 1);
                continue;
            }

            // Now we have multiple candidates k' that match t_0 and t_p.
            // Vasya wins if k_actual is the only one among these that matches
