#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] stores the maximum j such that s[j...i] contains no 3-AP.
    // This means for any l, r such that j <= l <= r <= i, s[l...r] contains no 3-AP.
    // Or, more precisely, for any l, r such that j <= l <= r <= i,
    // there is no x, k such that l <= x < x+2k <= r and s_x = s_{x+k} = s_{x+2k}.
    // This is equivalent to saying that for any x, k such that x+2k <= i,
    // if s_x = s_{x+k} = s_{x+2k}, then x < j.
    // So dp[i] is the smallest possible starting index for a substring ending at i
    // that contains no 3-AP.
    // Or, dp[i] is the maximum l such that the substring s[l...i] contains no 3-AP.
    // Any substring s[l'...i] with l' >= l will also contain no 3-AP.
    // So, dp[i] is the smallest index such that for any x, k with x >= dp[i] and x+2k <= i,
    // s_x = s_{x+k} = s_{x+2k} is false.
    // This is equivalent to: dp[i] is the smallest index such that for any x, k with x+2k <= i,
    // if s_x = s_{x+k} = s_{x+2k}, then x < dp[i].
    // Let's define dp[i] as the smallest index `p` such that for any `x, k` with `p <= x` and `x+2k <= i`,
    // it is NOT true that `s_x = s_{x+k} = s_{x+2k}`.
    // This means any substring `s[p...i]` does not contain a 3-AP.
    // And any substring `s[l...i]` with `l >= p` also does not contain a 3-AP.
    // The number of such substrings ending at `i` is `i - p + 1`.

    std::vector<int> dp(n);
    if (n > 0) {
        dp[0] = 0;
    }
    for (int i = 1; i < n; ++i) {
        dp[i] = dp[i-1]; // Inherit from previous. If s[dp[i-1]...i-1] had no 3-AP, then s[dp[i-1]...i] might.
                         // But if s[dp[i-1]...i-1] had no 3-AP, then s[dp[i-1]...i] also has no 3-AP
                         // unless a new 3-AP is formed that ends at i.
                         // The new 3-AP must be of the form (x, x+k, i).
                         // So, dp[i] should be at least dp[i-1].
                         // It's the smallest starting index for a valid substring ending at i.
                         // So, dp[i] = max(dp[i-1], (potential new constraint)).
    }

    // The actual definition of dp[i] should be:
    // dp[i] = max(dp[i-1], max_x_for_3AP_ending_at_i + 1)
    // where max_x_for_3AP_ending_at_i is the largest x such that x+2k = i and s_x = s_{x+k} = s_{x+2k}.
    // If no such x exists, this max is -1.
    // So, dp[i] is the smallest index `p` such that for any `x, k` with `p <= x` and `x+2k <= i`,
    // it is NOT true that `s_x = s_{x+k} = s_{x+2k}`.
    // This means `p` must be greater than any `x` that forms a 3-AP `(x, x+k, x+2k)` where `x+2k <= i`.
    // So `p = max(x_val_for_any_3AP_ending_at_or_before_i) + 1`.
    // Let `last_bad_start[i]` be the maximum `x` such that `x+2k <= i` and `s_x = s_{x+k} = s_{x+2k}`.
    // If no such `x` exists, `last_bad_start[i] = -1`.
    // Then `dp[i] = last_bad_start[i] + 1`.
    // The number of bad pairs ending at `i` is `i - dp[i] + 1`.

    // Let's re-evaluate `dp[i]` as the smallest `l` such that `s[l...i]` contains no 3-AP.
    // This means for any `x, k` such that `l <= x < x+2k <= i`, `s_x = s_{x+k} = s_{x+2k}` is false.
    // This is equivalent to `l > x` for all `x, k` such that `x+2k <= i` and `s_x = s_{x+k} = s_{x+2k}`.
    // So `l` must be `max(x_val_for_any_3AP_ending_at_or_before_i) + 1`.
    // Let `max_x_val_for_3AP_ending_at_or_before_i` be `M_i`.
    // Then `dp[i] = M_i + 1`.
    // The number of bad pairs `(l, i)` is `i - dp[i] + 1`.
    // `dp[i]` is non-decreasing. `M_i = max(M_{i-1}, max_x_val_for_3AP_ending_at_i)`.
    // So `dp[i] = max(dp[i-1], max_x_val_for_3AP_ending_at_i + 1)`.
    // `max_x_val_for_3AP_ending_at_i` is the largest `x` such that `x+2k = i` and `s_x = s_{x+k} = s_{x+2k}`.

    int current_max_x_for_3AP = -1; // Max x such that x+2k <= current_i and s_x=s_{x+k}=s_{x+2k}
    for (int i = 0; i < n; ++i) {
        // Check for new 3-APs ending at i
        // A 3-AP is (x, x+k, x+2k). If x+2k = i, then x+k = i-k.
        // So we need s_x = s_{i-k} = s_i.
        // The possible values for k are such that x >= 0 and x+2k = i.
        // x = i - 2k. So i - 2k >= 0 => 2k <= i => k <= i/2.
        // Also k >= 1.
        // So we check k from 1 to i/2.
        // For each k, x = i - 2k.
        // If s[i-2k] == s[i-k] == s[i], then we found a 3-AP.
        // The x for this 3-AP is i-2k.
        // We need to update current_max_x_for_3AP.
        for (int k = 1; k * 2 <= i; ++k) {
            int x = i - 2 * k;
            if (s[x] == s[x + k] && s[x + k] == s[i]) {
                current_max_x_for_3AP = std::max(current_max_x_for_3AP, x);
            }
        }

        // dp[i] is the smallest l such that s[l...i] contains no 3-AP.
        // This means l must be greater than any x that forms a 3-AP (x, x+k, x+2k) with x+2k <= i.
        // So l = current_max_x_for_3AP + 1.
        // The number of bad pairs (l, r) where r=i is i - (current_max_x_for_3AP + 1) + 1
        // which is i - current_max_x_for_3AP.
        // If current_max_x_for_3AP is -1, then it's i - (-1) = i+1.
        // This means all substrings ending at i are bad, which is correct.
        bad_pairs += (i - current_max_x_for_3AP);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
