bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for tracks to be covered
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            break;
        }

        long long current_h = h[h_idx];
        long long min_reach = current_h - T;
        long long max_reach = current_h + T;

        // If the current head cannot reach the current target track p[p_idx],
        // it means this head is too far to the right.
        // We need to find the first p[p_idx] that this head can potentially cover.
        // If p[p_idx] is already greater than max_reach, this head cannot cover it.
        // This head can only cover tracks p_j such that p_j <= max_reach.
        // Also, it must be able to reach p_j from current_h.
        // The first track this head can cover must be >= min_reach.

        // If p[p_idx] is already beyond max_reach, this head cannot cover it.
        // This head is effectively useless for p[p_idx] and subsequent tracks.
        // However, this is not entirely true. A head can cover a range.
        // The strategy is to use each head to cover as many *uncovered* tracks as possible,
        // starting from the leftmost uncovered track.

        // If the current head is too far right to cover p[p_idx] even if it moves left by T,
        // i.e., p[p_idx] > current_h + T, then this head cannot cover p[p_idx].
        // This head must be used for tracks to its right.
        // This logic is flawed. The head can move left or right.
        // The key is that a head at h_idx can cover any track in [h[h_idx]-T, h[h_idx]+T].
        // We want to cover p[p_idx], p[p_idx+1], ...
        // If h[h_idx] is too far right, i.e., h[h_idx] - T > p[p_idx], then this head cannot cover p[p_idx].
        // In this case, we need another head for p[p_idx].
        // This means we should advance h_idx.
        // But the current loop structure advances h_idx anyway.

        // Let's re-evaluate:
        // We are trying to cover p[p_idx] using the current head h[h_idx].
        // If h[h_idx] is too far to the right to cover p[p_idx] (i.e., h[h_idx] - T > p[p_idx]),
        // then this head cannot cover p[p_idx]. We must use a previous head (which is not possible
        // in this greedy approach) or a future head.
        // The greedy approach should be: use the current head h[h_idx] to cover p[p_idx] if possible.
        // If h[h_idx] - T > p[p_idx], then h[h_idx] cannot cover p[p_idx].
        // This means p[p_idx] must be covered by a head h_k with k < h_idx.
        // But we are iterating h_idx from left to right.
        // This implies that if h[h_idx] - T > p[p_idx], then p[p_idx] cannot be covered by any h_k with k >= h_idx.
        // So, if h[h_idx] - T > p[p_idx], it's impossible.
        // This is the correct condition for failure for the current p[p_idx].

        if (current_h - T > p[p_idx]) {
            // This head is too far right to cover p[p_idx].
            // Since h is sorted, all subsequent heads h[h_idx+1], ... will also be too far right.
            // So p[p_idx] cannot be covered.
            return false;
        }

        // If current_h - T <= p[p_idx], this head *can* cover p[p_idx].
        // Now, we want to cover as many tracks as possible with this head.
        // The head can cover tracks in the range [p[p_idx], current_h + T].
        // (It must cover p[p_idx], so its leftmost reach is p[p_idx].
        // Its rightmost reach is current_h + T).
        // So, it covers all p_j such that p[p_idx] <= p_j <= current_h + T.

        // Advance p_idx as long as p[p_idx] is within the range [p[p_idx_start], current_h + T].
        // The actual range covered by this head is [current_h - T, current_h + T].
        // We need to cover p[p_idx]. So we move the head to cover p[p_idx].
        // The effective range covered by this head, starting from p[p_idx], is
        // [p[p_idx], current_h + T].
        // We advance p_idx past all tracks that fall into this range.
        while (p_idx < m && p[p_idx] <= current_h + T) {
            p_idx++;
        }
    }
    return p_idx == m; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p and h is 10^10.
                                    // So T can be up to 10^10. 2*10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

