#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees a solution exists.
    // A simple strategy that works for all n >= 2 is to reverse the permutation.
    // Let p = [p_1, p_2, ..., p_n].
    // The sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // Let p' = [p_n, p_{n-1}, ..., p_1].
    // The sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are exactly the same set of sums, just in reverse order.
    // For example, if p = [1, 4, 2, 3], sums are [5, 6, 5].
    // p' = [3, 2, 4, 1], sums are [3+2, 2+4, 4+1] = [5, 6, 5].
    // The sorted lists of sums (fingerprints) will be identical.
    //
    // The only case where p' might be equal to p is if p is a palindrome.
    // For example, if n=3, p=[1,2,1] is not a permutation.
    // If n=4, p=[1,2,2,1] is not a permutation.
    // A permutation p can only be a palindrome if p_i = p_{n-i+1} for all i.
    // For example, if n=2, p=[1,2], p'=[2,1]. Different.
    // If n=3, p=[1,2,3], p'=[3,2,1]. Different.
    // If n=4, p=[1,2,3,4], p'=[4,3,2,1]. Different.
    //
    // A permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2).
    // If p is a permutation, all elements are distinct.
    // If p were a palindrome, p_1 = p_n, p_2 = p_{n-1}, etc.
    // Since all elements must be distinct, this implies that if p_1 = p_n, then p_1 must be unique,
    // and p_n must be unique, which is true.
    // But if p_1 = p_n, and p_1 is distinct from p_2, ..., p_{n-1},
    // then p_n must also be distinct from p_2, ..., p_{n-1}.
    // This means p_1 and p_n are the same value, which contradicts the definition of a permutation
    // (all elements distinct) unless n=1.
    // For n >= 2, p_1 and p_n must be distinct values.
    // Therefore, p_1 != p_n.
    // If p_1 != p_n, then reversing p will always produce a different permutation p'.
    // So, reversing the given permutation is a valid solution.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

