void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long days_left = d;

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i + 1; // 1-indexed pile number
        long long haybales_in_pile = a[i];
        long long cost_per_haybale = pile_idx - 1;

        if (cost_per_haybale == 0) { // Should not happen for i >= 1
            continue;
        }

        if (days_left >= cost_per_haybale) {
            long long haybales_possible_to_move = days_left / cost_per_haybale;
            long long haybales_to_move = std::min(haybales_in_pile, haybales_possible_to_move);

            current_a1 += haybales_to_move;
            days_left -= haybales_to_move * cost_per_haybale;
        } else {
            // Not enough days to move even one haybale from this pile
            break; 
        }
    }

    std::cout << current_a1 << std::endl;
}

