            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and no element is n.
    // If so, it means n was not found in any row's max,
    // which implies n is the value of some p[k] itself.
    // In this case, the max_val_in_row for that k would be n-1.
    // We need to find such a p[k] and change it to n.
    bool n_found_in_p = false;
    for (int val : p) {
        if (val == n) {
            n_found_in_p = true;
            break;
        }
    }

    if (!n_found_in_p) {
        // This means n was not directly assigned to any p[i].
        // It must be that one of the p[i] values is actually n,
        // and for that p[i], all a[i][j] (j!=i) are p[j],
        // so max_val_in_row for that i would be n-1.
        // We need to find an element that is n-1 and change it to n.
        // Since the problem guarantees a solution, there must be exactly one such element.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

