    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int current_dist = 0;
        // The frog starts at cell 0.
        // It needs to reach cell n+1.
        // The string s has length n.
        // s[i] corresponds to cell i+1.
        // We are interested in 'R' cells.
        // The frog must be able to jump from 0 to the first 'R' cell,
        // then from one 'R' cell to the next 'R' cell,
        // and finally from the last 'R' cell to n+1.
        // If there are no 'R' cells, the frog must jump from 0 to n+1 directly.

        // Consider the positions of 'R' characters.
        // Let's add virtual 'R' at position -1 (representing cell 0)
        // and at position n (representing cell n+1).
        // The actual cells are 0, 1, ..., n, n+1.
        // String indices are 0, ..., n-1.
        // Cell i corresponds to s[i-1].
        // Cell 0 is a special 'R' cell.
        // Cell n+1 is the target, effectively an 'R' cell.

        // We need to find the maximum distance between consecutive 'R' cells
        // (including cell 0 and cell n+1 as 'R' cells).
        // The minimum d will be this maximum distance.

        // Let's track the last 'R' position.
        // Initially, the frog is at cell 0, which acts like an 'R' cell.
        int last_r_pos = 0; // Represents cell 0

        for (int i = 0; i < s.length(); ++i) {
            // s[i] corresponds to cell i+1
            if (s[i] == 'R') {
                // The distance from the last 'R' cell to the current 'R' cell
                // is (i+1) - last_r_pos.
                max_dist = std::max(max_dist, (i + 1) - last_r_pos);
                last_r_pos = i + 1; // Update last 'R' cell position
            }
        }
        // After iterating through the string, we need to consider the jump
        // from the last 'R' cell found to the target cell n+1.
        max_dist = std::max(max_dist, (int)(s.length() + 1) - last_r_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

