    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost_base = 1; // Represents 2^k - 1
        long long current_cost_sum = 1;  // Represents (2^k - 1) * (2^k) / 2

        while (x >= current_cost_sum) {
            x -= current_cost_sum;
            count++;

            // Calculate next cost
            // If current_cost_base = 2^k - 1, then next_cost_base = 2^(k+1) - 1
            // next_cost_base = 2 * current_cost_base + 1
            // next_cost_sum = next_cost_base * (next_cost_base + 1) / 2

            // Check for overflow before calculating next_cost_base
            // current_cost_base can be up to 2*10^9 for x=10^18.
            // 2 * current_cost_base + 1 can exceed 2*10^9, but still fit in long long.
            // The maximum value for current_cost_base is when current_cost_sum is around 10^18.
            // (2^k-1)(2^k)/2 approx (2^k)^2/2 = 2^(2k-1)
            // If 2^(2k-1) approx 10^18, then 2k-1 approx log2(10^18) approx 18 * log2(10) approx 18 * 3.32 approx 59.79
            // So 2k approx 60, k approx 30.
            // current_cost_base = 2^k - 1 approx 2^30 - 1 approx 10^9.
            // next_cost_base = 2^(k+1) - 1 approx 2^31 - 1 approx 2*10^9.
            // next_cost_sum = (2^(k+1)-1)(2^(k+1))/2 approx (2^31)^2/2 = 2^62/2 = 2^61.
            // 2^61 is about 2.3 * 10^18, which fits in long long.
            // So, direct calculation is fine.

            current_cost_base = 2 * current_cost_base + 1;
            current_cost_sum = current_cost_base * (current_cost_base + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
