int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by:
        // 1. The total number of students divided by 3.
        // 2. The number of coders (each team needs at least one).
        // 3. The number of mathematicians (each team needs at least one).
        // 4. The sum of coders and mathematicians (each team needs at least one of each).
        //    This is equivalent to min(c, m) because if we have k teams, we need k coders and k mathematicians.
        //    The remaining k students can be filled by x, or by additional c/m.
        //    The total number of students available for 'specialized' roles (coder or mathematician) is c+m.
        //    The total number of students available for 'any' role is c+m+x.

        // Let 'k' be the number of teams.
        // Each team needs 1 coder, 1 mathematician, and 1 other student.
        // The 'other' student can be an unspecialized student (from x),
        // an additional coder (from c), or an additional mathematician (from m).

        // The number of teams 'k' must satisfy:
        // k <= c (we need at least k coders)
        // k <= m (we need at least k mathematicians)
        // 3k <= c + m + x (total students used cannot exceed total available)

        // Combining the first two, k <= min(c, m).
        // So, k <= min(c, m, (c + m + x) / 3).
        // This is the upper bound for k.

        // Let's check if this upper bound is always achievable.
        // Suppose we want to form k teams.
        // We need k coders and k mathematicians.
        // This uses k students from c and k students from m.
        // Remaining students: c' = c - k, m' = m - k, x' = x.
        // We still need to fill k "third slots".
        // The total number of students available for these third slots is c' + m' + x'.
        // We need to ensure c' + m' + x' >= k.
        // Substituting c' and m': (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // (c + m + x) / 3 >= k

        // So, the maximum number of teams is indeed limited by the minimum of these three values.
        long long ans = std::min({c, m, (c + m + x) / 3});

        std::cout << ans << "\n";
    }
    return 0;
}

