    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top triangle (from apex to cut i) should be i * (total_area / n)
        // Total area = (1/2) * base * h = (1/2) * 1 * h = h/2
        // Area of top triangle = i * (h / (2n))
        // Let x_i be the height of the top triangle.
        // By similarity, base_i / 1 = x_i / h => base_i = x_i / h
        // Area of top triangle = (1/2) * base_i * x_i = (1/2) * (x_i / h) * x_i = x_i^2 / (2h)
        // So, x_i^2 / (2h) = i * (h / (2n))
        // x_i^2 = i * (h^2 / n)
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

