    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use to generate k distinct differences

    // The first k+1 elements will generate k distinct differences.
    // We alternate between left and right pointers to create large differences.
    // Example: k=2, right=3. Sequence: 1, 3, 2. Differences: |1-3|=2, |3-2|=1.
    // Example: k=3, right=4. Sequence: 1, 4, 2, 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1.
