            std::cout << left++;
        } else { // Odd index
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // The remaining n - (k+1) elements can be filled in increasing order
    // starting from the next available number (which is 'left' after the loop).
    // This ensures that the differences generated by these elements are 1,
    // which is already among the k distinct differences (since k >= 1).
    for (int i = k + 1; i < n; ++i) {
        std::cout << left++;
        std::cout << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

