    long long k_max = n / m;

    // Calculate the sum of last digits for the first 10 multiples of m
    // (m % 10), (2m % 10), ..., (10m % 10)
    long long sum_first_10_digits = 0;
    for (int i = 1; i <= 10; ++i) {
        sum_first_10_digits += (static_cast<long long>(i) * m) % 10;
    }

    // Number of full cycles of 10 multiples
    long long num_full_cycles = k_max / 10;
    long long total_sum = num_full_cycles * sum_first_10_digits;

    // Remaining terms after full cycles
    long long remaining_terms = k_max % 10;
    for (long long i = 1; i <= remaining_terms; ++i) {
        total_sum += (i * m) % 10;
    }

    std::cout << total_sum << std::endl;
}

