void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This means a[i] <= a[i+1] <= ... <= a[n-1].
    // If such an `i` exists, then a[i-1] > a[i].
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-decreasing.
    // If i=0, the whole array is non-decreasing.
    // If i>0, then a[i-1] > a[i].

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This means a[j] >= a[j+1] >= ... >= a[i-1].
    // If such a `j` exists, then a[j-1] < a[j].
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now, a[j...i-1] is non-increasing.
    // If j=0, then a[0...i-1] is non-increasing.
    // If j>0, then a[j-1] < a[j].

    // The prefix to remove is of length `j`.
    // The remaining suffix is a[j...n-1].
    // This suffix is good because:
    // a[j...i-1] is non-increasing.
    // a[i...n-1] is non-decreasing.
    // This structure allows forming a non-decreasing sequence `c` by
    // first taking elements from a[j...i-1] (from right to left),
    // then taking elements from a[i...n-1] (from left to right).
    // Or, more generally, by taking elements from both ends.
    // The key is that the "valley" is at index `i-1` and `i`.
    // All elements to the left of `i` are >= a[i-1] (if `i-1` exists).
    // All elements to the right of `i-1` are >= a[i] (if `i` exists).
    // The elements a[j...n-1] form a "mountain" shape (or a single peak/valley).
    // Specifically, it's a non-increasing sequence followed by a non-decreasing sequence.
    // This is exactly the condition for a good array.

    std::cout << j << std::endl;
}

