    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. min_idx=pos[1], max_idx=pos[1]. Length is 1.
        // For m > 1, we expand the segment to include m.
        // The segment for m must contain all numbers from 1 to m.
        // This means its left boundary must be min(pos[1], ..., pos[m])
        // and its right boundary must be max(pos[1], ..., pos[m]).
        // We maintain current_min_idx and current_max_idx for numbers 1 to m-1.
        // When considering m, we update these boundaries to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The minimum value in this subsegment is 1, and maximum is m.
        //    This is guaranteed by how current_min_idx and current_max_idx are updated.
        //    By construction, current_min_idx and current_max_idx define the smallest
        //    contiguous range of indices that contains all numbers from 1 to m.
        // 2. The length of this subsegment must be exactly m.
        //    Length = current_max_idx - current_min_idx + 1.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

