#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops: minimum value a[i] can be set to while maintaining a[0] < a[1] < ... < a[i]
    // This means a[i] must be at least i.
    // We can set a[i] to min(a[i], a[i-1]+1) for the increasing part.
    // But since we can decrease, we want to know if a[i] *can* be at least i.
    // So, we need a[i] >= i for the increasing part.
    // Let's find the first index `i` from the left where `a[i] < i`.
    // All elements `a[0]...a[i-1]` can potentially form the start of an increasing sequence.
    int left_limit = n;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_limit = i;
            break;
        }
    }

    // Calculate suffix_min_ops: minimum value a[i] can be set to while maintaining a[i] > a[i+1] > ... > a[n-1]
    // This means a[i] must be at least (n-1-i).
    // Let's find the first index `i` from the right where `a[i] < (n-1-i)`.
    // All elements `a[i+1]...a[n-1]` can potentially form the end of a decreasing sequence.
    int right_limit = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_limit = i;
            break;
        }
    }

    // If left_limit is n, it means all a[i] >= i for i from 0 to n-1.
    // This implies we can always form an increasing sequence 0, 1, ..., n-1.
    // If right_limit is -1, it means all a[i] >= (n-1-i) for i from 0 to n-1.
    // This implies we can always form a decreasing sequence n-1, n-2, ..., 0.

    // A sharpened array requires a peak k.
    // The increasing part is a_0 < a_1 < ... < a_k.
    // The decreasing part is a_k > a_{k+1} > ... > a_{n-1}.
    // For a_i in the increasing part (i <= k), we need a_i >= i.
    // For a_j in the decreasing part (j >= k), we need a_j >= (n-1-j).
    // The peak element a_k must satisfy both conditions: a_k >= k AND a_k >= (n-1-k).
    // The crucial part is that the peak element `a_k` must be reachable.
    // If we can find *any* `k` such that `a_k` can be the peak, then it's possible.
    // This means we need to find a `k` such that:
    // 1. `a_i >= i` for all `i <= k` (to form the increasing part up to `k`)
    // 2. `a_j >= (n-1-j)` for all `j >= k` (to form the decreasing part from `k` onwards)

    // The `left_limit` is the first index `i` such that `a[i] < i`.
    // This means for any `k >= left_limit`, the condition `a_i >= i` for all `i <= k` cannot be satisfied.
    // So, any potential peak `k` must be strictly less than `left_limit`.
    // `k < left_limit`.

    // The `right_limit` is the first index `i` from the right such that `a[i] < (n-1-i)`.
    // This means for any `k <= right_limit`, the condition `a_j >= (n-1-j)` for all `j >= k` cannot be satisfied.
    // So, any potential peak `k` must be strictly greater than `right_limit`.
    // `k > right_limit`.

    // Combining these, we need to find a `k` such that `right_limit < k < left_limit`.
    // If such a `k` exists, then it's possible. Otherwise, it's not.
    // This is equivalent to checking if `right_limit + 1 < left_limit`.

    if (right_limit + 1 < left_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

