#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, ensure the median element itself is s.
    // This is always necessary and contributes abs(a[median_idx] - s) operations.
    operations += std::abs(a[median_idx] - s);

    // If a[median_idx] is already s, or we've adjusted it to s,
    // we need to ensure elements to its left are <= s and elements to its right are >= s.

    // Iterate through elements to the left of the median.
    // If any a[i] < s, it's fine.
    // If any a[i] > s, it must be decreased to s.
    // Since a is sorted, if a[median_idx] is adjusted to s,
    // any a[i] (i < median_idx) that is currently > s must be decreased to s.
    // However, if a[median_idx] was originally > s and we decreased it to s,
    // then any a[i] (i < median_idx) that was > a[median_idx] (original)
    // would also be > s.
    // The condition is that after operations, all elements at indices < median_idx must be <= s.
    // Since we want to minimize operations, we only change elements that violate this.
    // If a[i] > s for i < median_idx, we must decrease it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Iterate through elements to the right of the median.
    // If any a[i] > s, it's fine.
    // If any a[i] < s, it must be increased to s.
    // Similar logic: if a[median_idx] was originally < s and we increased it to s,
    // then any a[i] (i > median_idx) that was < a[median_idx] (original)
    // would also be < s.
    // The condition is that after operations, all elements at indices > median_idx must be >= s.
    // If a[i] < s for i > median_idx, we must increase it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

