struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order of values
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order of values
    std::sort(b.begin(), b.end());

    // Create the result array A'
    // The optimal strategy is to pair the i-th smallest A value with the i-th largest B value.
    // Since we sorted A ascending and B ascending,
    // a_elements[i].value is the (i+1)-th smallest A value.
    // b[m-1-i] is the (i+1)-th largest B value.
    // So, a_elements[i].value should be paired with b[m-1-i].

    std::vector<long long> a_prime(m);
    for (int i = 0; i < m; ++i) {
        // a_elements[i].value is the i-th smallest A value (0-indexed)
        // b[m - 1 - i] is the i-th largest B value (0-indexed)
        // We want to assign a_elements[i].value to the original position of b[m-1-i]
        // This is incorrect. We need to assign a_elements[i].value to the original position of a_elements[m-1-i].
        // The problem asks to rearrange A. So, a_prime[original_index_of_A_element] = new_value.
        // The pairing is (A_sorted[i], B_sorted[m-1-i]).
        // The value A_sorted[i] should be placed at the original index of A_sorted[m-1-i].
        // This means a_prime[a_elements[m-1-i].original_index] = a_elements[i].value.
        a_prime[a_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

