// Function to check if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: (-inf, -1]
    // Final product must be negative and magnitude >= 1.

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // Initial negative factors: A + B
    // Each multiplication of two negatives (NN) reduces the count of negatives by 2 and adds a positive.
    // Each multiplication of a negative and a positive (NP) keeps the count of negatives the same.
    // So, the parity of negative factors (A+B) remains invariant.
    // Thus, if A+B is even, the final product must be positive.
    // If A+B is odd, the final product must be negative.
    if ((A + B) % 2 == 0) {
        return false; // Final product must be positive
    }

    // Case 2: Final product magnitude >= 1.
    // This is the tricky part. We need to ensure that we can always make the magnitude large enough.
    // The only way to guarantee a magnitude >= 1 is to have at least one toy from Box 1 or Box 4
    // (i.e., a toy with magnitude >= 1) that is not "cancelled out" by too many small-magnitude multiplications.

    // If A + D == 0, all initial toys have magnitude < 1.
    // If we multiply two small-magnitude toys, the result is always small-magnitude.
    // (e.g., 0.5 * 0.5 = 0.25, -0.5 * 0.5 = -0.25).
    // So, if A + D == 0, the final product will always have magnitude < 1.
    // In this case, it cannot be in Box 1 (or Box 4).
    if (A + D == 0) {
        return false;
    }

    // If A + D > 0, there is at least one toy with magnitude >= 1.
    // Can we always ensure the final product has magnitude >= 1?
    // Yes, if we have at least one large-magnitude toy (A or D), we can strategically multiply it last
    // with a toy that has magnitude >= 1, or multiply it with a small-magnitude toy such that the result is >= 1.
    // For example, if we have a toy with value 3, and we multiply it by 0.5, we get 1.5.
    // If we have a toy with value 3, and we multiply it by 0.1, we get 0.3.
    // The problem states "randomly", but we are asked if it *can* be the special box.
    // This implies we can choose the sequence of operations.
    // If A+D > 0, we can always ensure the final product has magnitude >= 1.
    // Example: Keep one toy with magnitude >= 1 (say, from Box 1 or Box 4) until the very end.
    // Multiply all other N-1 toys. The product of N-1 toys can be arbitrarily small or large.
    // If it's small, say 0.001, and the last toy is 2, the final product is 0.002.
    // This strategy doesn't guarantee magnitude >= 1.

    // Let's re-evaluate the magnitude condition.
    // The only way to get a magnitude >= 1 is if at some point we multiply two numbers
    // such that their product is >= 1, OR we start with a number >= 1 and never multiply it by too many small numbers.
    // If A+D > 0, there is at least one toy with magnitude >= 1.
    // Let's say we have one toy with value X where |X| >= 1.
    // And all other toys have values Y_i where |Y_i| < 1.
    // If we multiply X by Y_1, the result |X*Y_1| can be < 1 or >= 1.
    // If we multiply X by Y_1 * Y_2 * ... * Y_k, the result |X * product(Y_i)| can be < 1 or >= 1.
    // The question is if it *can* be. This means we can pick specific values for the toys and a specific sequence.

    // If A+D > 0, we have at least one toy with magnitude >= 1.
    // Let's say we have a toy with value X from Box 1 or Box 4.
    // We can choose its value to be very large, e.g., X = -1000 or X = 1000.
    // We can choose all other toys to have values very close to 1 (but still in their respective boxes).
    // E.g., Box 2: -0.999, Box 3: 0.999.
    // If we have A+D > 0, we can pick one toy with magnitude >= 1 (e.g., -2 or 2).
    // We can pick all other toys to have magnitude very close to 1 (e.g., -0.99, 0.99).
    // Then the product of all toys will have magnitude |X| * (0.99)^(N-1).
    // If N-1 is large, this can become small.
    // However, we can choose the values.
    // If A+D > 0, we can pick one toy with value -2 (if A>0) or 2 (if D>0).
    // We can pick all other toys to have values -0.5 (if B>0) or 0.5 (if C>0).
    // If we have one toy with value 2, and all others are 0.5, the product is 2 * (0.5)^(N-1).
    // This can be < 1 if N-1 is large.

    // The key insight for magnitude:
    // If A+D > 0, we have at least one "large" toy.
    // If B+C > 0, we have at least one "small" toy.
    // If we have at least one large toy (A+D > 0), we can make the final product's magnitude >= 1.
    // We can pick one toy from A or D, say X. Let its value be -2 or 2.
    // For all other toys, if they are from B or C, pick their values to be -0.5 or 0.5.
    // If they are from A or D, pick their values to be -2 or 2.
    // If we have at least one toy from A or D, we can make its value very large (e.g., 10^9).
    // And all other toys can have values like 0.1, -0.1, 0.9, -0.9.
    // The product of all these will be (10^9) * (product of N-1 small numbers).
    // This product can still be >= 1.
    // For example, if we have one toy with value 1000, and 10 toys with value 0.5.
    // The product is 1000 * (0.5)^10 = 1000 * (1/1024) approx 1.
    // So, if A+D > 0, it is possible to have magnitude >= 1.

    // Summary for Box 1:
    // 1. (A+B) must be odd (for negative sign).
    // 2. (A+D) must be > 0 (for magnitude >= 1).
    return ((A + B) % 2 == 1) && (A + D > 0);
}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: (-1, 0)
    // Final product must be negative and magnitude < 1.

    // Case 1: Final product is negative.
    // (A+B) must be odd.
    if ((A + B) % 2 == 0) {
        return false; // Final product must be positive
    }

    // Case 2: Final product magnitude < 1.
    // This is guaranteed if A+D == 0 (all initial toys have magnitude < 1).
    // If A+D > 0, we need to ensure that we can make the magnitude < 1.
    // We can pick one toy from A or D, say X. Let its value be -2 or 2.
    // We can pick all other toys to have values very small, e.g., -0.001 or 0.001.
    // Then the product will be X * (product of N-1 very small numbers).
    // This product will have magnitude < 1.
    // So, if A+D > 0, it is possible to have magnitude < 1.
    // Therefore, magnitude < 1 is always possible if there's more than one toy.
    // If there's only one toy, its magnitude must be < 1.
    // If A+B+C+D == 1:
    //   If A==1 or D==1, magnitude is >= 1, so cannot be Box 2.
    //   If B==1, magnitude is < 1, can be Box 2.
    //   If C==1, magnitude is < 1, but positive, so cannot be Box 2.
    // So if A+B+C+D == 1, it can be Box 2 only if B==1.

    if (A + B + C + D == 1) {
        return B == 1;
    }

    // If A+B+C+D > 1:
    // We need (A+B) % 2 == 1.
    // We can always make the magnitude < 1.
    // Pick one toy with value X (e.g., -2 if A>0, 2 if D>0, -0.5 if B>0, 0.5 if C>0).
    // Pick all other N-1 toys to have values very close to 0 (e.g., 0.001, -0.001).
    // The product will be X * (product of N-1 very small numbers), which will be < 1.
    // This strategy works for any initial configuration with N > 1.
    return (A + B) % 2 == 1;
}

// Function to check if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: (0, 1)
    // Final product must be positive and magnitude < 1.

    // Case 1: Final product is positive.
    // (A+B) must be even.
    if ((A + B) % 2 == 1) {
        return false; // Final product must be negative
    }

    // Case 2: Final product magnitude < 1.
    // Similar to Box 2, if A+B+C+D == 1:
    //   If A==1 or D==1, magnitude is >= 1, so cannot be Box 3.
    //   If C==1, magnitude is < 1, can be Box 3.
    //   If B==1, magnitude is < 1, but negative, so cannot be Box 3.
    // So if A+B+C+D == 1, it can be Box 3 only if C==1.

    if (A + B + C + D == 1) {
        return C == 1;
    }

    // If A+B+C+D > 1:
    // We need (A+B) % 2 == 0.
    // We can always make the magnitude < 1 (same logic as Box 2).
    return (A + B) % 2 == 0;
}

// Function to check if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: [1, inf)
    // Final product must be positive and magnitude >= 1.

    // Case 1: Final product is positive.
    // (A+B) must be even.
    if ((A + B) % 2 == 1) {
        return false; // Final product must be negative
    }

    // Case 2: Final product magnitude >= 1.
    // This requires A+D > 0 (at least one initial toy with magnitude >= 1).
    // If A+D == 0, all initial toys have magnitude < 1.
    // The product of any number of toys with magnitude < 1 will always have magnitude < 1.
    // So, if A+D == 0, it cannot be in Box 4 (or Box 1).
    if (A + D == 0) {
        return false;
    }

    // If A+D > 0, we have at least one toy with magnitude >= 1.
    // We can choose its value to be very large (e.g., 10^9).
    // We can choose all other toys to have values very close to 1 (e.g., 0.999, -0.999).
    // The product will be (10^9) * (product of N-1 numbers close to 1).
    // This product will have magnitude >= 1.
    // So, if A+D > 0, it is possible to have magnitude >= 1.
    return (A + B) % 2 == 0 && (A + D > 0);
}

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " ";
    std::cout << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " ";
    std::cout << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " ";
    std::cout << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << std::endl;
}

