#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        current_xor ^= a[i];
    }

    // We need S' = 2 * X'
    // Let S_0 be current_sum and X_0 be current_xor.
    // We want S_0 + b_1 + ... + b_k = 2 * (X_0 ^ b_1 ^ ... ^ b_k)

    // Strategy: Append at most 3 elements.
    // The problem guarantees a solution always exists.
    // A simple strategy is to append two elements: X_0 and S_0 + X_0.
    // Let's try to append two elements: b1, b2.
    // New sum S' = S_0 + b1 + b2
    // New XOR X' = X_0 ^ b1 ^ b2
    // We want S' = 2 * X'

    // Consider appending b1 = X_0.
    // Then X' = X_0 ^ X_0 ^ b2 = b2.
    // And S' = S_0 + X_0 + b2.
    // We need S_0 + X_0 + b2 = 2 * b2.
    // S_0 + X_0 = b2.
    // So, if we append X_0 and S_0 + X_0, the condition should hold.
    // Let b1 = X_0 and b2 = S_0 + X_0.
    // New sum S' = S_0 + X_0 + (S_0 + X_0) = 2 * (S_0 + X_0).
    // New XOR X' = X_0 ^ X_0 ^ (S_0 + X_0) = S_0 + X_0.
    // So, S' = 2 * X' is satisfied.
    // The elements to append are X_0 and S_0 + X_0.
    // These are non-negative since a_i >= 0.
    // The maximum value for S_0 is 10^5 * 10^9 = 10^14.
    // The maximum value for X_0 is around 2^30 (since a_i <= 10^9).
    // So S_0 + X_0 can be up to 10^14 + 2^30, which fits in long long.
    // This strategy always works and uses 2 elements.

    // Output 2 elements:
    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << current_sum + current_xor << std::endl;
}

