// Function to check if a subarray is a permutation
// This version is optimized for checking prefix/suffix properties
// It returns the maximum value in the subarray if it's a permutation,
// otherwise 0.
int check_permutation_property(const std::vector<int>& arr, int len) {
    if (len == 0) return 0; // An empty sequence cannot be a permutation of length > 0
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] < 1 || arr[i] > len || seen[arr[i]]) {
            return 0; // Not a permutation: out of range or duplicate
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    // After checking all elements, if max_val is equal to len,
    // and all numbers from 1 to len were seen exactly once, it's a permutation.
    // The `seen` array and `max_val` check together ensure this.
    return max_val == len ? len : 0;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n + 1, 0);
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    bool current_prefix_valid = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val < 1 || val > (i + 1) || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        seen_prefix[val] = true;
        prefix_max[i + 1] = std::max(prefix_max[i], val);
        if (current_prefix_valid && prefix_max[i + 1] == (i + 1)) {
            prefix_is_perm[i + 1] = true;
        }
    }

    std::vector<int> suffix_max(n + 1, 0);
    std::vector<bool> suffix_is_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    bool current_suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        int val = a[i];
        if (val < 1 || val > len || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        seen_suffix[val] = true;
        suffix_max[len] = std::max(suffix_max[len - 1], val); // suffix_max[k] stores max for last k elements
        if (current_suffix_valid && suffix_max[len] == len) {
            suffix_is_perm[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

