int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it will form 'ab' pairs with all 'b's
            // currently to its right.
            // Each such 'ab' replacement (ab -> bba) effectively moves the 'a'
            // past one 'b' and adds one 'b'.
            // The number of steps for this 'a' is equal to the current b_count.
            total_steps = (total_steps + b_count) % mod;

            // After this 'a' has been processed (conceptually moved past all 'b's),
            // it will have generated an additional 'b' for each 'b' it passed.
            // So, the number of 'b's available for 'a's further to the left
            // effectively doubles.
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

