#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left.
    // Then 'n - i' items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // prefix_sum[n] is sum of all weights
        // prefix_sum[i] is sum of first 'i' weights
        // So, prefix_sum[n] - prefix_sum[i] is sum of weights from index 'i' to 'n-1'
        // These are the items taken from the right.
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for difference in counts
        if (i > j) { // More items from left
            if (i - j > 1) { // If difference is 2 or more, there are (i-j-1) extra left items
                current_energy += (long long)(i - j - 1) * Ql;
            }
        } else if (j > i) { // More items from right
            if (j - i > 1) { // If difference is 2 or more, there are (j-i-1) extra right items
                current_energy += (long long)(j - i - 1) * Qr;
            }
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

