        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    // Step 3: Compare s_prime with the original s
    if (s_prime == s) {
        std::cout << w << std::endl;
