// Function to convert a number to its parity pattern string
// For example, 241 -> "001" (2 is even, 4 is even, 1 is odd)
// The pattern is always 18 characters long, padded with '0's on the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's to the left to make it 18 characters long
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should always compare patterns of the same length.
    // Max length of number is 18 digits (10^18 - 1). Max length of pattern is 18.
    // So, we normalize all patterns to length 18.
    while (pattern.length() < 18) {
        pattern += '0'; // Append '0' to the right, which corresponds to prepending '0' to the left of the number
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string
    // The key is the 18-character parity pattern string, value is its count
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Normalize the query pattern 's' to 18 characters
            // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // and "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we should pad the query pattern 's' with '0's to the left (which means appending '0's to the right of our reversed pattern string).
            while (s.length() < 18) {
                s = '0' + s; // Prepend '0' to the pattern string
            }
            // The get_parity_pattern function generates patterns in reverse order of digits.
            // So, for comparison, we need to reverse the query pattern 's' as well.
            std::reverse(s.begin(), s.end());

            // Retrieve count from map. If pattern not found, count is 0.
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

