// Function to find prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> prime_factorize(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let q = q1^a1 * q2^a2 * ... * qk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least a_i factors of q_i for all i.
        // To make x not divisible by q, we must remove enough factors of some q_i from p
        // such that x has fewer than a_i factors of q_i.
        // To maximize x, we should remove as few factors as possible.
        // This means for each prime factor q_i of q, we try to divide p by q_i until
        // the resulting number p' is no longer divisible by q_i^(a_i).
        // The largest such p' will be our answer.

        std::vector<std::pair<long long, int>> q_factors = prime_factorize(q);
        long long max_x = 1;

        for (const auto& factor_pair : q_factors) {
            long long prime_factor = factor_pair.first;
            // int q_exponent = factor_pair.second; // Not directly needed, we just need to know it's a prime factor of q

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= prime_factor;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
