void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 0 means cannot move left (x-1). So, target X must be >= current x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // f3 = 0 means cannot move right (x+1). So, target X must be <= current x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // f4 = 0 means cannot move down (y-1). So, target Y must be >= current y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
        // f2 = 0 means cannot move up (y+1). So, target Y must be <= current y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // The problem guarantees that if a point exists, one exists within [-10^5, 10^5].
        // We can pick any valid point. For example, (min_x, min_y).
        // We need to clamp min_x and min_y to the guaranteed range if they fall outside.
        // However, the problem statement says "Both X and Y should not exceed 10^5 by absolute value;
        // it is guaranteed that if there exists at least one point reachable by all robots,
        // then at least one of such points has both coordinates not exceeding 10^5 by absolute value."
        // This implies that if min_x, min_y are valid, they will be within the range or we can pick one that is.
        // Since we are looking for *any* such point, and the bounds are derived from robot positions
        // which are within [-10^5, 10^5], min_x and min_y will naturally be within this range.
        // For example, if all robots are at (0,0) and can't move, min_x=0, max_x=0, min_y=0, max_y=0.
        // If a robot is at (10^5, 10^5) and can't move left, min_x becomes 10^5.
        // If a robot is at (-10^5, -10^5) and can't move right, max_x becomes -10^5.
        // The initial large/small values for min/max are just to handle the "infinity" case.
        // The actual coordinates will be bounded by the robot coordinates.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

