}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int x = 0; x <= 9; ++x) {
        std::vector<int> colors(n);
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_x = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                colors[i] = 1;
                s1_digits.push_back(d[i]);
            } else if (d[i] > x) {
                colors[i] = 2;
                s2_digits.push_back(d[i]);
            } else { // d[i] == x
                // Try to assign to color 2 first, if possible
                // This means d[i] is the first 'x' or previous 'x's were also color 2
                // Or, if we haven't seen any digit > x yet, we can assign to color 1
                // The strategy is: all d_i < x are color 1.
                // All d_i > x are color 2.
                // For d_i == x:
                // If we haven't seen any d_j > x yet, we can assign d_i to color 1.
                // If we have seen d_j > x, then d_i must be color 2.
                // This is equivalent to finding the first occurrence of 'x' that we want to color 2.
                // All 'x's before that are color 1, all 'x's after that are color 2.
                // This is handled by the loop below.
            }
        }

        // Check if s1_digits and s2_digits are non-decreasing
        for (size_t i = 1; i < s1_digits.size(); ++i) {
            if (s1_digits[i] < s1_digits[i-1]) {
                possible_x = false;
                break;
            }
        }
        if (!possible_x) continue;

        for (size_t i = 1; i < s2_digits.size(); ++i) {
            if (s2_digits[i] < s2_digits[i-1]) {
                possible_x = false;
                break;
            }
        }
        if (!possible_x) continue;

        // Now, handle digits equal to x
        // Find the split point for digits equal to x
        // All d_i == x before split_idx are color 1
        // All d_i == x at or after split_idx are color 2
        // The split_idx is the first index where d[i] == x that we assign to color 2.
        // All d[i] == x before this index must be color 1.
        // All d[i] == x after this index must be color 2.
        // This means we need to find the first 'x' that is greater than or equal to the last digit of S1.
        // And all 'x's after that must be greater than or equal to the first digit of S2.
        // This is equivalent to finding the first 'x' that we want to color 2.
        // All 'x's before it are color 1, all 'x's after it are color 2.

        int last_s1_val = -1;
        if (!s1_digits.empty()) {
            last_s1_val = s1_digits.back();
        }

        int first_s2_val = 10;
        if (!s2_digits.empty()) {
            first_s2_val = s2_digits.front();
        }

        // If last_s1_val > first_s2_val, then this x is not possible.
        // This check is implicitly handled by the full construction below.

        // Find the first index `k` such that d[k] == x and we want to color it 2.
        // All d[i] == x for i < k will be color 1.
        // All d[i] == x for i >= k will be color 2.
        // If no such k exists, all x's are color 1 (k=n) or all x's are color 2 (k=0).

        int split_k = n; // Default: all x's are color 1
        for (int i = 0; i < n; ++i) {
            if (d[i] == x) {
                if (d[i] >= last_s1_val) { // This 'x' can potentially be the first 'x' in S2
                    split_k = i;
                    break;
                } else { // This 'x' must be in S1
                    colors[i] = 1;
                }
            }
        }

        // Now, fill in the remaining 'x's based on split_k
        for (int i = 0; i < n; ++i) {
            if (d[i] == x) {
                if (i < split_k) {
                    colors[i] = 1;
                } else {
                    colors[i] = 2;
                }
            }
        }

        // Reconstruct S1 and S2 to check validity
        std::vector<int> final_s1_digits;
        std::vector<int> final_s2_digits;
        for (int i = 0; i < n; ++i) {
            if (colors[i] == 1) {
                final_s1_digits.push_back(d[i]);
            } else {
                final_s2_digits.push_back(d[i]);
            }
        }

        bool current_x_valid = true;
        for (size_t i = 1; i < final_s1_digits.size(); ++i) {
            if (final_s1_digits[i] < final_s1_digits[i-1]) {
                current_x_valid = false;
                break;
            }
        }
        if (!current_x_valid) continue;

        for (size_t i = 1; i < final_s2_digits.size(); ++i) {
            if (final_s2_digits[i] < final_s2_digits[i-1]) {
                current_x_valid = false;
                break;
            }
        }
        if (!current_x_valid) continue;

        if (!final_s1_digits.empty() && !final_s2_digits.empty()) {
            if (final_s1_digits.back() > final_s2_digits.front()) {
                current_x_valid = false;
            }
        }

        if (current_x_valid) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) return 0;
    long long MOD = 1000000007;
    long long term1 = n % MOD;
    long long term2 = (n + 1) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7
    long long sum = (term1 * term2) % MOD;
    sum = (sum * inv2) % MOD;
    return sum;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Calculate sum_r = sum_{r=1}^{b-1} r
    long long sum_r = sum_arithmetic_series(b - 1);

    // Calculate sum_k = sum_{k=1}^{a} k
    long long sum_k = sum_arithmetic_series(a);

    // Calculate sum_kb = sum_{k=1}^{a} (kb)
    // This is b * sum_k
    long long sum_kb = (b % MOD * sum_k) % MOD;

    // The total sum is (sum_kb * sum_r + sum_r * a) % MOD
    // sum_kb * sum_r corresponds to sum_{k=1}^{a} sum_{r=1}^{b-1} rkb
    // sum_r * a corresponds to sum_{k=1}^{a} sum_{r=1}^{b-1} r
    // which is a * (sum_{r=1}^{b-1} r)

    long long term1 = (sum_kb * sum_r) % MOD;
    long long term2 = (sum_r * (a % MOD)) % MOD;

    long long total_sum = (term1 + term2) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26); // Adjacency list for each character
    std::vector<bool> present_in_s(26, false); // Track characters present in s

    for (char c : s) {
        present_in_s[c - 'a'] = true;
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1 - 'a'].insert(c2);
        adj[c2 - 'a'].insert(c1);
    }

    // Check for invalid configurations (more than 2 neighbors)
    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string result_layout = "";
    std::vector<bool> visited(26, false);

    // Find starting points for paths (characters with 1 neighbor)
    // Or any character present in 's' if all have 2 neighbors (forms a cycle)
    // Or any character if 's' is empty or single char (no constraints)

    // First, try to build paths starting from characters with 1 neighbor
    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() == 1 && !visited[i]) {
            char current_char = (char)('a' + i);

            // Traverse the path
            while (true) {
                result_layout += current_char;
                visited[current_char - 'a'] = true;

                char next_char = '\0';
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }

                if (next_char == '\0') { // End of path
                    break;
                }
                current_char = next_char;
            }
        }
    }

    // If there are still unvisited characters that were part of 's'
    // This implies a cycle, which is not allowed for a single row.
    // Or, if s is empty or single char, no constraints, all chars have 0 neighbors.
    // The only case where a character in 's' might not be visited is if it's part of a cycle.
    // However, if all characters in 's' have 2 neighbors, they form a single path or cycle.
    // If it's a cycle, it would have been fully traversed starting from any point.
    // If it's a path, it would have been fully traversed starting from an endpoint.
    // So, if any character in 's' is unvisited, it means there's a problem.
    // The only exception is if 's' is empty or has one character, in which case no constraints are imposed.
    // But the problem guarantees |s| >= 1.
    // If s has one character, say 'a', then present_in_s['a'-'a'] is true, adj['a'-'a'] is empty.
    // It will be handled by the next loop.

    // Check if all characters from 's' have been included in the layout
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
            // This means a character from 's' was not part of any path starting from a 1-degree node.
            // This implies it's part of a component where all nodes have degree 2 (a cycle).
            // A cycle cannot be represented in a single row.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters (those not in 's' or not part of any path)
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            result_layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << result_layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
