    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_y[i] stores the total y accumulated when starting at x=i and performing
    // the "decrease x" step (x = i - a[i]), assuming it terminates.
    // dp_next_x[i] stores the next x value after performing the "decrease x" step
    // (x = i - a[i]), assuming it terminates.
    // These are for the second part of the cycle (x_curr - a[x_curr]).
    // We need to compute these for x from n down to 1.
    // dp_y[i] = a[i] + dp_y[i - a[i]] if i - a[i] is valid and terminates
    // dp_next_x[i] = dp_next_x[i - a[i]] if i - a[i] is valid and terminates
    // If i - a[i] is <= 0, then dp_y[i] = a[i], dp_next_x[i] = i - a[i]
    // If i - a[i] is > n, then dp_y[i] = a[i], dp_next_x[i] = i - a[i]
    // If it loops, then -1.

    std::vector<long long> dp_y(n + 1);
    std::vector<int> dp_next_x(n + 1); // Stores the x value after the "decrease" step
                                       // or 0 if it terminates (x <= 0 or x > n)
                                       // or -1 if it loops.

    // Initialize dp_y and dp_next_x for base cases (terminating states)
    for (int i = 1; i <= n; ++i) {
        long long next_x_val = i - a[i];
        if (next_x_val <= 0 || next_x_val > n) {
            dp_y[i] = a[i];
            dp_next_x[i] = 0; // Sentinel for termination
        } else {
            // Will be computed later
            dp_y[i] = -1; // Mark as uncomputed or potentially looping
            dp_next_x[i] = -1;
        }
    }

    // Use a stack for DFS-like computation to detect cycles and compute values
    std::vector<int> path_stack;
    std::vector<bool> on_stack(n + 1, false); // To detect cycles

    for (int i = 1; i <= n; ++i) {
        if (dp_next_x[i] != -1) { // Already computed or base case
            continue;
        }

        path_stack.clear();
        int current_x = i;

        while (current_x >= 1 && current_x <= n && dp_next_x[current_x] == -1 && !on_stack[current_x]) {
