    // We want to find the tightest upper bound for each a_0[j].
    // Let's denote current_sum_d[j] as the sum of d's applied to index j up to the current operation.
    // For a type 2 operation (l, r, M), we have max_{j=l..r} (a_0[j] + current_sum_d[j]) = M.
    // This implies a_0[j] + current_sum_d[j] <= M for all j in [l, r].
    // So, a_0[j] <= M - current_sum_d[j].
    // We need to find the minimum of these (M - current_sum_d[j]) values for each j.

    std::vector<long long> current_sum_d(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_sum_d[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_val_at_idx[j] = std::min(min_val_at_idx[j], ops[i].val - current_sum_d[j]);
            }
        }
    }

    // Initialize initial_a with the tightest upper bounds found.
    // If no type 2 operation constrained an element, it can be anything, e.g., 0.
    // The problem states |a_i| <= 10^9.
    // If min_val_at_idx[j] is still its initial large value, it means no type 2 op constrained it.
    // We can set initial_a[j] to 0 in such cases, or any value within [-10^9, 10^9].
    // For simplicity, let's use min_val_at_idx[j] as the initial_a[j] if it was constrained.
    // If not constrained, we can set it to 0.
    for (int i = 0; i < n; ++i) {
        if (min_val_at_idx[i] == 2000000000000000000LL) {
            initial_a[i] = 0; // Default for unconstrained elements
        } else {
            initial_a[i] = min_val_at_idx[i];
        }
    }

    // Second pass: Verify if this initial_a satisfies all type 2 operations.
    // If max_{j=l..r} (initial_a[j] + current_sum_d[j]) != M, then no solution.
    // Also, check if initial_a[j] + current_sum_d[j] <= M for all j in [l, r].
    // The way initial_a was constructed guarantees initial_a[j] + current_sum_d[j] <= M for all j in [l, r]
    // for the specific current_sum_d[j] at the time of that type 2 operation.
    // We need to check if the maximum is *exactly* M.

    std::fill(current_sum_d.begin(), current_sum_d.end(), 0);
    std::vector<long long> current_a(n);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_sum_d[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = -3000000000000000000LL; // Sufficiently small
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] = initial_a[j] + current_sum_d[j];
                max_val_in_range = std::max(max_val_in_range, current_a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraints for initial_a
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            // This case should ideally not happen if the problem guarantees a solution
            // within these bounds, and our construction is correct.
            // However, if min_val_at_idx[i] was very large/small, it might exceed.
            // The problem states "all numbers in his array didn't exceed 10^9 in their absolute value".
            // This implies that if a solution exists, there is one within these bounds.
            // Our construction finds the largest possible initial_a[i] that satisfies all <= M constraints.
            // If this largest possible value exceeds 10^9, it means no solution exists within bounds.
            // However, the problem statement implies that if a solution exists, it's within bounds.
            // So, if we found a solution, it should be within bounds.
            // Let's just output NO if it's out of bounds.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children_data(n);
    for (int i = 0; i < n; ++i) {
        children_data[i].id = i + 1;
        std::cin >> children_data[i].v >> children_data[i].d >> children_data[i].p;
        children_data[i].in_line = true;
    }

    std::vector<int> treated_children_ids;

    // Use a list to represent the dynamic queue of children
    // Store indices into children_data vector
    std::list<int> current_line;
    for (int i = 0; i < n; ++i) {
        current_line.push_back(i);
    }

    auto it = current_line.begin();
    while (it != current_line.end()) {
        int current_child_idx = *it;

        treated_children_ids.push_back(children_data[current_child_idx].id);
        children_data[current_child_idx].in_line = false; // Mark as treated

        long long office_cry_volume = children_data[current_child_idx].v;
        long long hall_cry_volume_sum = 0; // Accumulates d_j from children leaving due to chain reaction

        // Remove current child from line and advance iterator
        it = current_line.erase(it);

        // Apply confidence reduction from office cry and accumulated hall cries
        auto line_it = it;
        int count_after_office_cry = 0;
        while (line_it != current_line.end()) {
            int child_in_line_idx = *line_it;

            // Apply office cry reduction
            if (office_cry_volume > 0) {
                children_data[child_in_line_idx].p -= office_cry_volume;
                office_cry_volume--;
            }

            // Apply accumulated hall cry reduction
            children_data[child_in_line_idx].p -= hall_cry_volume_sum;

            // Check if confidence drops below zero
            if (children_data[child_in_line_idx].p < 0) {
                hall_cry_volume_sum += children_data[child_in_line_idx].d;
                children_data[child_in_line_idx].in_line = false; // Mark as left
                line_it = current_line.erase(line_it); // Remove from line
            } else {
                ++line_it;
            }
        }
    }

    std::cout << treated_children_ids.size() << "\n";
    for (size_t i = 0; i < treated_children_ids.size(); ++i) {
        std::cout << treated_children_ids[i] << (i == treated_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

