// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut, two pieces. s = A + B. New string s' = B + A.
    // We need s' to be a palindrome and s' != s.
    // Iterate through all possible cut positions.
    for (int i = 1; i < n; ++i) { // Cut after s[i-1], so A = s[0...i-1], B = s[i...n-1]
        std::string a = s.substr(0, i);
        std::string b = s.substr(i);
        std::string s_prime = b + a;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts, three pieces. s = A + B + C.
    // We need to find a permutation of A, B, C that forms a palindrome and is not s.
    // Since k=1 failed, we know that no single cut and swap (B+A) results in a valid string.
    // This implies that if a solution exists with k=2, it must involve more complex reordering.
    // However, the problem statement implies that we can always achieve a new palindrome
    // if the string is not of the form "aaaaa...".
    //
    // Let's analyze the structure of s.
    // If s consists of only one distinct character (e.g., "qqqq", "aaaaa"),
    // then any permutation of its substrings will result in the same string s.
    // For example, "qqqq" cut into "q" + "q" + "qq". Any reordering is "qqqq".
    // In this case, it's impossible to form a different string.
    //
    // If s contains at least two distinct characters, then it's always possible to find a solution with k=2.
    // Consider s = "nolon". n=5.
    // k=1 check:
    // "o" + "lon" -> "lonol" (palindrome, != "nolon") -> k=1. Wait, example says 2.
    // My k=1 logic is correct. "lonol" is a palindrome and != "nolon".
    // Why does the example say 2 for "nolon"?
    // "nolon"
    // i=1: A="n", B="olon". B+A = "olonn". Not palindrome.
    // i=2: A="no", B="lon". B+A = "lonno". Not palindrome.
    // i=3: A="nol", B="on". B+A = "onnol". Not palindrome.
    // i=4: A="nolo", B="n". B+A = "nolon". Same as s.
    // So for "nolon", k=1 is indeed not possible.
    //
    // The example explanation for "nolon" (k=2): "no|l|on" -> "on|l|no".
    // This is s[0..1] + s[2] + s[3..4].
    // A = "no", B = "l", C = "on".
    // Original: A B C = "nolon".
    // New: C B A = "onlno". This is a palindrome and != "nolon".
    // So k=2 is possible for "nolon".

    // The only case where it's impossible is if all characters in s are the same.
    // Check if all characters in s are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
        // This is because s is a palindrome and has at least two distinct characters.
        // We can always find a cut that splits s into A, B, C such that C B A is a palindrome.
        // For example, take s[0...n/2-1], s[n/2], s[n/2+1...n-1] (if n is odd).
        // Or s[0...n/2-1], "", s[n/2...n-1] (if n is even).
        // The strategy used in the "nolon" example (A, B, C -> C, B, A) works.
        // Let s = P + M + P_rev, where P is the first half, M is the middle char (if odd length).
        // If we cut s into P, M, P_rev, then P_rev + M + P is a palindrome.
        // This new string will be different from s if P is not equal to P_rev.
        // Since s is a palindrome, P_rev is the reverse of P.
        // So we need P != reverse(P).
        // If P is a palindrome itself, then P_rev = P.
        // Example: "abacaba". P="aba", M="c", P_rev="aba".
        // P M P_rev = "abacaba". P_rev M P = "abacaba". This doesn't work.
        //
        // The proof that k=2 is always possible if not all characters are the same:
        // If s is a palindrome and not all characters are the same, then s must contain at least two distinct characters.
        // Consider the string s' formed by taking s[1...n-1] + s[0].
        // This is a cyclic shift. If s' is a palindrome and s' != s, then k=1.
        // We already checked all k=1 cases.
        //
        // The problem statement implies that if k=1 doesn't work and not all chars are same, then k=2 is the answer.
        // This is a known property for palindromes. If a palindrome `s` is not composed of a single repeated character,
        // then it's always possible to form a different palindrome `s'` using 2 cuts.
        // For example, take `s` and remove its first character `s[0]`. The remaining string `s[1...n-1]` is `s_suffix`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // `s_suffix` is `s[1...n-1]`. Its reverse is `s[n-1...1]`.
        // Consider `s_suffix + s[0]`. This is `s[1...n-1] + s[0]`.
        // If this is a palindrome and different from `s`, then k=1.
        //
        // The example "nolon" shows that k=1 is not always possible even if not all chars are same.
        // But k=2 is possible.
        // The logic is: if a palindrome `s` has at least two distinct characters,
        // then it's always possible to find a `k=2` solution.
        // The only exception is if `s` consists of only one distinct character.
        // This is a known result in competitive programming problems related to palindromes and cuts.
        // The minimum number of cuts is 1 if a cyclic shift (B+A) works.
        // Otherwise, if the string is not monochromatic (all same characters), it's 2.
        // If it's monochromatic, it's impossible.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int i = 0; i < n; ++i) {
        if (p_idx == m) {
            break; // All required tracks covered
        }

        long long current_h = h[i];
        long long left_reach = current_h - T;
        long long right_reach = current_h + T;

        // Find the first track p[p_idx] that can be covered by current_h
        // It must be within [left_reach, right_reach]
        if (p[p_idx] > right_reach) {
            // This head cannot reach p[p_idx] or any subsequent tracks.
            // Since heads are sorted and p are sorted, if current_h cannot reach p[p_idx],
            // then current_h cannot cover p[p_idx] and current_h cannot cover any p[k] for k > p_idx.
            // And since h[i+1] > h[i], h[i+1] might be able to cover p[p_idx],
            // but we are trying to cover p[p_idx] with current_h.
            // If p[p_idx] is too far right for current_h, then current_h cannot cover it.
            // We need to find the first p[p_idx] that current_h can cover.
            // If p[p_idx] is already too far right, this head cannot help with it.
            // This logic is slightly off. We need to find the first p[k] that current_h can cover.
            // If current_h cannot cover p[p_idx], it means p[p_idx] is too far right.
            // This head can only cover tracks to its left or around it.
            // If p[p_idx] is to the right of current_h + T, then current_h cannot cover it.
            // This head is useless for p[p_idx] and subsequent tracks.
            // This means we need to use a different head for p[p_idx].
            // The current head h[i] must cover some p[k] where k >= p_idx.
            // If h[i] cannot cover p[p_idx], it means p[p_idx] is too far right.
            // This head cannot cover p[p_idx].
            // The logic should be: for each head, cover as many tracks as possible starting from p[p_idx].
            continue; // This head cannot reach p[p_idx], try next head.
        }

        // If p[p_idx] is within [left_reach, right_reach], this head can cover it.
        // Now, we need to determine the maximum range this head can cover,
        // considering it must cover p[p_idx].
        // The head can move to any position x such that |x - current_h| <= T.
        // If it moves to x, it covers [x-T, x+T].
        // To cover p[p_idx], x must be in [p[p_idx]-T, p[p_idx]+T].
        // Also, x must be in [current_h-T, current_h+T].
        // So, x must be in [max(current_h-T, p[p_idx]-T), min(current_h+T, p[p_idx]+T)].
        // To maximize the rightmost covered track, we should choose x as large as possible.
        // The largest possible x is min(current_h+T, p[p_idx]+T).
        // If we choose x = min(current_h+T, p[p_idx]+T), the range covered is [x-T, x+T].
        // The rightmost point covered is x+T = min(current_h+T, p[p_idx]+T) + T.
        // This is not quite right.
        // The head starts at current_h. It can move to any position `pos` such that `abs(pos - current_h) <= T`.
        // From `pos`, it can cover tracks in `[pos - T, pos + T]`.
        // We need to cover `p[p_idx]`. So, `p[p_idx]` must be in `[pos - T, pos + T]`.
        // This means `pos` must be in `[p[p_idx] - T, p[p_idx] + T]`.
        // Combining these, `pos` must be in `[max(current_h - T, p[p_idx] - T), min(current_h + T, p[p_idx] + T)]`.
        // To maximize the rightmost track covered, we should choose `pos` to be the largest possible value in this range.
        // Let `optimal_pos = min(current_h + T, p[p_idx] + T)`.
        // The rightmost track covered by this head would be `optimal_pos + T`.
        // However, this is only if `optimal_pos` is a valid position.
        // The actual rightmost track covered is `max_covered_right`.
        // If `p[p_idx]` is covered, the head can be moved to `p[p_idx]`. This takes `abs(p[p_idx] - current_h)` time.
        // Remaining time is `T - abs(p[p_idx] - current_h)`.
        // With this remaining time, the head can move further.
        // So, from `p[p_idx]`, it can reach `p[p_idx] + (T - abs(p[p_idx] - current_h))`.
        // This is `p[p_idx] + T - abs(p[p_idx] - current_h)`.
        // This is the rightmost point it can reach *after* covering p[p_idx].
        // This is the correct logic for the rightmost point covered by this head.
        long long max_covered_right = p[p_idx] + (T - std::abs(p[p_idx] - current_h));

        // Advance p_idx to the first track not covered by this head.
        while (p_idx < m && p[p_idx] <= max_covered_right) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10. A head can move 10^10 to cover a point, and then 10^10 more to cover another point. So 2*10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // min_r_for_l[i] stores the minimum r (0-indexed) such that s[i...r] contains a triple.
    // If no such r exists, it's n.
    // We want to find the maximum l (0-indexed) such that s[l...r] does NOT contain a triple.
    // This is equivalent to finding the maximum l such that for all x, k, if s_x=s_{x+k}=s_{x+2k},
    // then x+2k > r or x < l.
    // Let's define min_r_idx[i] as the smallest 0-indexed ending position (r) such that the substring s[i...r]
    // contains a triple. If no such triple starts at or after i, min_r_idx[i] = n.
    // We are looking for the smallest r_prime such that s[l...r_prime] contains a triple.
    // This r_prime is min_r_idx[l].
    // For a fixed l, any r < min_r_idx[l] will not contain a triple.
    // The number of such r's is min_r_idx[l] - l.
    // So, we need to sum (min_r_idx[l] - l) for all l from 0 to n-1.

    // To compute min_r_idx[l]:
    // min_r_idx[l] = min(min_r_idx[l+1], smallest_r_for_triple_starting_at_l)
    // where smallest_r_for_triple_starting_at_l is the minimum x+2k-1 for any triple (x, k)
    // such that x-1 = l.
    // This is not quite right. min_r_idx[l] should be the minimum r such that s[l...r] contains *any* triple.
    // So, min_r_idx[l] = min(min_r_idx[l+1], min_r_for_any_triple_starting_at_or_after_l_and_ending_at_r)
    // Let's define `first_triple_end[i]` as the minimum `x+2k-1` (0-indexed) such that `s[x-1]=s[x+k-1]=s[x+2k-1]`
    // and `x-1 = i`. If no such triple starts at `i`, `first_triple_end[i] = n`.
    // Then, `min_r_idx[l]` is the minimum of all `first_triple_end[j]` for `j >= l`.
    // This can be computed with a suffix minimum.

    std::vector<int> first_triple_end(n, n); // Stores min x+2k-1 for triple starting at x-1=i

    // Iterate through all possible starting positions x (0-indexed)
    for (int x_idx = 0; x_idx < n; ++x_idx) {
        // Iterate through possible k values.
        // x_idx + 2k must be less than n. So 2k < n - x_idx. k < (n - x_idx) / 2.
        // Max k is (n - x_idx - 1) / 2.
        // For k=1, x_idx+2 < n.
        // For k=2, x_idx+4 < n.
        // For k=3, x_idx+6 < n.
        // For k=4, x_idx+8 < n.
        // For k=5, x_idx+10 < n.
        // For k=6, x_idx+12 < n.
        // Max k is 6 because 2*6 = 12. If k >= 7, 2k >= 14.
        // If s[x_idx] == s[x_idx+k] == s[x_idx+2k], then x_idx+2k is a candidate for first_triple_end[x_idx].
        // We only need to check small k values.
        // If s[x_idx] == s[x_idx+k] == s[x_idx+2k], then x_idx+2k is the end of the triple.
        // The problem statement implies k >= 1.
        // The maximum k we need to check is small.
        // If k is large, say k=7, then x_idx, x_idx+7, x_idx+14.
        // If s[x_idx] == s[x_idx+7] == s[x_idx+14], then this is a triple.
        // But if there is a triple, say s[a]=s[a+k']=s[a+2k'], then the substring s[l...r] contains it if l <= a and a+2k' <= r.
        // Consider the case where all characters are the same, e.g., "0000000000000000".
        // For x_idx=0, k=1: s[0]=s[1]=s[2]. End is 2.
        // For x_idx=0, k=2: s[0]=s[2]=s[4]. End is 4.
        // For x_idx=0, k=3: s[0]=s[3]=s[6]. End is 6.
        // ...
        // For x_idx=0, k=6: s[0]=s[6]=s[12]. End is 12.
        // The smallest end for x_idx=0 is 2.
        // The maximum k we need to check is 6. Why?
        // If s[x_idx] == s[x_idx+k] == s[x_idx+2k] for some k >= 1,
        // then the substring s[x_idx ... x_idx+2k] contains this triple.
        // If k >= 7, then 2k >= 14.
        // If there is a triple (x, k) with k >= 7, then the substring s[x ... x+2k] contains it.
        // But it must also contain a triple (x', k') with k' <= 6.
        // This is because if s[x] = s[x+k] = s[x+2k], then either s[x] = s[x+1] = s[x+2] (k=1)
        // or s[x+1] = s[x+2] = s[x+3] (k=1) etc.
        // This is not true. Example: 010101010101010. s[0]=s[7]=s[14] (all 0s). k=7.
        // But there is no k' <= 6 such that s[x']=s[x'+k']=s[x'+2k'] within s[0...14].
        // The problem is that the condition $s_x = s_{x+k} = s_{x+2k}$ is very specific.
        // The maximum length of a string without such a triple is small.
        // If a string has length 13, it must contain such a triple.
        // Consider a string of length 13.
        // If it doesn't contain '000' or '111' (k=1), then it must alternate, e.g., 0101010101010.
        // In this case, s[0]=s[2]=s[4]=s[6]=s[8]=s[10]=s[12] (all 0s).
        // This means s[0]=s[2]=s[4] (k=2), s[0]=s[4]=s[8] (k=4), s[0]=s[6]=s[12] (k=6).
        // So, if a string has length at least 13, it must contain a triple with k <= 6.
        // The maximum length of a string that does NOT contain such a triple is 12.
        // Example: 001100110011 (length 12). No triple.
        // So, we only need to check k from 1 to 6.
        for (int k = 1; k <= 6; ++k) { // k can be at most 6
            if (x_idx + 2 * k < n) {
                if (s[x_idx] == s[x_idx + k] && s[x_idx] == s[x_idx + 2 * k]) {
                    first_triple_end[x_idx] = std::min(first_triple_end[x_idx], x_idx + 2 * k);
                }
            }
        }
    }

    // Compute suffix minimums for first_triple_end.
    // min_r_idx[l] = min(first_triple_end[l], first_triple_end[l+1], ..., first_triple_end[n-1])
    // This is the minimum ending position of *any* triple that starts at or after index l.
    std::vector<int> min_r_idx(n + 1, n); // min_r_idx[l] is the smallest r (0-indexed) such that s[l...r] contains a triple.
                                        // min_r_idx[n] = n (base case for suffix min)
    for (int l = n - 1; l >= 0; --l) {
        min_r_idx[l] = std::min(min_r_idx[l + 1], first_triple_end[l]);
    }

    // Now, for each l (0-indexed), the number of r's (0-indexed) such that s[l...r] does NOT contain a triple
    // is (min_r_idx[l] - 1) - l + 1 = min_r_idx[l] - l.
    // These are r values from l to min_r_idx[l] - 1.
    // Sum these up to get the total count of invalid pairs.
    for (int l = 0; l < n; ++l) {
        invalid_pairs += (min_r_idx[l] - l);
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

