        std::vector<long long> a(n);
        int min_idx = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < a[min_idx]) {
                min_idx = i;
            }
        }

        long long min_val = a[min_idx];
        long long operations = 0;

        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // We want to add min_val to a[i] as many times as possible
            // without a[i] exceeding k.
            // Each operation adds min_val.
            // The current pile size is a[i].
            // We can add min_val until a[i] + x * min_val > k.
            // So, x * min_val <= k - a[i].
            // x <= (k - a[i]) / min_val.
            // Since x must be an integer, x = floor((k - a[i]) / min_val).
            if (min_val == 0) { // Should not happen based on constraints (a_i >= 1)
                // If min_val is 0, we can add infinitely without exceeding k,
                // unless k is also 0 and a[i] is positive.
                // But a_i >= 1, so min_val >= 1.
            } else {
                operations += (k - a[i]) / min_val;
            }
        }
        std::cout << operations << "\n";
    }
    return 0;
}

