    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n >= 2) and results in the same set of adjacent sums.
    // For example, if p = [p1, p2, p3], sums are [p1+p2, p2+p3].
    // Reversed p' = [p3, p2, p1], sums are [p3+p2, p2+p1].
    // The set of sums is the same, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // Since n >= 2, p is always different from its reverse unless n=1 (not possible)
    // or p is a palindrome (e.g., [1,2,1] not a permutation, [1,2,3,2,1] not a permutation).
    // A permutation cannot be a palindrome unless n=1.
    // For n=2, p=[1,2], p'=[2,1]. F(p)=[3], F(p')=[3].
    // For n=3, p=[1,2,3], p'=[3,2,1]. F(p)=[3,5], F(p')=[5,3]. Sorted: [3,5].
    // So reversing the permutation is a general solution.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

