void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // up to 2048.
        // For example, if val=1 and count=5, we add 5*1=5 to current_sum.
        // If val=1024 and count=3, we add 3*1024=3072 to current_sum.
        // The sum is capped at 2048, because any value beyond 2048
        // cannot be used to form 2048.
        // For example, if we have 1024 and 1024, we can form 2048.
        // If we have 1024, 1024, 1024, we can form 2048 and have 1024 left over.
        // The effective sum we can form is 2048.
        // So, we only care about the sum up to 2048.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

