    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[n - 1] != b[n - 1]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element.
            // Update has_pos_one/has_neg_one based on a[i] for future checks.
            if (a[i] == 1) has_pos_one = true;
            else if (a[i] == -1) has_neg_one = true;
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // a[i] > b[i], need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }

        // Update has_pos_one/has_neg_one based on a[i] for future checks.
        if (a[i] == 1) has_pos_one = true;
        else if (a[i] == -1) has_neg_one = true;
    }

    std::cout << "YES\n";
}

