#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current nice staircase (1, 3, 7, 15, ...)
        while (true) {
            // Cost of a nice staircase with k stairs is k * (k + 1) / 2
            // Here, k is actually 2^p - 1 for some p.
            // The number of cells for a nice staircase with (2^p - 1) stairs is (2^p - 1) * (2^p) / 2.
            // Let's use 'k' to denote the number of stairs, which is 2^p - 1.
            // The cost is k * (k+1) / 2.
            // For k=1 (p=1), cost = 1 * 2 / 2 = 1.
            // For k=3 (p=2), cost = 3 * 4 / 2 = 6.
            // For k=7 (p=3), cost = 7 * 8 / 2 = 28.
            // For k=15 (p=4), cost = 15 * 16 / 2 = 120.

            long long cost_of_this_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_this_staircase <= x) {
                current_cost += cost_of_this_staircase;
                count++;
                // Next k will be 2 * k + 1
                // This is equivalent to 2^(p+1) - 1
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

