    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available divided by 3.
        // 2. The number of coders (each team needs at least one coder).
        // 3. The number of mathematicians (each team needs at least one mathematician).
        // So, k <= (c + m + x) / 3
        // And k <= c
        // And k <= m
        // Combining these, k <= min(c, m, (c + m + x) / 3)

        // Let's check if a given number of teams 'k' is possible.
        // To form 'k' teams, we need at least 'k' coders and 'k' mathematicians.
        // The remaining (c - k) coders and (m - k) mathematicians, along with 'x' unspecialized students,
        // must fill the remaining 'k' slots (one for each team, since each team already has 1C and 1M).
        // So, (c - k) + (m - k) + x >= k
        // c + m + x >= 3k
        // k <= (c + m + x) / 3

        // Also, we cannot form more teams than the minimum of coders or mathematicians,
        // because each team requires at least one of each.
        // So, k <= c and k <= m.

        // Therefore, the maximum k is limited by min(c, m, (c + m + x) / 3).

        long long ans = std::min({c, m, (c + m + x) / 3});
