int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the alternating part to generate k distinct differences

    // Generate k distinct differences using the alternating pattern
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k + 1) elements, we need to ensure no new distinct differences are introduced.
    // The simplest way is to continue with an increasing sequence.
    // The last number printed was either `left-1` or `right+1`.
    // If it was `left-1`, then `left` is the next available number.
    // If it was `right+1`, then `right` is the next available number.
    // In both cases, `left` is the smallest unused number.
    // So, we can just print `left, left+1, ..., n`.
    for (int i = k + 1; i < n; ++i) {
        std::cout << left++;
        std::cout << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

