    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // If we remove a prefix of length `p`, the remaining array starts with a[p].
    // The smallest `p` is 0.
    int p = n - 1;
    while (p > 0 && a[p-1] <= a[p]) {
        p--;
    }
    // Now a[p...n-1] is non-decreasing.
    // If p is 0, the whole array is non-decreasing.

    // Find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // We are looking for the first element from the right that breaks this non-increasing pattern.
    // The elements a[p...n-1] are already non-decreasing.
    // We need to find the first element from the right that is not part of the non-increasing suffix
    // that precedes the non-decreasing suffix.
    // So we start from p-1 and go left.
    int q = p; // q is the start of the non-increasing part.
    while (q > 0 && a[q-1] >= a[q]) {
        q--;
    }
    // Now a[q...p-1] is non-increasing.
    // The elements a[q...n-1] form a "mountain" or "valley" shape:
    // a[q] >= a[q+1] >= ... >= a[p-1] <= a[p] <= ... <= a[n-1].
    // This is the longest suffix that can be made good.
    // The length of the prefix to remove is `q`.

    std::cout << q << std::endl;
}

