}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the minimum required value for each element if it were part of the strictly increasing prefix
    // For a_i to be part of a strictly increasing prefix starting from 0:
    // a_0 >= 0, a_1 >= 1, ..., a_i >= i
    // So, we need original_a_i >= i
    std::vector<long long> min_left(n);
    for (int i = 0; i < n; ++i) {
        min_left[i] = i;
    }

    // Calculate the minimum required value for each element if it were part of the strictly decreasing suffix
    // For a_i to be part of a strictly decreasing suffix ending at 0:
    // a_{n-1} >= 0, a_{n-2} >= 1, ..., a_i >= (n-1-i)
    // So, we need original_a_i >= (n-1-i)
    std::vector<long long> min_right(n);
    for (int i = 0; i < n; ++i) {
        min_right[i] = (n - 1 - i);
    }

    // Check if there exists a peak k such that:
    // 1. For all i < k, a_i can be made >= i (original_a_i >= i)
    // 2. For all i > k, a_i can be made >= (n-1-i) (original_a_i >= (n-1-i))
    // 3. For the peak a_k, it must be able to satisfy both conditions:
    //    original_a_k >= k AND original_a_k >= (n-1-k)
    //    This simplifies to original_a_k >= max(k, n-1-k)

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        // Check left part (a_0 to a_k)
        // For a_i (i < k), we need a_i >= i.
        // For a_k, we need a_k >= k.
        if (a[k] < min_left[k]) {
            continue; // a_k cannot be the peak for this k, as it's too small for the left side
        }

        // Check right part (a_k to a_{n-1})
        // For a_i (i > k), we need a_i >= (n-1-i).
        // For a_k, we need a_k >= (n-1-k).
        if (a[k] < min_right[k]) {
            continue; // a_k cannot be the peak for this k, as it's too small for the right side
        }

        // If a[k] satisfies its own conditions for being a peak,
        // we still need to check if all elements to its left and right can satisfy their conditions.
        // This is implicitly handled by the min_left and min_right arrays.
        // If a[k] can be made >= k AND a[k] can be made >= (n-1-k),
        // and all elements a[0]...a[k-1] can be made >= 0...k-1 respectively,
        // and all elements a[k+1]...a[n-1] can be made >= (n-1-(k+1))...0 respectively,
        // then it's possible.

        // The conditions are:
        // For i from 0 to k: a[i] >= i
        // For i from k to n-1: a[i] >= (n-1-i)
        // We need to find a k such that both hold for the original array.

        bool current_k_possible = true;
        for (int i = 0; i < k; ++i) { // Elements strictly to the left of k
            if (a[i] < min_left[i]) {
                current_k_possible = false;
                break;
            }
        }
        if (!current_k_possible) continue;

        for (int i = k + 1; i < n; ++i) { // Elements strictly to the right of k
            if (a[i] < min_right[i]) {
                current_k_possible = false;
                break;
            }
        }
        if (!current_k_possible) continue;

        // If we reach here, it means a[k] satisfies its peak conditions (a[k] >= k and a[k] >= n-1-k)
        // AND all elements to its left satisfy a[i] >= i
        // AND all elements to its right satisfy a[i] >= n-1-i
        // This means we can form a sharpened array with peak at k.
        possible = true;
        break;
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

