// Function to determine if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // The number of negative factors is A + B.
    // If A + B is odd, the final product can be negative.
    if ((A + B) % 2 == 1) {
        // To be in Box 1, the final product must be <= -1.
        // This means its absolute value must be >= 1.
        // We need to ensure we can achieve a magnitude >= 1.
        // A magnitude >= 1 is possible if:
        // 1. There is at least one toy in Box 1 or Box 4 (magnitude >= 1).
        // 2. Or, if there are no toys in Box 1 or Box 4, but there are at least two toys in Box 2 or Box 3.
        //    However, if all toys are in Box 2 or Box 3, their product will always be < 1 in magnitude.
        //    So, we must have at least one toy from Box 1 or Box 4 to guarantee magnitude >= 1.
        //    If A+D == 0, then all toys are in B and C. The product of any number of toys from B and C will have magnitude < 1.
        //    So, if A+D == 0, it's impossible to get a final product with magnitude >= 1.
        if (A + D > 0) {
            return true;
        }
    }
    return false;
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // The number of negative factors is A + B.
    // If A + B is odd, the final product can be negative.
    if ((A + B) % 2 == 1) {
        // To be in Box 2, the final product must be between -1 and 0.
        // This means its absolute value must be between 0 and 1.
        // This is always possible if A+B is odd, unless all toys are in Box 1 or Box 4.
        // If all toys are in Box 1 or Box 4, and A+B is odd, the magnitude will be >= 1.
        // So, we need to ensure we can achieve a magnitude < 1.
        // This is possible if:
        // 1. There is at least one toy in Box 2 or Box 3 (magnitude < 1).
        // 2. Or, if there are no toys in Box 2 or Box 3, but there are at least two toys in Box 1 or Box 4.
        //    If we have only one toy in Box 1 or Box 4, and A+B is odd, it must be from Box 1.
        //    In this case, if total_toys == 1, it's in Box 1.
        //    If total_toys > 1, we can always combine a large number with a small number to get a small number.
        //    For example, if we have {-3, 3, 0.1}, we can do (-3 * 0.1) = -0.3 (Box 2), then (-0.3 * 3) = -0.9 (Box 2).
        //    The only way to *not* be able to get magnitude < 1 is if all toys have magnitude >= 1, and there's only one such toy.
        //    If A+D > 1, we can always combine two toys from A/D to get a large number, then combine with a small number.
        //    Or, if B+C > 0, we can combine a toy from B/C with any other toy to potentially get a small number.
        //    The only scenario where we *cannot* get a magnitude < 1 is if all toys have magnitude >= 1 (i.e., B=C=0)
        //    AND there is only one toy (A+D=1).
        //    If B=C=0 and A+D=1, then total_toys=1. If A=1, B=C=D=0, then the toy is in Box 1.
        //    If D=1, A=B=C=0, then the toy is in Box 4.
        //    So, if total_toys == 1 and A=1, it's in Box 1.
        //    If total_toys == 1 and D=1, it's in Box 4.
        //    In these cases, it cannot be in Box 2.
        //    Otherwise, if A+B is odd, it can be in Box 2.
        if (total_toys == 1) {
            return false; // If only one toy, it's either in Box 1 or Box 4, not Box 2.
        }
        return true;
    }
    return false;
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Final product is positive.
    // This requires an even number of negative factors.
    // The number of negative factors is A + B.
    // If A + B is even, the final product can be positive.
    if ((A + B) % 2 == 0) {
        // To be in Box 3, the final product must be between 0 and 1.
        // This means its absolute value must be between 0 and 1.
        // This is always possible if A+B is even, unless all toys are in Box 1 or Box 4.
        // If all toys are in Box 1 or Box 4, and A+B is even, the magnitude will be >= 1.
        // So, we need to ensure we can achieve a magnitude < 1.
        // This is possible if:
        // 1. There is at least one toy in Box 2 or Box 3 (magnitude < 1).
        // 2. Or, if there are no toys in Box 2 or Box 3, but there are at least two toys in Box 1 or Box 4.
        //    If we have only one toy in Box 1 or Box 4, and A+B is even, it must be from Box 4.
        //    In this case, if total_toys == 1, it's in Box 4.
        //    If total_toys > 1, we can always combine a large number with a small number to get a small number.
        //    The only scenario where we *cannot* get a magnitude < 1 is if all toys have magnitude >= 1 (i.e., B=C=0)
        //    AND there is only one toy (A+D=1).
        //    If B=C=0 and A+D=1, then total_toys=1. If A=1, B=C=D=0, then the toy is in Box 1.
        //    If D=1, A=B=C=0, then the toy is in Box 4.
        //    In these cases, it cannot be in Box 3.
        //    Otherwise, if A+B is even, it can be in Box 3.
        if (total_toys == 1) {
            return false; // If only one toy, it's either in Box 1 or Box 4, not Box 3.
        }
        return true;
    }
    return false;
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Final product is positive.
    // This requires an even number of negative factors.
    // The number of negative factors is A + B.
    // If A + B is even, the final product can be positive.
    if ((A + B) % 2 == 0) {
        // To be in Box 4, the final product must be >= 1.
        // This means its absolute value must be >= 1.
        // We need to ensure we can achieve a magnitude >= 1.
        // A magnitude >= 1 is possible if:
        // 1. There is at least one toy in Box 1 or Box 4 (magnitude >= 1).
        // 2. Or, if there are no toys in Box 1 or Box 4, but there are at least two toys in Box 2 or Box 3.
        //    However, if all toys are in Box 2 or Box 3, their product will always be < 1 in magnitude.
        //    So, if A+D == 0, it's impossible to get a final product with magnitude >= 1.
        if (A + D > 0) {
            return true;
        }
    }
    return false;
}

