long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: N=2, Chanek takes 1, Opponent takes 1. Chanek gets 1.
                chanek_coins += 1;
                n -= 1; // N becomes 1, then opponent takes 1.
            } else {
                // Check if N is a power of 2
                // A number is a power of 2 if (n & (n - 1)) == 0
                if ((n & (n - 1)) == 0) { // N is a power of 2 (and N > 2)
                    // Chanek takes 1. N becomes N-1 (odd).
                    // Opponent takes 1. N becomes N-2 (even).
                    // Chanek takes N/2. N becomes N/2.
                    // This is better than Chanek taking N/2 directly.
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is even but not a power of 2
                    // Chanek takes N/2.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        }
        // Opponent's turn (if n > 0)
        if (n > 0) {
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    n -= 1;
                } else {
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        n -= 1;
                    } else { // N is even but not a power of 2
                        n /= 2;
                    }
                }
            }
        }
    }
    return chanek_coins;
}

