    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'a') {
            // If we encounter an 'a', it means this 'a' will eventually
            // jump over all 'b's to its right.
            // Each 'b' it jumps over will double the number of 'a's
            // that need to jump over it (conceptually).
            // The number of 'b's this 'a' needs to jump over is `count_a`.
            // So, this 'a' contributes `count_a` steps.
            total_steps = (total_steps + count_a) % mod;
            // After this 'a' jumps over all `count_a` 'b's, it effectively
            // becomes a 'b' (or rather, it creates a 'b' in its place
            // and moves past the original 'b').
            // The key insight is that an 'a' effectively doubles the
            // number of 'b's that need to be processed by 'a's to its left.
            // So, `count_a` doubles for the next 'a' to its left.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'b'
            // If we encounter a 'b', it means this 'b' is available
            // for an 'a' to its left to jump over.
            // So, we increment the count of 'b's that an 'a' can jump over.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

