// Function to convert a number to its parity pattern string
// For example, 12345 -> "10101"
// The pattern is always 18 characters long, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern_str;
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding the number with '0's from the left
    // For example, 92 -> "01" (reversed) -> "10" (correct)
    // Padded to 18: "000000000000000010"
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // A map to store counts of each 18-digit parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the query pattern with '0's from the left to make it 18 characters long
            // This is equivalent to padding with '0's from the right in the reversed string
            // For example, "010" -> "000...000010"
            std::string query_pattern_padded = s;
            while (query_pattern_padded.length() < 18) {
                query_pattern_padded = '0' + query_pattern_padded;
            }

            std::cout << pattern_counts[query_pattern_padded] << "\n";
        }
    }

    return 0;
}

