    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum_w(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_w[i + 1] = prefix_sum_w[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;
        long long left_items_weight_sum = prefix_sum_w[i];
        long long right_items_weight_sum = prefix_sum_w[n] - prefix_sum_w[i];

        current_energy += left_items_weight_sum * l;
        current_energy += right_items_weight_sum * r;

        int num_left = i;
        int num_right = n - i;

        if (num_left > num_right) {
            // More items from left. The difference is num_left - num_right.
            // We need to pay Ql for (num_left - num_right - 1) times.
            // This is because if num_left = num_right + 1, no extra Ql is paid.
            // If num_left = num_right + 2, one extra Ql is paid.
            // So, if num_left > num_right, we pay Ql for (num_left - num_right - 1) times.
            // The number of times we pay Ql is max(0, num_left - num_right - 1).
            current_energy += std::max(0, num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items from right. The difference is num_right - num_left.
            // We need to pay Qr for (num_right - num_left - 1) times.
            current_energy += std::max(0, num_right - num_left - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

