// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must be p / (some factor of p that makes it not divisible by q).
        // To maximize x, we need to divide p by the smallest possible factor that achieves x % q != 0.
        // This smallest factor must be related to the prime factors of q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long r : q_prime_factors) {
            // For each prime factor r of q, we want to find the largest divisor of p
            // that is not divisible by q.
            // Consider p_temp = p. We want to remove just enough factors of r from p_temp
            // such that p_temp is no longer divisible by q.
            // The resulting p_temp will be a candidate for x.
            // We want to maximize this p_temp.

            long long current_p = p;
            while (current_p % r == 0 && current_p % q == 0) {
                current_p /= r;
            }
            // After this loop, current_p is a divisor of p.
            // It is guaranteed that current_p % q != 0 because we removed enough factors of r.
            // If current_p % r != 0, then current_p cannot be divisible by q (since q is divisible by r).
            // If current_p % r == 0, but current_p % q != 0, it means the power of r in current_p
            // is less than the power of r in q.
            // This current_p is a candidate for x. We want the maximum such x.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string ans(n, ' ');
    bool found_solution = false;

    for (int split_digit = 0; split_digit <= 9; ++split_digit) {
        int last1 = -1;
        int last2 = -1;
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < split_digit) { // Must be color 1
                if (d[i] >= last1) {
                    ans[i] = '1';
                    last1 = d[i];
                } else {
                    possible = false;
                    break;
                }
            } else if (d[i] > split_digit) { // Must be color 2
                if (d[i] >= last2) {
                    ans[i] = '2';
                    last2 = d[i];
                } else {
                    possible = false;
                    break;
                }
            } else { // d[i] == split_digit
                // Try to put in color 1
                if (d[i] >= last1) {
                    ans[i] = '1';
                    last1 = d[i];
                } else if (d[i] >= last2) { // If cannot put in color 1, try color 2
                    ans[i] = '2';
                    last2 = d[i];
                } else { // Cannot put in either
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            // Final check: last1 <= first2.
            // This is implicitly handled by the split_digit logic.
            // All digits assigned '1' are <= split_digit.
            // All digits assigned '2' are >= split_digit.
            // If last1 is the largest digit in S1, and first2 is the smallest in S2,
            // then last1 <= split_digit <= first2.
            // The only edge case is if S1 is empty or S2 is empty.
            // If S1 is empty, last1 remains -1.
            // If S2 is empty, last2 remains -1.
            // The logic above ensures that if a digit is assigned to color 1, it's >= last1.
            // If a digit is assigned to color 2, it's >= last2.
            // The crucial part is that any digit assigned '1' is <= split_digit,
            // and any digit assigned '2' is >= split_digit.
            // So, the last digit of S1 (if S1 is not empty) will be <= split_digit.
            // The first digit of S2 (if S2 is not empty) will be >= split_digit.
            // Thus, last(S1) <= split_digit <= first(S2) is guaranteed.
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << ans << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

