int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1: can move left (x-1). If f1=0, cannot move left.
            // So, if f1=0, target X must be >= current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 1: can move right (x+1). If f3=0, cannot move right.
            // So, if f3=0, target X must be <= current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 1: can move down (y-1). If f4=0, cannot move down.
            // So, if f4=0, target Y must be >= current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 1: can move up (y+1). If f2=0, cannot move up.
            // So, if f2=0, target Y must be <= current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. The problem guarantees that if a solution exists,
            // one exists with coordinates not exceeding 10^5 by absolute value.
            // We can pick any point within the valid range.
            // For example, (min_x, min_y) or (max_x, max_y) or (0,0) if within range.
            // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
            // This implies that if min_x > 10^5 or max_x < -10^5, etc., we should pick a point within [-10^5, 10^5].
            // However, the guarantee "if there exists at least one point reachable by all robots,
            // then at least one of such points has both coordinates not exceeding 10^5 by absolute value"
            // means we don't need to clamp our chosen min_x/min_y if they are outside this range,
            // as long as they are valid. The problem implies that if min_x is, say, 200000,
            // then there must be some other valid point within [-10^5, 10^5].
            // But the simplest interpretation is to just output any valid point.
            // Let's pick min_x and min_y, and clamp them to [-10^5, 10^5] if they fall outside,
            // to be safe, although the problem statement implies this might not be strictly necessary
            // if min_x/min_y are already valid.
            // The maximum possible coordinate value for x_i, y_i is 10^5.
            // So min_x and max_x will be within [-10^5, 10^5] if they are derived from x_i.
            // The initial values are outside this range, but they are just sentinels.
            // Any actual bound will be an x_i or y_i.
            // So, min_x, max_x, min_y, max_y will always be within [-10^5, 10^5] if they are not the sentinel values.
            // If they are sentinel values, it means no robot restricted that bound, so we can pick 0.
            long long final_x = min_x;
            if (final_x < -100000) final_x = -100000;
            if (final_x > 100000) final_x = 100000; // This case should not happen if min_x is derived from x_i

            long long final_y = min_y;
            if (final_y < -100000) final_y = -100000;
            if (final_y > 100000) final_y = 100000; // This case should not happen if min_y is derived from y_i

            std::cout << 1 << " " << final_x << " " << final_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length(); ++i) {
        char current_char = s[i];
        if (i > 0) {
            char prev_char = s[i - 1];
            adj[current_char].insert(prev_char);
            adj[prev_char].insert(current_char);
        }
        if (i < s.length() - 1) {
            char next_char = s[i + 1];
            adj[current_char].insert(next_char);
            adj[next_char].insert(current_char);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string keyboard_layout = "";
    std::set<char> visited_in_path;
    char path_start_char = '\0';

    // Find a starting character for a path (degree 1 in the adjacency graph)
    // Or if all characters have degree 2, pick any unvisited character.
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            path_start_char = c;
            break;
        }
    }

    // If no degree 1 node found, it means all nodes in the password graph have degree 2 (a cycle)
    // or there are no characters from the password (s.length() == 1).
    // If s.length() == 1, adj will be empty for that char, so it won't be picked.
    // If s.length() > 1 and all nodes have degree 2, pick any character from s.
    if (path_start_char == '\0' && !s.empty()) {
        path_start_char = s[0];
    }

    if (path_start_char != '\0') {
        char current_char = path_start_char;
        char prev_char = '\0'; // Sentinel for the first step

        while (visited_in_path.find(current_char) == visited_in_path.end()) {
            keyboard_layout += current_char;
            visited_in_path.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
            if (current_char == '\0' && adj[prev_char].size() == 2) {
                // This case should not happen if the graph is a path or cycle
                // and we started from a degree 1 node.
                // If we started from a degree 2 node in a cycle, this loop would continue.
                // If we started from a degree 2 node in a path, this means we reached the other end.
                // This condition is mainly for when current_char becomes '\0' because there are no more neighbors
                // (i.e., we reached an end of a path).
                break;
            }
        }
    }

    // Add remaining characters not in the password or not part of the main path
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_path.find(c) == visited_in_path.end()) {
            keyboard_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << keyboard_layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) return 0;
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;

    // (n * (n + 1) / 2) % MOD
    // We need to handle division by 2.
    // Since MOD is prime (10^9 + 7), we can use modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long inv2 = 500000004; 

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    if (term1 % 2 == 0) {
        term1 /= 2;
    } else {
        term2 /= 2;
    }

    return (term1 * term2) % MOD;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_val = sum_arithmetic_series(b - 1);

    // Calculate sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a
    long long sum_k_b_plus_1_val;

    long long sum_k_val = sum_arithmetic_series(a); // (a * (a + 1) / 2) % MOD

    long long term_b_times_sum_k = (b % MOD * sum_k_val) % MOD;
    long long term_a = a % MOD;

    sum_k_b_plus_1_val = (term_b_times_sum_k + term_a) % MOD;

    // Total sum = (sum_{k=1 to a} (k * b + 1)) * (sum_{r=1 to b-1} r)
    long long total_sum = (sum_k_b_plus_1_val * sum_r_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char t0_char = s[k_actual]; // The first character Vasya sees

        // Find all possible k' values that could produce t0_char
        // These are the indices where s[idx] == t0_char
        const std::vector<int>& possible_k_values = char_indices[t0_char - 'a'];

        if (possible_k_values.size() == 1) {
            // If only one k' produces t0_char, Vasya already knows k.
            // He wins regardless of the second letter.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p (1 to L-1)
        // to maximize his win probability for this t0_char.
        double max_win_prob_for_t0 = 0.0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed p, count how many k' values lead to a unique determination.
            int wins_for_this_p = 0;

            // Group possible_k_values by the character they produce at t[p]
            // map: char_at_t_p -> list_of_k_values_producing_it
            std::map<char, std::vector<int>> groups_by_tp_char;
            for (int k_prime : possible_k_values) {
                char tp_char = s[(k_prime + p) % L];
                groups_by_tp_char[tp_char].push_back(k_prime);
            }

            // If a group has only one k', then choosing this p and observing this tp_char
            // uniquely determines k'.
            for (const auto& pair : groups_by_tp_char) {
                if (pair.second.size() == 1) {
                    wins_for_this_p++;
                }
            }

            // The probability of winning with this p is (number of unique k's) / (total number of possible k's)
            max_win_prob_for_t0 = std::max(max_win_prob_for_t0, (double)wins_for_this_p / possible_k_values.size());
        }
        total_win_prob += max_win_prob_for_t0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int m = static_cast<int>(std::sqrt(n));
    // If n is a perfect square, m*m = n.
    // If n is not a perfect square, m*m < n.
    // We want k*l >= n.
    // To minimize k+l, we want k and l to be close to sqrt(n).
    // Let k = m. Then l must be at least ceil(n/m).
    // If n is a perfect square, m*m = n, so k=m, l=m works.
    // If n is not a perfect square, m*m < n.
    // We can choose k = m, and l = ceil(n/m).
    // Or we can choose k = m+1, and l = ceil(n/(m+1)).
    // The construction below uses blocks of size m.
    // The number of blocks will be ceil(n/m).
    // The LIS length will be ceil(n/m).
    // The LDS length will be m.
    // So, LIS + LDS = ceil(n/m) + m.
    // This is approximately 2*sqrt(n).

    // Example: n=4, m=2. Blocks of size 2.
    // Block 1: 2 1
    // Block 2: 4 3
    // Permutation: 2 1 4 3.
    // LIS: [2,4], [1,3], [2,3], [1,4] -> length 2.
    // LDS: [2,1], [4,3] -> length 2.
    // Sum = 4.
    // The example output is 3 4 1 2.
    // LIS: [3,4], [1,2] -> length 2.
    // LDS: [3,1], [4,2], [3,2], [4,1] -> length 2.
    // Sum = 4.
    // My construction for n=4:
    // m = sqrt(4) = 2.
    // Block size = 2.
    // Current number = 1.
    // Block 1: 2 1 (from 1 to 2)
    // Block 2: 4 3 (from 3 to 4)
    // Result: 2 1 4 3. This is also valid.

    // The construction strategy:
    // Divide the numbers 1 to n into blocks of size `m`.
    // For each block, print numbers in decreasing order.
    // The blocks themselves are arranged in increasing order of their starting values.
    // Example: n=7, m=2.
    // Block size = 2.
    // Block 1: 2 1 (numbers 1, 2)
    // Block 2: 4 3 (numbers 3, 4)
    // Block 3: 6 5 (numbers 5, 6)
    // Block 4: 7 (number 7)
    // Result: 2 1 4 3 6 5 7
    // LIS: [1,3,5,7] or [2,4,6,7] -> length 4.
    // LDS: [2,1], [4,3], [6,5] -> length 2.
    // Sum = 4 + 2 = 6.
    // For n=7, sqrt(7) approx 2.64. ceil(sqrt(7)) = 3.
    // 2*sqrt(7) approx 5.29.
    // My construction gives 6.
    // If we choose m=3:
    // Block size = 3.
    // Block 1: 3 2 1
    // Block 2: 6 5 4
    // Block 3: 7
    // Result: 3 2 1 6 5 4 7
    // LIS: [1,4,7] or [2,5,7] or [3,6,7] -> length 3.
    // LDS: [3,2,1], [6,5,4] -> length 3.
    // Sum = 3 + 3 = 6.
    // Both m=2 and m=3 give sum 6.

    // The problem asks for *any* permutation.
    // The strategy of using blocks of size `m = floor(sqrt(n))` and reversing each block
    // seems to be a common way to achieve near-optimal LIS+LDS sum.
    // The LIS length will be `ceil(n/m)` (one element from each block).
    // The LDS length will be `m` (within any block).
    // Sum = `ceil(n/m) + m`.

    int current_num = 1;
    while (current_num <= n) {
        int block_end = std::min(current_num + m - 1, n);
        for (int i = block_end; i >= current_num; --i) {
            std::cout << i << (i == n ? "" : " ");
        }
        current_num = block_end + 1;
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_indices;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_indices.push_back(i);
        }
    }

    // Iterate over all possible right endpoints r
    for (int r = 0; r < n; ++r) {
        // Case 1: Substring starts with '1'
        // s_l...s_r, where s_l = '1'
        // The length of the substring is len = r - l + 1.
        // The value is val = f(s_l...s_r).
        // We need len = val.
        // Since val >= 2^(len-1), we must have len >= 2^(len-1).
        // This inequality holds only for small len:
        // len=1: 1 >= 2^0 = 1 (True)
        // len=2: 2 >= 2^1 = 2 (True)
        // len=3: 3 >= 2^2 = 4 (False)
        // So, if s_l = '1', len can be at most 2.
        // This means r - l + 1 <= 2, or l >= r - 1.
        // So, l can be r or r-1.

        // If s[r] == '1', consider substrings ending at r that start with '1'.
        // These are s_l...s_r where s_l = '1'.
        // The maximum possible value for f(s_l...s_r) is 2^len - 1.
        // The minimum possible value for f(s_l...s_r) is 2^(len-1) (if s_l='1').
        // We need len = f(s_l...s_r).
        // Since len is at most 20, f(s_l...s_r) is at most 2^20 - 1, which fits in long long.

        // Iterate backwards from r to find potential starting positions l.
        // We only need to check a limited number of characters to the left of r.
        // The maximum length of a substring we need to check is about 20 (since 2^20 is approx 10^6,
        // and N is 2*10^5, so len cannot exceed N. Also, 2^len grows much faster than len).
        // Specifically, if len = f(s_l...s_r), then len <= 20 is sufficient because 2^20 > 2*10^5.
        // So, l must be at least r - 20 + 1.

        long long current_val = 0;
        for (int l = r; l >= std::max(0, r - 20); --l) { // Check up to 20 characters to the left
            int len = r - l + 1;
            if (s[l] == '1') {
                current_val = 0; // Reset value for this new substring starting at l
                for (int k = l; k <= r; ++k) {
                    current_val = (current_val << 1) | (s[k] - '0');
                }
                if (current_val == len) {
                    good_substrings_count++;
                }
            }
        }

        // Case 2: Substring starts with '0'
        // s_l...s_r, where s_l = '0'.
        // The value f(s_l...s_r) is the same as f(s_k...s_r) where s_k is the first '1' from the left.
        // If there is no '1' in s_l...s_r, then f(s_l...s_r) = 0.
        // In this case, we need len = 0, which is impossible as len >= 1.
        // So, there must be at least one '1' in the substring.
        // Let k be the index of the first '1' in s_l...s_r.
        // Then f(s_l...s_r) = f(s_k...s_r).
        // We need r - l + 1 = f(s_k...s_r).
        // Let val_k_r = f(s_k...s_r).
        // We need r - l + 1 = val_k_r.
        // This implies l = r - val_k_r + 1.
        // For this to be a valid starting position, we need:
        // 1. l >= 0
        // 2. s_l = '0' (unless l=k, which is handled by Case 1)
        // 3. All characters s_l, ..., s_{k-1} must be '0'.
        // 4. k must be the index of the first '1' in s_l...s_r.

        // Iterate over possible '1' positions k (the first '1' in the substring)
        // k must be <= r.
        // We only need to consider k such that r - k + 1 <= 20 (approx).
        // This is because val_k_r = f(s_k...s_r) is at most 2^(r-k+1)-1.
        // If val_k_r is large, then r - l + 1 = val_k_r implies l is very small.
        // The number of leading zeros is k - l.
        // The total length is r - l + 1.
        // The value is f(s_k...s_r).
        // We need r - l + 1 = f(s_k...s_r).
        // This means l = r - f(s_k...s_r) + 1.
        // We need to find k such that s_k = '1' and k <= r.
        // And for such k, calculate val_k_r = f(s_k...s_r).
        // Then calculate the required l_prime = r - val_k_r + 1.
        // If l_prime is a valid index, and s[l_prime...k-1] are all '0's, then we count it.

        // Find the first '1' at or before r.
        auto it = std::upper_bound(ones_indices.begin(), ones_indices.end(), r);
        if (it == ones_indices.begin()) {
            // No '1's up to r. All substrings ending at r are all '0's.
            // f(all_zeros) = 0. Length >= 1. No good substrings.
            continue;
        }
        --it; // Now *it is the index of the largest '1' <= r.

        // Iterate backwards from this '1' (k) to find potential first '1's of the substring.
        // We only need to check k such that r - k + 1 is small (up to ~20).
        // So k >= r - 20 + 1.
        for (int k_idx = std::distance(ones_indices.begin(), it); k_idx >= 0; --k_idx) {
            int k = ones_indices[k_idx];
            if (k < r - 20) { // Optimization: if k is too far left, r-k+1 > 20.
                              // Then f(s_k...s_r) will be too large to equal r-l+1.
                              // Specifically, f(s_k...s_r) >= 2^(r-k).
                              // If r-k > 20, then f(s_k...s_r) > 2^20 > 2*10^5.
                              // But r-l+1 <= N <= 2*10^5. So no match possible.
                break;
            }

            long long val_k_r = 0;
            for (int i = k; i <= r; ++i) {
                val_k_r = (val_k_r << 1) | (s[i] - '0');
            }

            // If val_k_r is too large, it cannot be equal to r-l+1.
            // r-l+1 <= N. If val_k_r > N, then no match.
            if (val_k_r > n) { // val_k_r > max possible length
                continue;
            }

            // Calculate the required starting position l_prime
            int l_prime = r - static_cast<int>(val_k_r) + 1;

            // Check conditions for l_prime:
            // 1. l_prime must be a valid index: 0 <= l_prime <= k.
            // 2. All characters s_l_prime, ..., s_{k-1} must be '0'.
            //    This means k - l_prime is the number of leading zeros.
            //    The number of leading zeros must be non-negative.
            //    If l_prime == k, then there are 0 leading zeros, and s_k is the first char.
            //    This case (l_prime == k) is handled by Case 1.
            //    So we are interested in l_prime < k.
            if (l_prime >= 0 && l_prime < k) {
                // Check if s_l_prime...s_{k-1} are all '0's.
                // This is equivalent to checking if there are no '1's in [l_prime, k-1].
                auto it_check = std::lower_bound(ones_indices.begin(), ones_indices.end(), l_prime);
                if (it_check == ones_indices.end() || *it_check >= k) {
                    // No '1' found in [l_prime, k-1], so all are '0's.
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << "\n";
}

