struct Operation {
    char type;
    int value;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Operation> ops(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> ops[i].type >> ops[i].value;
    }

    // Simulate the effect of the operations on two specific inputs: 0 and 1023.
    // We only care about bits 0-9.
    // Let's track the state of each bit position.
    // For each bit 'b' (0 to 9):
    //   'bit_0_val[b]' will store the final value of bit 'b' if the input bit 'b' was 0.
    //   'bit_1_val[b]' will store the final value of bit 'b' if the input bit 'b' was 1.

    // Initialize for input 0: all bits are 0.
    // Initialize for input 1: all bits are 1. (This is conceptual, we're tracking how an input bit 'b' affects output bit 'b')
    std::vector<int> bit_0_val(10); // Stores the final state of bit 'b' if initial bit 'b' was 0
    std::vector<int> bit_1_val(10); // Stores the final state of bit 'b' if initial bit 'b' was 1

    for (int b = 0; b < 10; ++b) {
        bit_0_val[b] = 0; // If input bit b is 0, it starts as 0
        bit_1_val[b] = 1; // If input bit b is 1, it starts as 1
    }

    for (const auto& op : ops) {
        for (int b = 0; b < 10; ++b) {
            int const_bit = (op.value >> b) & 1;
            if (op.type == '&') {
                bit_0_val[b] &= const_bit;
                bit_1_val[b] &= const_bit;
            } else if (op.type == '|') {
                bit_0_val[b] |= const_bit;
                bit_1_val[b] |= const_bit;
            } else { // '^'
                bit_0_val[b] ^= const_bit;
                bit_1_val[b] ^= const_bit;
            }
        }
    }

    // Now, for each bit 'b':
    // - If bit_0_val[b] == 0 and bit_1_val[b] == 0: The output bit 'b' is always 0, regardless of input bit 'b'.
    // - If bit_0_val[b] == 1 and bit_1_val[b] == 1: The output bit 'b' is always 1, regardless of input bit 'b'.
    // - If bit_0_val[b] == 0 and bit_1_val[b] == 1: The output bit 'b' is the same as the input bit 'b'.
    // - If bit_0_val[b] == 1 and bit_1_val[b] == 0: The output bit 'b' is the inverse of the input bit 'b'.

    // We need to find a sequence of at most 5 operations that achieves this.
    // A single AND, OR, XOR operation can be used to represent these transformations.
    // Let's try to combine them into a minimal set.

    // We can represent the final transformation for each bit 'b' as:
    // output_bit_b = (input_bit_b & A_b) | (B_b & ~input_bit_b)
    // This is equivalent to:
    // output_bit_b = (input_bit_b ^ C_b) & D_b | E_b
    // Or more simply, we can find a single AND, OR, XOR constant.

    // Let's try to find a single AND, OR, XOR constant that works for all bits.
    // This is not generally possible. For example, if bit 0 is inverted and bit 1 is passed through.

    // The problem states that the output program should return the same integer for all arguments from 0 to 1023.
    // This means we can determine the final state of each bit 'b' (0-9) based on its initial state.
    // Let's define three constants:
    // `and_mask`: bits that must be 1 for the output bit to be 1 (if input bit is 1)
    // `or_mask`: bits that must be 1 for the output bit to be 1 (if input bit is 0)
    // `xor_mask`: bits that flip the input bit

    // Let's find the combined effect on an initial value `x`.
    // The final value `y` can be expressed as:
    // `y = (x & final_and_val) | final_or_val`
    // This is not quite right.
    // A more general form for a single bit `b` is:
    // `y_b = (x_b & A_b) | (B_b & ~x_b)`
    // where `A_b = bit_1_val[b]` and `B_b = bit_0_val[b]`.
    // This can be rewritten as:
    // `y_b = (x_b ^ C_b) & D_b | E_b`
    // where `C_b = B_b`, `D_b = A_b ^ B_b ^ 1`, `E_b = B_b`.
    // This is `y_b = (x_b ^ B_b) & (A_b ^ B_b ^ 1) | B_b`.
    // This is equivalent to `y_b = (x_b ^ B_b) & (A_b | B_b) | B_b`.
    // No, this is `y_b = (x_b ^ B_b) & (A_b ^ B_b) | B_b` if `A_b` and `B_b` are 0 or 1.
    // Let's check:
    // If `x_b = 0`: `y_b = (0 ^ B_b) & (A_b ^ B_b) | B_b = B_b & (A_b ^ B_b) | B_b = B_b`. Correct.
    // If `x_b = 1`: `y_b = (1 ^ B_b) & (A_b ^ B_b) | B_b`.
    //   If `B_b = 0`: `y_b = (1 ^ 0) & (A_b ^ 0) | 0 = 1 & A_b = A_b`. Correct.
    //   If `B_b = 1`: `y_b = (1 ^ 1) & (A_b ^ 1) | 1 = 0 & (A_b ^ 1) | 1 = 0 | 1 = 1`. Correct.

    // So, the transformation for each bit `b` is `(x_b ^ B_b) & (A_b ^ B_b) | B_b`.
    // Let `XOR_CONST = B_b` for all bits `b`.
    // Let `AND_CONST = A_b ^ B_b` for all bits `b`.
    // Let `OR_CONST = B_b` for all bits `b`.
    // This means we can represent the final transformation as:
    // `(x ^ XOR_CONST) & AND_CONST | OR_CONST`
    // where `XOR_CONST` is the integer formed by `bit_0_val[b]` for each bit `b`.
    // `AND_CONST` is the integer formed by `bit_1_val[b] ^ bit_0_val[b]` for each bit `b`.
    // `OR_CONST` is the integer formed by `bit_0_val[b]` for each bit `b`.

    int final_xor_val = 0; // This will be the B_b part
    int final_and_val = 0; // This will be the A_b ^ B_b part
    int final_or_val = 0;  // This will be the B_b part

    for (int b = 0; b < 10; ++b) {
        if (bit_0_val[b] == 1) { // B_b = 1
            final_xor_val |= (1 << b);
            final_or_val |= (1 << b);
        }
        if (bit_1_val[b] != bit_0_val[b]) { // A_b ^ B_b = 1
            final_and_val |= (1 << b);
        }
    }

    // The final expression is `(x ^ final_xor_val) & final_and_val | final_or_val`.
    // We need to output this in at most 5 lines.
    // This can be done in 3 lines:
    // ^ final_xor_val
    // & final_and_val
    // | final_or_val

    std::vector<Operation> result_ops;
    if (final_xor_val != 0) {
        result_ops.push_back({'^', final_xor_val});
    }
    if (final_and_val != 1023) { // If final_and_val is 1023, it's equivalent to no AND operation for bits 0-9
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If final_or_val is 0, it's equivalent to no OR operation
        result_ops.push_back({'|', final_or_val});
    }

    // Special case: if all bits are mapped to 0, the result is always 0.
    // This happens if final_xor_val = 0, final_and_val = 0, final_or_val = 0.
    // (x ^ 0) & 0 | 0 = x & 0 | 0 = 0.
    // In this case, result_ops would be empty. We should output one '& 0' or '| 0' or '^ 0'
    // No, if final_xor_val=0, final_and_val=0, final_or_val=0, then result_ops is empty.
    // This means the output is always 0.
    // The expression (x ^ 0) & 0 | 0 simplifies to 0.
    // If result_ops is empty, it means the function always returns 0.
    // We can represent this with '& 0'.
    if (result_ops.empty()) {
        // Check if the function always returns 0.
        // This happens if for all b, bit_0_val[b] == 0 and bit_1_val[b] == 0.
        // In this case, final_xor_val = 0, final_and_val = 0, final_or_val = 0.
        // The expression (x ^ 0) & 0 | 0 evaluates to 0.
        // So, we can output '& 0'.
        result_ops.push_back({'&', 0});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.type << " " << op.value << std::endl;
    }

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies the logic as we can always assume the target is in the first quadrant
        // and n is the larger coordinate. The number of moves and diagonal moves will be the same.
        if (n < 0) n = -n;
        if (m < 0) m = -m;
        if (n < m) std::swap(n, m);

        // Case 1: k < n. It's impossible to reach (n, m) in k moves if k is less than the maximum coordinate.
        // This is because each move changes at most one coordinate by 1 (if moving axially) or both by 1 (if moving diagonally).
        // To reach (n, m) from (0,0), at least n moves are required to cover the x-distance, or m moves for y-distance.
        // So, at least max(n, m) moves are required. Since n >= m, at least n moves are required.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= n.
        // We can always reach (n, m) in n moves using n diagonal moves (e.g., (0,0) -> (1,1) -> ... -> (m,m) -> ... -> (n,m) if m=n).
        // Or, more generally, m diagonal moves to reach (m,m), then n-m axial moves to reach (n,m). Total n moves.
        // The remaining k - n moves must be "wasted" moves.
        // A wasted move is a pair of moves that cancel each other out, e.g., (x,y) -> (x+1,y) -> (x,y).
        // Each such pair of moves increases the total move count by 2 without changing the final position.
        //
        // Let's analyze the parity of coordinates and moves.
        // Each move changes the sum of coordinates (x+y) by 0, 1, or 2.
        // Each move changes the parity of x or y or both.
        //
        // Consider the parity of (n, m) and k.
        //
        // If (n - m) is even:
        // This means n and m have the same parity.
        // We can reach (n, m) from (0, 0) in n moves.
        // For example, m diagonal moves to reach (m, m).
        // Then n-m axial moves to reach (n, m).
        // Total moves: m + (n-m) = n.
        // The remaining k - n moves must be wasted.
        // If (k - n) is even, we can use (k - n) / 2 pairs of moves that cancel out.
        // Each pair can be two axial moves (e.g., (x,y) -> (x+1,y) -> (x,y)) or two diagonal moves (e.g., (x,y) -> (x+1,y+1) -> (x,y)).
        // If we use two axial moves, the number of diagonal moves doesn't change.
        // If we use two diagonal moves, the number of diagonal moves increases by 2.
        // To maximize diagonal moves, we should use diagonal moves for these wasted pairs.
        // So, if (k - n) is even, the maximum diagonal moves is k.
        //
        // If (n - m) is odd:
        // This means n and m have different parities.
        // We cannot reach (n, m) from (0, 0) in n moves if n and m have different parities.
        // Why? Consider the parity of x+y.
        // A diagonal move changes x+y by $\pm 2$ or $0$. So parity of x+y doesn't change.
        // An axial move changes x+y by $\pm 1$. So parity of x+y changes.
        // To reach (n,m) from (0,0), the parity of (x+y) must change from 0 to (n+m)%2.
        // This requires (n+m)%2 axial moves.
        //
        // A simpler way:
        // Consider the parity of the coordinates.
        // Each move changes the parity of x or y or both.
        // If we make $D$ diagonal moves and $A$ axial moves.
        // Final x-coordinate: $x_f = \sum \Delta x_i$.
        // Final y-coordinate: $y_f = \sum \Delta y_i$.
        //
        // Let's consider the parity of the target coordinates (n, m).
        // If n and m have different parities (i.e., (n-m) is odd), then (n+m) is odd.
        // If n and m have the same parity (i.e., (n-m) is even), then (n+m) is even.
        //
        // Consider the parity of k.
        // If k and (n+m) have different parities, it's impossible to reach (n,m) in k moves.
        // Why? Each move changes the parity of x or y.
        // If we make $k$ moves, the final coordinates $(x_k, y_k)$ will have $x_k \equiv k \pmod 2$ and $y_k \equiv k \pmod 2$ if all moves were axial.
        // If we make $k$ moves, the final coordinates $(x_k, y_k)$ will have $x_k \equiv y_k \pmod 2$ if all moves were diagonal.
        //
        // Let's use a known property:
        // The parity of (x+y) changes with each axial move, and stays the same with each diagonal move.
        // So, (n+m) % 2 must be equal to (number of axial moves) % 2.
        // Let $A$ be the number of axial moves. Then $A \equiv (n+m) \pmod 2$.
        // Total moves $k = D + A$.
        // So $k \equiv D + A \pmod 2$.
        // $k \equiv D + (n+m) \pmod 2$.
        //
        // We want to maximize $D$.
        // The minimum number of moves to reach (n, m) is $n$ (since $n \ge m$).
        // This can be achieved by $m$ diagonal moves and $n-m$ axial moves.
        // Total moves $n$. Number of diagonal moves $m$.
        //
        // If $k \ge n$:
        // We have $k-n$ "extra" moves.
        //
        // If $(k - n)$ is even:
        // We can use $(k-n)/2$ pairs of moves that cancel out.
        // Each pair can be two diagonal moves (e.g., (x,y) -> (x+1,y+1) -> (x,y)) or two axial moves.
        // To maximize diagonal moves, we use diagonal pairs.
        // So, we can make $k$ diagonal moves.
        // Example: (2,2) in 3 moves. n=2, m=2, k=3. n-m=0 (even). k-n=1 (odd).
        // This case falls into the next one.
        //
        // If $(k - n)$ is odd:
        // We have an odd number of extra moves.
        // We can't just add pairs of moves. We need to adjust.
        //
        // Consider the parity of $n$ and $m$.
        //
        // Case A: $n$ and $m$ have the same parity (i.e., $n-m$ is even).
        // The minimum moves to reach $(n,m)$ is $n$.
        // This path uses $m$ diagonal moves and $n-m$ axial moves.
        // The total number of moves is $n$.
        // The parity of $n$ is the same as the parity of $m$.
        // The parity of $n$ is the same as the parity of $n-m$.
        //
        // If $k$ has the same parity as $n$:
        // Then $k-n$ is even. We can add $(k-n)/2$ pairs of moves.
        // Each pair can be two diagonal moves.
        // So, we can make $k$ diagonal moves.
        // Example: (2,2) in 2 moves. n=2, m=2, k=2. n-m=0 (even). k-n=0 (even). Max diag = 2.
        // Example: (2,2) in 4 moves. n=2, m=2, k=4. n-m=0 (even). k-n=2 (even). Max diag = 4.
        //
        // If $k$ has different parity than $n$:
        // Then $k-n$ is odd. We cannot simply add pairs of moves.
        // We need to make one move that changes the parity of the total path length.
        // Consider the path of $n$ moves (m diagonal, n-m axial).
        // We need to add $k-n$ moves. Since $k-n$ is odd, we need to add an odd number of moves.
        // We can replace one diagonal move with three moves: (x,y) -> (x+1,y+1) -> (x,y+1) -> (x+1,y).
        // This changes the final position from (x+1,y+1) to (x+1,y). This is not good.
        //
        // A better way to think about it:
        // We need to reach (n,m) in k moves.
        // The maximum number of diagonal moves is $k$. This is possible if $k \ge n$ and $k \equiv n \pmod 2$.
        // If $k \ge n$ and $k \equiv n \pmod 2$, then we can make $n$ moves to reach $(n,m)$ (m diagonal, n-m axial).
        // The remaining $k-n$ moves are even. We can use $(k-n)/2$ pairs of diagonal moves that cancel out.
        // E.g., $(x,y) \to (x+1,y+1) \to (x,y)$. This uses 2 diagonal moves and returns to $(x,y)$.
        // So, total diagonal moves = $m + (k-n)$. This is not correct.
        // The $n$ moves to reach $(n,m)$ can be $n$ diagonal moves if $n=m$.
        // If $n \ne m$, we need $m$ diagonal moves and $n-m$ axial moves.
        //
        // Let's re-evaluate the parity condition.
        // The final coordinates $(n,m)$ must be reachable.
        // The minimum number of moves is $n$.
        // If $k < n$, impossible. Output -1.
        //
        // If $k \ge n$:
        // We have $k$ moves. We want to maximize diagonal moves.
        // The maximum possible diagonal moves is $k$.
        // This is achievable if we can reach $(n,m)$ using $k$ diagonal moves.
        // This means $n$ and $m$ must be reachable by $k$ diagonal moves.
        // If we make $k$ diagonal moves, the final coordinates $(x_k, y_k)$ will have $x_k \equiv y_k \pmod 2$.
        // So, if $n \not\equiv m \pmod 2$, we cannot make $k$ diagonal moves.
        //
        // Let's consider the parity of $n$ and $m$.
        //
        // If $n \equiv m \pmod 2$ (i.e., $n-m$ is even):
        // We can reach $(n,m)$ using $n$ moves.
        // For example, $m$ diagonal moves to $(m,m)$, then $n-m$ axial moves to $(n,m)$.
        // Total moves $n$.
        // The remaining $k-n$ moves must be "wasted".
        // If $k-n$ is even, we can add $(k-n)/2$ pairs of diagonal moves that cancel out.
        // E.g., $(x,y) \to (x+1,y+1) \to (x,y)$. Each such pair adds 2 diagonal moves.
        // So, the total diagonal moves would be $k$.
        // If $k-n$ is odd, this means $k$ and $n$ have different parities.
        // We cannot simply add pairs of moves.
