#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> v(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        v[i] = (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the left part (jars 1 to n)
    // P_L[k] = sum of v[0]...v[k-1]
    std::vector<int> p_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        p_left[i + 1] = p_left[i] + v[i];
    }

    // Calculate suffix sums for the right part (jars n+1 to 2n)
    // P_R[k] = sum of v[2n-1]...v[2n-k]
    std::vector<int> p_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        p_right[i + 1] = p_right[i] + v[2 * n - 1 - i];
    }

    // Map to store the minimum number of jars eaten from the left (k)
    // to achieve a certain balance (p_left[n] - p_left[k])
    // This is equivalent to p_left[k] for the remaining jars.
    // The balance of remaining jars (k+1 to n) is p_left[n] - p_left[k].
    // We want to find the minimum k for each balance.
    // The balance of jars 1 to k is p_left[k].
    // If we eat k jars from the left, the remaining jars are k+1 to n.
    // Their balance is p_left[n] - p_left[k].
    // We are interested in the balance of the *eaten* jars from the left.
    // Let's rephrase:
    // If we eat k jars from the left (jars 1 to k), the balance of these k jars is p_left[k].
    // We store the minimum k for each p_left[k].
    std::map<int, int> min_k_for_balance_left;
    for (int k = 0; k <= n; ++k) { // k is number of jars eaten from left
        int current_balance_eaten_left = p_left[k];
        if (min_k_for_balance_left.find(current_balance_eaten_left) == min_k_for_balance_left.end()) {
            min_k_for_balance_left[current_balance_eaten_left] = k;
        } else {
            min_k_for_balance_left[current_balance_eaten_left] = std::min(min_k_for_balance_left[current_balance_eaten_left], k);
        }
    }

    int min_total_eaten = 2 * n; // Initialize with max possible

    // Iterate over the number of jars eaten from the right (r)
    for (int r = 0; r <= n; ++r) { // r is number of jars eaten from right
        int current_balance_eaten_right = p_right[r];

        // The total balance of all 2n jars is p_left[n] + p_right[n].
        // Let B_total = p_left[n] + p_right[n].
        // If we eat k jars from left and r jars from right,
        // the balance of eaten jars is B_eaten = p_left[k] + p_right[r].
        // The balance of remaining jars is B_remaining = B_total - B_eaten.
        // We want B_remaining = 0, so B_total - B_eaten = 0, which means B_eaten = B_total.
        // So we need p_left[k] + p_right[r] = p_left[n] + p_right[n].
        // This means p_left[k] = (p_left[n] + p_right[n]) - p_right[r].

        int target_balance_eaten_left = (p_left[n] + p_right[n]) - current_balance_eaten_right;

        if (min_k_for_balance_left.count(target_balance_eaten_left)) {
            int k = min_k_for_balance_left[target_balance_eaten_left];
            min_total_eaten = std::min(min_total_eaten, k + r);
        }
    }

    std::cout << min_total_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

