                } else {
                    // prev_b is in an allowed range. We can choose current_b = prev_b.
                    current_b = prev_b;
                }
            } else { // The allowed range is [current_a, upper_bound_after_wrap] (no wrap)
                     // This means [current_a, m-1] and [0, upper_bound_after_wrap] overlap
                     // and cover the entire [0, m-1] range.
                     // So we can always set current_b = prev_b.
                current_b = prev_b;
            }
        }
        prev_b = current_b;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a_initial(n, LLONG_MAX); // a_initial[i] stores max_val - current_delta[i]
                                                  // which is an upper bound for A_0[i]

    // Process operations in reverse to find upper bounds for A_0[i]
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1: a[j] = a[j] + d
            // This operation adds d to a[j].
            // When we process in reverse, this means that the value of a[j] *before* this operation
            // was a[j] - d.
            // So, if we have an upper bound for A_0[j] based on operations *after* this one,
            // that upper bound applies to A_0[j] - d *before* this operation.
            // Thus, A_0[j] must be <= (current upper bound) + d.
            // We update the upper bound for A_0[j] by adding d.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (a_initial[j] != LLONG_MAX) { // Only update if it's not the initial LLONG_MAX
                    a_initial[j] += ops[i].val;
                }
            }
        } else {
            // Type 2: max(a[l..r]) = m
            // This means for all j in [l, r], a[j] <= m.
            // Since a[j] = A_0[j] + current_delta[j] (where current_delta[j] is sum of d's from ops 0 to i-1)
            // and we are processing in reverse, a_initial[j] currently holds an upper bound for A_0[j]
            // based on operations *after* this one.
            // So, A_0[j] must be <= m.
            // We take the minimum of the current upper bound and m.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a_initial[j] = std::min(a_initial[j], ops[i].val);
            }
        }
    }

    // Initialize A_0 with the derived upper bounds.
    // If an element has no type 2 constraints, its upper bound is LLONG_MAX.
    // We can pick 0 for such elements, as long as it satisfies |A_0[i]| <= 10^9.
    // The problem states |a_i| <= 10^9, which refers to the initial array.
    // So, if a_initial[j] is LLONG_MAX, we can set A_0[j] = 0.
    // Otherwise, A_0[j] = a_initial[j].
    // We must ensure A_0[j] <= 10^9.
    // The maximum possible value for m_i is 5*10^7.
    // The maximum possible value for d_i is 10^4.
    // There are 5000 operations.
    // So, a_initial[j] could be m_i + M*d_i, where M is number of type 1 ops.
    // 5*10^7 + 5000 * 10^4 = 5*10^7 + 5*10^7 = 10^8. This fits in 10^9.
    // The minimum possible value for m_i is -5*10^7.
    // The minimum possible value for d_i is -10^4.
    // So, a_initial[j] could be m_i + M*d_i, where M is number of type 1 ops.
    // -5*10^7 + 5000 * (-10^4) = -5*10^7 - 5*10^7 = -10^8. This fits in 10^9.
    // So, a_initial[j] will always be within [-10^9, 10^9] if it's not LLONG_MAX.
    for (int i = 0; i < n; ++i) {
        if (a_initial[i] == LLONG_MAX) {
            a_initial[i] = 0; // Default to 0 if no upper bound from type 2 ops
        }
    }

    // Verify the solution
    std::vector<long long> current_a = a_initial;
    std::vector<long long> delta(n, 0); // current_delta[j] = sum of d's applied to j

    for (const auto& op : ops) {
        if (op.type == 1) {
            // Apply type 1 operation to delta
            for (int j = op.l; j <= op.r; ++j) {
                delta[j] += op.val;
            }
        } else {
            // Verify type 2 operation
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, a_initial[j] + delta[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_initial[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and intermediate calculations to prevent overflow
// as a_i can be up to 10^9 and y can accumulate many such values.
// x is an index, so it fits in int, but intermediate x values can also be large.
// However, x is only used as an index or compared to n, so it's fine if it goes out of bounds.
// The problem states x <= 0 or x > n for termination.
// If x becomes very large, it will eventually exceed n.
// If x becomes very small (negative), it will eventually be <= 0.
// The critical part is that x must be a valid index (1 to n) to access a_x.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_val[0] is unused, a_val[1] corresponds to a_2, ..., a_val[n-1] corresponds to a_n.
    // This means a_val[k] stores a_{k+1} from the problem statement.
    // When we need a_x, we access a_val[x-1].
    std::vector<long long> a_val(n); 
    for (int i = 1; i < n; ++i) { // Read a_2 to a_n
        std::cin >> a_val[i];
    }

    // dp[i] will store the result for starting x=i.
    // dp[i] = {final_y, final_x}
    // We need to compute this for x_start = 1 to n-1.
    // The values a_x are only needed when x is in [1, n].
    // The values a_x are fixed for x >= 2.
    // For x=1, a_1 changes for each query.

    // We can use dynamic programming or memoization.
    // Let's define a state as (current_x, current_y).
    // The path taken depends only on current_x.
    // The total y accumulated depends on the path and the values a_x encountered.
    // Let's define dp[x] as a pair {final_y_increment, final_x_offset}
    // if we start at x and follow the path until termination or a cycle.
    // This is tricky because the path depends on a_x, which changes for x=1.

    // The problem structure suggests that if we start at x, we go to x + a_x, then to (x + a_x) - a_{x+a_x}.
    // Let's denote the value of a_x as `val_x`.
    // From x, we go to x + val_x, then to (x + val_x) - val_{x + val_x}.
    // The total y accumulated is val_x + val_{x + val_x}.
    // This is a chain of jumps.
    // x_curr -> x_curr + val_curr -> (x_curr + val_curr) - val_{x_curr + val_curr} -> ...
    // Let's define `next_x[k]` as the x value after two steps (add a_k, subtract a_{k+a_k}) starting from k.
    // Let `y_add[k]` be the y value added in these two steps.
    // `next_x[k] = k + a_k - a_{k+a_k}`
    // `y_add[k] = a_k + a_{k+a_k}`
    // This is only valid if k and k+a_k are within [1, n].

    // We can precompute results for starting positions x >= 2.
    // For x >= 2, a_x is fixed.
    // Let `memo[x]` store the pair {final_y, final_x} if starting at `x`.
    // `memo[x].first` is the total y accumulated.
    // `memo[x].second` is the final x value (0 or n+1 for termination).
    // We can use -1 for `memo[x].first` to indicate "not computed" or "cycle detected".

    std::vector<long long> memo_y(n + 1, -2); // -2 indicates not computed, -1 indicates cycle
    std::vector<long long> memo_x_final(n + 1, -2); // Final x value (0 or n+1 for termination)
    std::vector<bool> visiting(n + 1, false); // To detect cycles

    // Function to compute result for a given starting x (where a_x is fixed)
    // Returns {final_y, final_x}
    std::function<std::pair<long long, long long>(long long)> solve = 
        [&](long long current_x) -> std::pair<long long, long long> {

        if (current_x <= 0 || current_x > n) {
            return {0, current_x}; // Base case: already terminated, 0 y added, x is current_x
        }

        if (memo_y[current_x] != -2) { // Already computed or cycle detected
            if (memo_y[current_x] == -1) { // Cycle detected
                return {-1, -1}; // Propagate cycle
            }
            return {memo_y[current_x], memo_x_final[current_x]};
        }

        if (visiting[current_x]) { // Cycle detected
            memo_y[current_x] = -1; // Mark as cycle
            memo_x_final[current_x] = -1;
            return {-1, -1};
        }

        visiting[current_x] = true;

        long long val_at_x = a_val[current_x - 1]; // a_x

        // Step 1: x = x + val_at_x, y = y + val_at_x
        long long x_after_step1 = current_x + val_at_x;
        long long y_added_step1 = val_at_x;

        // Check termination after step 1
        if (x_after_step1 <= 0 || x_after_step1 > n) {
            visiting[current_x] = false;
            memo_y[current_x] = y_added_step1;
            memo_x_final[current_x] = x_after_step1;
            return {y_added_step1, x_after_step1};
        }

        long long val_at_x_after_step1 = a_val[x_after_step1 - 1]; // a_{x_after_step1}

        // Step 2: x = x - val_at_x_after_step1, y = y + val_at_x_after_step1
        long long x_after_step2 = x_after_step1 - val_at_x_after_step1;
        long long y_added_step2 = val_at_x_after_step1;

        // Recursively solve for the next state
        std::pair<long long, long long> next_res = solve(x_after_step2);

        visiting[current_x] = false;

        if (next_res.first == -1) { // Cycle detected in subsequent steps
            memo_y[current_x] = -1;
            memo_x_final[current_x] = -1;
            return {-1, -1};
        }

        long long total_y = y_added_step1 + y_added_step2 + next_res.first;
        long long final_x = next_res.second;

        memo_y[current_x] = total_y;
        memo_x_final[current_x] = final_x;
        return {total_y, final_x};
    };

    // Compute for all x from 2 to n
    for (int i = 2; i <= n; ++i) {
        solve(i);
    }

    // Now handle the queries for a_1 = i (1 <= i <= n-1)
    for (int i = 1; i < n; ++i) {
        long long current_a1 = i; // This is the value of a_1 for this run

        // Initial state: x=1, y=0
        // Step 1: x = 1 + current_a1, y = 0 + current_a1
        long long x_after_step1 = 1 + current_a1;
        long long y_added_step1 = current_a1;

        // Check termination after step 1
        if (x_after_step1 <= 0 || x_after_step1 > n) {
            std::cout << y_added_step1 << "\n";
            continue;
        }

        long long val_at_x_after_step1 = a_val[x_after_step1 - 1]; // a_{x_after_step1}

        // Step 2: x = x_after_step1 - val_at_x_after_step1, y = y_added_step1 + val_at_x_after_step1
        long long x_after_step2 = x_after_step1 - val_at_x_after_step1;
        long long y_added_step2 = val_at_x_after_step1;

        // Now use the precomputed results for x_after_step2
        std::pair<long long, long long> next_res;
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            next_res = {0, x_after_step2}; // Already terminated
        } else {
            next_res = {memo_y[x_after_step2], memo_x_final[x_after_step2]};
        }

        if (next_res.first == -1) { // Cycle detected
            std::cout << -1 << "\n";
        } else {
            std::cout << y_added_step1 + y_added_step2 + next_res.first << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool present;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].present = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].present) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].present = false; // This child is now cured and leaves the line

        long long current_v_effect = children[i].v;
        long long cumulative_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].present) {
                continue;
            }

            // Apply cumulative d effect from children who left earlier
            children[j].p -= cumulative_d_effect;

            // Apply v effect from the child currently being cured
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j's confidence dropped below zero
            if (children[j].p < 0) {
                children[j].present = false;
                cumulative_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = std::numeric_limits<long long>::max();
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // This is only possible if n >= 2. If n=1, there are no pairs.
    // If n=1, the problem statement says n >= 2.
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    if (n >= 2) {
        long long current_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[a[i].original_index] = 1;
            }
        }
    }

    // Case 2: The smallest element a[0] is in S1, and all other elements a[1...n-1] are in S2.
    // This is a specific partition strategy.
    // S1 = {a[0]}
    // S2 = {a[1], ..., a[n-1]}
    //
    // Possible f values:
    // 1. a_i + a_j for a_i, a_j in S2.
    //    min_same_S2 = a[1].value + a[2].value (if n >= 3)
    //    max_same_S2 = a[n-2].value + a[n-1].value (if n >= 3)
    // 2. a_i + a_j + h for a_i in S1, a_j in S2.
    //    min_diff = a[0].value + a[1].value + h
    //    max_diff = a[0].value + a[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same_S2, min_diff)
    // max_f = max(max_same_S2, max_diff)

    if (n >= 2) { // Need at least two elements for any f value.
        long long current_min_f = a[0].value + a[1].value + h; // min_diff
        long long current_max_f = a[0].value + a[n - 1].value + h; // max_diff

        if (n >= 3) { // If S2 has at least two elements
            current_min_f = std::min(current_min_f, a[1].value + a[2].value);
            current_max_f = std::max(current_max_f, a[n - 1].value + a[n - 2].value);
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    // Case 3: The largest element a[n-1] is in S1, and all other elements a[0...n-2] are in S2.
    // S1 = {a[n-1]}
    // S2 = {a[0], ..., a[n-2]}
    //
    // Possible f values:
    // 1. a_i + a_j for a_i, a_j in S2.
    //    min_same_S2 = a[0].value + a[1].value (if n >= 3)
    //    max_same_S2 = a[n-3].value + a[n-2].value (if n >= 3)
    // 2. a_i + a_j + h for a_i in S1, a_j in S2.
    //    min_diff = a[n-1].value + a[0].value + h
    //    max_diff = a[n-1].value + a[n-2].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same_S2, min_diff)
    // max_f = max(max_same_S2, max_diff)

    if (n >= 2) {
        long long current_min_f = a[n - 1].value + a[0].value + h; // min_diff
        long long current_max_f = a[n - 1].value + a[n - 2].value + h; // max_diff

        if (n >= 3) { // If S2 has at least two elements
            current_min_f = std::min(current_min_f, a[0].value + a[1].value);
            current_max_f = std::max(current_max_f, a[n - 2].value + a[n - 3].value);
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[n - 1].original_index] = 1;
            for (int i = 0; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    // Case 4: The smallest element a[0] is in S1, and the largest element a[n-1] is in S2.
    // All other elements a[1...n-2] are in S1.
    // S1 = {a[0], a[1], ..., a[n-2]}
    // S2 = {a[n-1]}
    //
    // Possible f values:
    // 1. a_i + a_j for a_i, a_j in S1.
    //    min_same_S1 = a[0].value + a[1].value (if n >= 3)
    //    max_same_S1 = a[n-3].value + a[n-2].value (if n >= 3)
    // 2. a_i + a_j + h for a_i in S1, a_j in S2.
    //    min_diff = a[0].value + a[n-1].value + h
    //    max_diff = a[n-2].value + a[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same_S1, min_diff)
    // max_f = max(max_same_S1, max_diff)

    if (n >= 2) {
        long long current_min_f = a[0].value + a[n - 1].value + h; // min_diff
        long long current_max_f = a[n - 2].value + a[n - 1].value + h; // max_diff

        if (n >= 3) { // If S1 has at least two elements
            current_min_f = std::min(current_min_f, a[0].value + a[1].value);
            current_max_f = std::max(current_max_f, a[n - 2].value + a[n - 3].value);
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[n - 1].original_index] = 2;
            for (int i = 0; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 1;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s_prefix and s_suffix.
    // We can form s_suffix + s_prefix.
    // We need to check if s_suffix + s_prefix is a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // Cut position i means s[0...i-1] and s[i...n-1]
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_new = s_suffix + s_prefix;
        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // With two cuts, we get three pieces: s_left, s_middle, s_right.
    // s = s_left + s_middle + s_right.
    // We can rearrange these pieces.
    // Since s is a palindrome, s[0...n/2-1] is the reverse of s[n/2+1...n-1] (if n is odd, middle char is s[n/2]).
