#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median (indices 0 to median_idx - 1)
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median (indices median_idx + 1 to n - 1)
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>
#include <map>

long long solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }
    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    std::vector<long long> unique_p;
    std::set<long long> p_set(p.begin(), p.end());
    for (long long val : p_set) {
        unique_p.push_back(val);
    }
    p = unique_p;
    m = p.size();

    std::vector<long long> unique_h;
    std::set<long long> h_set(h.begin(), h.end());
    for (long long val : h_set) {
        unique_h.push_back(val);
    }
    h = unique_h;
    n = h.size();

    std::vector<long long> all_coords;
    all_coords.reserve(n + m);
    for (long long val : h) all_coords.push_back(val);
    for (long long val : p) all_coords.push_back(val);
    std::sort(all_coords.begin(), all_coords.end());
    all_coords.erase(std::unique(all_coords.begin(), all_coords.end()), all_coords.end());

    std::map<long long, int> coord_to_idx;
    for (int i = 0; i < all_coords.size(); ++i) {
        coord_to_idx[all_coords[i]] = i;
    }

    std::vector<int> h_idx(n);
    for (int i = 0; i < n; ++i) {
        h_idx[i] = coord_to_idx[h[i]];
    }
    std::vector<int> p_idx(m);
    for (int i = 0; i < m; ++i) {
        p_idx[i] = coord_to_idx[p[i]];
    }

    int max_coord_idx = all_coords.size();

    auto check = [&](long long T) {
        std::vector<int> covered_until(n, -1); // covered_until[i] is the max index covered by head i
        std::vector<int> covered_from(n, max_coord_idx); // covered_from[i] is the min index covered by head i

        for (int i = 0; i < n; ++i) {
            long long current_h = h[i];
            long long current_h_idx = h_idx[i];

            // Option 1: Move left
            long long left_reach_val = current_h - T;
            int left_reach_idx = std::lower_bound(all_coords.begin(), all_coords.end(), left_reach_val) - all_coords.begin();
            covered_from[i] = std::min(covered_from[i], left_reach_idx);
            covered_until[i] = std::max(covered_until[i], (int)current_h_idx);

            // Option 2: Move right
            long long right_reach_val = current_h + T;
            int right_reach_idx = std::upper_bound(all_coords.begin(), all_coords.end(), right_reach_val) - all_coords.begin() - 1;
            covered_from[i] = std::min(covered_from[i], (int)current_h_idx);
            covered_until[i] = std::max(covered_until[i], right_reach_idx);
        }

        std::vector<int> dp(m + 1, max_coord_idx); // dp[i] = min_idx_of_head_that_covers_p[i-1]_and_all_previous_p
        dp[0] = -1; // Base case: all tracks before p[0] are covered (vacuously true)

        for (int i = 0; i < m; ++i) { // Iterate through target tracks p
            if (dp[i] == max_coord_idx) continue;

            int current_p_idx = p_idx[i];

            // Try to cover p[i] with an existing head
            for (int head_idx = 0; head_idx < n; ++head_idx) {
                if (covered_from[head_idx] <= current_p_idx && current_p_idx <= covered_until[head_idx]) {
                    // Head `head_idx` covers `p[i]`.
                    // If this head also covers `p[i-1]` (or `dp[i]` is -1), then it can extend the coverage.
                    // The condition `dp[i] <= covered_until[head_idx]` means that the head that covered `p[i-1]`
                    // (or the "virtual" head for dp[0]) can be extended to `p[i]` by `head_idx`.
                    // This is not quite right. `dp[i]` is the minimum starting index of a head that covers `p[i-1]` and all previous.
                    // We need to find a head `j` such that `covered_from[j] <= p_idx[i]` and `p_idx[i] <= covered_until[j]`.
                    // And `dp[i]` must be less than or equal to `covered_until[j]`.
                    // This means that the range `[dp[i], p_idx[i]]` must be covered.
                    // The head `j` must cover `p_idx[i]`.
                    // The range `[dp[i], p_idx[i]]` must be covered.
                    // If `dp[i]` is -1, it means all previous `p`s are covered. We just need to cover `p[i]`.
                    // If `dp[i]` is not -1, it means the previous `p`s were covered by a head starting at `dp[i]` or later.
                    // So we need to cover `[dp[i], p_idx[i]]`.
                    // A head `j` covers `[covered_from[j], covered_until[j]]`.
                    // If `covered_from[j] <= dp[i]` and `p_idx[i] <= covered_until[j]`, then head `j` covers the required range.
                    if (covered_from[head_idx] <= dp[i] && current_p_idx <= covered_until[head_idx]) {
                        dp[i+1] = std::min(dp[i+1], covered_from[head_idx]);
                    }
                }
            }

            // Try to cover p[i] by moving a head to cover a range [L, R]
            // This is the core logic for the DP state.
            // dp[i] is the minimum starting index of a head that covers p[i-1] and all previous p's.
            // We want to find a head `j` and a range `[L, R]` such that `L <= dp[i]` and `p_idx[i] <= R`.
            // The time taken for head `j` to cover `[L, R]` must be `T`.
            // This means `max(abs(h[j] - L), abs(h[j] - R)) <= T`.
            // This is equivalent to `h[j] - T <= L` and `R <= h[j] + T`.
            // So we need `h[j] - T <= L <= dp[i]` and `p_idx[i] <= R <= h[j] + T`.
            // Combining these, we need `h[j] - T <= dp[i]` and `p_idx[i] <= h[j] + T`.
            // This means `h[j] >= dp[i] - T` and `h[j] <= p_idx[i] + T`.
            // So we need to find a head `j` such that `h[j] - T <= all_coords[dp[i]]` and `all_coords[p_idx[i]] <= h[j] + T`.
            // This is `all_coords[h_idx[j]] - T <= all_coords[dp[i]]` and `all_coords[p_idx[i]] <= all_coords[h_idx[j]] + T`.
            // This is `all_coords[h_idx[j]] >= all_coords[dp[i]] - T` and `all_coords[h_idx[j]] <= all_coords[p_idx[i]] + T`.
            // Let's use the original coordinates for clarity.
            // We need to find a head `j` such that `h[j] >= all_coords[dp[i]] - T` and `h[j] <= all_coords[p_idx[i]] + T`.
            // And this head `j` must cover the range `[all_coords[dp[i]], all_coords[p_idx[i]]]`.
            // The time taken for head `j` to cover `[L, R]` is `max(abs(h[j] - L), abs(h[j] - R))`.
            // We need to cover `[all_coords[dp[i]], all_coords[p_idx[i]]]`.
            // So we need `max(abs(h[j] - all_coords[dp[i]]), abs(h[j] - all_coords[p_idx[i]])) <= T`.
            // This means `h[j] - T <= all_coords[dp[i]]` and `all_coords[p_idx[i]] <= h[j] + T`.
            // Or `h[j] >= all_coords[dp[i]] - T` and `h[j] <= all_coords[p_idx[i]] + T`.
            // This is equivalent to `h[j]` being in the range `[all_coords[dp[i]] - T, all_coords[p_idx[i]] + T]`.
            // We need to find if there exists such a head `j`.
            // If `dp[i]` is -1, it means we need to cover `p[i]` and previous are already covered.
            // So we need `max(abs(h[j] - p[i]), abs(h[j] - p[i])) <= T` which is `abs(h[j] - p[i]) <= T`.
            // This is `h[j] >= p[i] - T` and `h[j] <= p[i] + T`.
            // This is exactly what `covered_from[j] <= p_idx[i] <= covered_until[j]` checks.
            // So the first loop handles the case where `dp[i]` is -1.

            // For `dp[i] != -1`:
            // We need to cover the range `[all_coords[dp[i]], all_coords[p_idx[i]]]`.
            // Find a head `j` such that `max(abs(h[j] - all_coords[dp[i]]), abs(h[j] - all_coords[p_idx[i]])) <= T`.
            // This is equivalent to `h[j] - T <= all_coords[dp[i]]` AND `all_coords[p_idx[i]] <= h[j] + T`.
            // This means `h[j]` must be in the range `[all_coords[p_idx[i]] - T, all_coords[dp[i]] + T]`.
            // No, this is wrong. It's `h[j]` must be in `[all_coords[dp[i]] - T, all_coords[p_idx[i]] + T]`.
            // Let `L_val = all_coords[dp[i]]` and `R_val = all_coords[p_idx[i]]`.
            // We need `max(abs(h[j] - L_val), abs(h[j] - R_val)) <= T`.
            // This means `h[j] - T <= L_val` and `R_val <= h[j] + T`.
            // So `h[j] <= L_val + T` and `h[j] >= R_val - T`.
            // So we need a head `h[j]` in the range `[R_val - T, L_val + T]`.
            // Let's find the indices for these values.
            long long required_L_val = all_coords[dp[i]];
            long long required_R_val = all_coords[p_idx[i]];

            long long head_min_val = required_R_val - T;
            long long head_max_val = required_L_val + T;

            auto it_low = std::lower_bound(h.begin(), h.end(), head_min_val);
            auto it_high = std::upper_bound(h.begin(), h.end(), head_max_val);

            if (it_low != it_high) { // There is at least one head in the required range
                dp[i+1] = std::min(dp[i+1], (int)dp[i]); // This head covers the range starting from dp[i]
            }
        }

        return dp[m] != max_coord_idx;
    };

    long long low = 0, high = 2e10, ans = high; // Max possible diff is 10^10, so 2*10^10 is safe upper bound

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return ans;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::cout << solve() << std::endl;
    return 0;
}

