    // This corresponds to `l` (1-indexed) from `n` down to `1`.
    for (int x = n - 1; x >= 0; --x) {
        // Initialize `first_bad_r[x+1]` based on `first_bad_r[x+2]`.
        // If `s[x+1 ... r-1]` contains a bad triplet, then `s[x ... r-1]` also does.
        first_bad_r[x + 1] = first_bad_r[x + 2];

        // Check for new bad triplets starting at `x`.
        // `k` can range from 1 up to `(n-1-x)/2`.
        // `x+2k` must be less than `n`.
        // `x+2k <= n-1` => `2k <= n-1-x` => `k <= (n-1-x)/2`.
