#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <ranges>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of any permutation p, let's call it p_rev,
        // will have the same fingerprint as p.
        // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
        // F(p_rev) = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
        // These two multisets of sums are identical.
        // The problem guarantees a solution exists and p' != p.
        // If p is not a palindrome, then p_rev is different from p,
        // and thus p_rev is a valid solution.
        // If p is a palindrome, then p_rev is identical to p.
        // However, a permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2)
        // or it contains duplicate elements (e.g., [1,2,1] is not a permutation).
        // A permutation consists of distinct integers from 1 to n.
        // For p to be a palindrome, p_i must equal p_{n-i+1}.
        // If n is even, say n=4, p=[p_1, p_2, p_3, p_4].
        // For p to be a palindrome, p_1=p_4 and p_2=p_3.
        // But all elements must be distinct. This is impossible.
        // For example, if p_1=1, then p_4=1. But 1 can only appear once.
        // So, if n is even, no permutation can be a palindrome.
        // Thus, if n is even, reverse(p) is always different from p.

        // If n is odd, say n=3, p=[p_1, p_2, p_3].
        // For p to be a palindrome, p_1=p_3. This is impossible for a permutation.
        // The only element that doesn't have a pair is the middle element p_{(n+1)/2}.
        // So, for a permutation to be a palindrome, it would require p_i = p_{n-i+1} for i != (n+1)/2.
        // This means p_1=p_n, p_2=p_{n-1}, etc.
        // Since all elements must be distinct, this is impossible for any n >= 2.
        // Therefore, for any permutation p of length n >= 2, p is never a palindrome.
        // This means reverse(p) is always a different permutation from p.

        // So, simply reversing the given permutation p always yields a valid p'.
        std::ranges::reverse(p);
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

