#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only numbers up to 2048 are relevant for forming 2048
            counts[s_val]++;
        }
    }

    // Iterate through powers of two from smallest to 1024
    // 2048 is 2^11. We need to form 2^11.
    // The smallest power of two is 1 (2^0).
    // The largest power of two that can be merged to form 2048 is 1024 (2^10).
    // If we have 2048 initially, we win.
    // If we have two 1024s, we can merge them to 2048.
    // If we have two 512s, we can merge them to 1024, then use that 1024.
    // This process is greedy: always merge smallest available numbers to form larger ones.
    // We only care about forming 2048. Any number larger than 2048 is not useful.

    for (int p = 1; p < 2048; p *= 2) {
        if (counts[p] >= 2) {
            counts[p * 2] += counts[p] / 2;
        }
    }

    if (counts[2048] > 0) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

