void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else if (n == 2) {
        std::cout << 57 << "\n";
    } else if (n == 3) {
        std::cout << 239 << "\n";
    } else {
        // For n >= 4, we can construct a number starting with '2' and '3',
        // followed by (n-2) '7's.
        // The number will be 2377...7 (n-2 times '7').
        // This number is not divisible by 2 (it's odd).
        // This number is not divisible by 3 (sum of digits: 2+3+(n-2)*7 = 5 + 7n - 14 = 7n - 9.
        // If 7n-9 is divisible by 3, then n must be divisible by 3.
        // For example, if n=4, sum=19, not div by 3.
        // If n=5, sum=26, not div by 3.
        // If n=6, sum=33, div by 3.
        // So, 237...7 is not always a solution.

        // Let's use the pattern 23...39.
        // The number is 2 followed by (n-1) '3's.
        // Example: n=4 -> 2333.
        // Digits are 2, 3.
        // Not divisible by 2 (odd).
        // Sum of digits: 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        // If 3n-1 is divisible by 3, then -1 must be divisible by 3, which is false.
        // So, 23...3 is never divisible by 3.
        // This pattern works for n >= 2.
        // For n=2: 23.
        // For n=3: 233.
        // For n=4: 2333.
        // This is a valid construction for n >= 2.
        // Since n=2 and n=3 have specific outputs in the example,
        // we can use this for n >= 4.
        // The problem asks for *any* solution.

        // The example output for n=4 is 6789.
        // Let's try to construct a number with 2 followed by (n-1) 3s.
        // This works for n >= 2.
        // For n=2: 23.
        // For n=3: 233.
        // For n=4: 2333.
        // This is a valid solution.

        // Let's stick to a simple pattern that works for all n >= 2.
        // A number consisting of '2' followed by (n-1) '3's.
        // Example: n=2 -> 23. Digits: 2, 3. Not div by 2 (odd). Not div by 3 (sum=5). Valid.
        // Example: n=3 -> 233. Digits: 2, 3. Not div by 2 (odd). Not div by 3 (sum=8). Valid.
        // Example: n=4 -> 2333. Digits: 2, 3. Not div by 2 (odd). Not div by 3 (sum=11). Valid.
        // This pattern works for all n >= 2.
        // The problem statement gives specific outputs for n=2, n=3, n=4.
        // My pattern gives 23, 233, 2333.
        // The example gives 57, 239, 6789.
        // Since "any solution" is fine, my pattern is valid.

        // Print '2'
        std::cout << '2';
        // Print (n-1) '3's
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << "\n";
    }
}

