void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the last element's price
    int min_suffix = a[n - 1];

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        // If the current price is greater than the minimum price found so far in the suffix,
        // then this price is "bad".
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If the current price is not greater than min_suffix, it means
            // a[i] <= min_suffix. This a[i] now becomes the new minimum
            // for the suffix starting from this position.
            min_suffix = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

