#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it means the actual value for that position
    // should be n, because n-1 is the maximum possible value for min(p_i, p_j) if p_i is n.
    // If p_i is n, then min(p_i, p_j) = p_j. The maximum of these p_j's (for j != i) would be n-1.
    // So, if max_val_in_row is n-1, it implies p_i must be n.
    // This is because the permutation contains values from 1 to n.
    // If p_i was not n, then max_val_in_row would be at most p_i - 1 (if p_i is not n, then n is somewhere else).
    // If p_i is n, then max_val_in_row = max_{j!=i} p_j = n-1.
    // If p_i is not n, then max_val_in_row <= p_i.
    // If max_val_in_row is n-1, then p_i must be n.
    // If max_val_in_row is less than n-1, then p_i is max_val_in_row.
    // This logic is sound because the problem guarantees a solution exists and p is a permutation of 1 to n.
    // The only value that can be 'missing' from the max_val_in_row calculation is 'n' itself.
    // If p_i is 'n', then max_val_in_row will be 'n-1' (the largest value among other p_j's).
    // For any other p_i < n, max_val_in_row will be p_i (if p_i is the largest among p_i and all p_j's)
    // or some p_j (if p_j is larger than p_i). But since p_i is the value we are trying to find,
    // and a_ij = min(p_i, p_j), then max_j(a_ij) = p_i if p_i is smaller than all other p_j's,
    // or p_i if p_i is larger than some p_j's but smaller than others.
    // The key insight is that if p_i is the largest value (n), then max_{j!=i} min(p_i, p_j) = max_{j!=i} p_j = n-1.
    // For any other p_i < n, max_{j!=i} min(p_i, p_j) will be p_i.
    // This is because there must be some p_j > p_i (specifically, n is somewhere else).
    // So, max_{j!=i} min(p_i, p_j) = p_i.
    // The only exception is when p_i = n.
    // So, if max_val_in_row is n-1, then p_i must be n. Otherwise, p_i is max_val_in_row.

    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1) {
            bool n_is_present = false;
            for (int k = 0; k < n; ++k) {
                if (p[k] == n) {
                    n_is_present = true;
                    break;
                }
            }
            if (!n_is_present) { // If n is not yet assigned to any p[k]
                p[i] = n;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted skill levels be b_0, b_1, ..., b_{2n-1}.
        //
        // Consider a partition where Class A has k students and Class B has 2n-k students.
        // Both k and 2n-k must be odd.
        //
        // The median of a class of size S is the element at index (S-1)/2 in its sorted list.
        //
        // It can be proven that the optimal strategy is to assign the smallest n elements
        // to one class and the largest n elements to the other class, or more generally,
        // to split the sorted array into two contiguous blocks.
        //
        // However, the problem statement implies we can pick any students for any class.
        //
        // Let's consider the sorted array a_0, a_1, ..., a_{2n-1}.
        //
        // If we pick a class of size S_A, its median will be some a_i.
        // If we pick a class of size S_B, its median will be some a_j.
        //
        // The key insight for this type of problem is often that the optimal medians
        // will be "close" in the sorted array.
        //
        // Consider the case where n=1. We have 2 students.
        // Class A must have 1 student, Class B must have 1 student.
        // The medians are a[0] and a[1]. The difference is a[1] - a[0].
        //
        // Consider the case where n=2. We have 4 students.
        // Possible odd sizes: (1,3) or (3,1).
        // If Class A has 1 student, its median is that student's skill.
        // If Class B has 3 students, its median is the middle student's skill.
        //
        // The problem statement is a bit tricky. "each class has odd number of students".
        //
        // Let's re-read the example for n=3 (6 students).
        // Skills: 1 2 3 4 5 6.
        // One partition: Class A = [6, 4, 2], median 4. Class B = [5, 1, 3], median 3. Diff = 1.
        //
        // The crucial observation for this problem is that to minimize the difference between medians,
        // we should make the medians as close as possible.
        //
        // If we sort all $2n$ students: $a_0, a_1, \dots, a_{2n-1}$.
        //
        // Consider the case where Class A has $S_A$ students and Class B has $S_B$ students.
        // $S_A$ and $S_B$ are odd.
        // The median of Class A will be the $((S_A-1)/2)$-th element in its sorted list.
        // The median of Class B will be the $((S_B-1)/2)$-th element in its sorted list.
        //
        // The minimum possible value for $S_A$ or $S_B$ is 1.
        // The maximum possible value for $S_A$ or $S_B$ is $2n-1$.
        //
        // If we choose $S_A = 2k_A+1$ and $S_B = 2k_B+1$, then $2k_A+1 + 2k_B+1 = 2n$,
        // which means $2(k_A+k_B+1) = 2n$, so $k_A+k_B+1 = n$.
        // The median of Class A is its $(k_A)$-th element (0-indexed).
        // The median of Class B is its $(k_B)$-th element (0-indexed).
        //
        // The problem is equivalent to finding two students, say student $i$ and student $j$,
        // such that $a_i$ is the median of Class A and $a_j$ is the median of Class B,
        // and $|a_i - a_j|$ is minimized.
        //
        // For $a_i$ to be the median of Class A (size $2k_A+1$), there must be $k_A$ students
        // in Class A with skill $\le a_i$ and $k_A$ students with skill $\ge a_i$.
        // Similarly for $a_j$ and Class B (size $2k_B+1$).
        //
        // The crucial observation is that the problem asks for the minimum difference.
        // This minimum difference is achieved when the two medians are $a_{n-1}$ and $a_n$.
        //
        // Let's try to prove this.
        // Suppose we pick $a_i$ as the median of Class A and $a_j$ as the median of Class B.
        // Without loss of generality, assume $i < j$.
        //
        // For $a_i$ to be the median of Class A, Class A must contain $k_A$ elements smaller than or equal to $a_i$,
        // and $k_A$ elements greater than or equal to $a_i$.
        // For $a_j$ to be the median of Class B, Class B must contain $k_B$ elements smaller than or equal to $a_j$,
        // and $k_B$ elements greater than or equal to $a_j$.
        //
        // The total number of elements smaller than $a_i$ is $i$.
        // The total number of elements greater than $a_j$ is $(2n-1) - j$.
        //
        // To make $a_i$ the median of Class A, we need to select $k_A$ elements from $a_0, \dots, a_{i-1}$
        // and $k_A$ elements from $a_{i+1}, \dots, a_{2n-1}$.
        //
        // This problem is a known variant. The minimum difference between medians of two odd-sized partitions
        // is always achieved by taking $a_{n-1}$ and $a_n$ as the medians.
        //
        // Let's verify this.
        // We need to form two classes, each of odd size.
        // Let Class A have $S_A$ students and Class B have $S_B$ students.
        // $S_A = 2k_A+1$, $S_B = 2k_B+1$.
        // $k_A+k_B+1 = n$.
        //
        // We want to show that we can always form two classes such that $a_{n-1}$ is the median of one and $a_n$ is the median of the other.
        //
        // Consider Class A with $a_{n-1}$ as its median.
        // We need to pick $k_A$ elements smaller than $a_{n-1}$ and $k_A$ elements larger than $a_{n-1}$.
        // The elements $a_0, \dots, a_{n-2}$ are smaller than or equal to $a_{n-1}$. There are $n-1$ such elements.
        // The elements $a_n, \dots, a_{2n-1}$ are larger than or equal to $a_n$. There are $n$ such elements.
        //
        // Let's try to construct the classes.
        //
        // Class A: $a_{n-1}$ is the median.
        // We need to pick $k_A$ elements from $a_0, \dots, a_{n-2}$ (left of $a_{n-1}$)
        // and $k_A$ elements from $a_n, \dots, a_{2n-1}$ (right of $a_{n-1}$).
        //
        // Class B: $a_n$ is the median.
        // We need to pick $k_B$ elements from $a_0, \dots, a_{n-1}$ (left of $a_n$)
        // and $k_B$ elements from $a_{n+1}, \dots, a_{2n-1}$ (right of $a_n$).
        //
        // The simplest partition is to make $k_A = 0$ and $k_B = n-1$.
        // Class A has size $2(0)+1 = 1$. Its median is $a_{n-1}$.
        // Class B has size $2(n-1)+1 = 2n-1$. Its median is $a_n$.
        //
        // Can we form Class A with $a_{n-1}$ as its median and size 1? Yes, just take $\{a_{n-1}\}$.
        // Can we form Class B with $a_n$ as its median and size $2n-1$?
        // We need to pick $n-1$ elements smaller than $a_n$ and $n-1$ elements larger than $a_n$.
        // The remaining students are $a_0, \dots, a_{n-2}$ and $a_{n+1}, \dots, a_{2n-1}$.
        // There are $n-1$ students $a_0, \dots, a_{n-2}$.
        // There are $n-1$ students $a_{n+1}, \dots, a_{2n-1}$.
        // So we can form Class B as $\{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This class has $ (n-1) + 1 + (n-1) = 2n-1$ students.
        // Its median is $a_n$.
        //
        // This construction is valid.
        // Class A = $\{a_{n-1}\}$ (size 1, median $a_{n-1}$)
        // Class B = $\{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$ (size $2n-1$, median $a_n$)
        // All students are assigned. Each class has an odd number of students.
        // The absolute difference is $|a_n - a_{n-1}|$.
        //
        // Since $a_n$ and $a_{n-1}$ are adjacent in the sorted array, their difference is the minimum possible
        // difference between any two elements $a_i, a_j$ such that $i < j$.
        // Any other choice of medians $a_p, a_q$ with $p < q$ would result in $|a_q - a_p| \ge |a_n - a_{n-1}|$
        // if $p \le n-1$ and $q \ge n$.
        // If $p, q < n$, then $a_q - a_p \le a_{n-1} - a_0$.
        // If $p, q \ge n$, then $a_q - a_p \le a_{2n-1} - a_n$.
        //
        // The problem is asking for the minimum possible absolute difference between medians.
        // The medians must be chosen from the $2n$ students.
        // Let $M_1$ be the median of class 1 and $M_2$ be the median of class 2.
        // We want to minimize $|M_1 - M_2|$.
        //
        // The crucial point is that the $n$-th smallest element ($a_{n-1}$ in 0-indexed) and the $(n+1)$-th smallest element ($a_n$ in 0-indexed)
        // are the "middle" two elements of the entire sorted $2n$ students.
        //
        // The minimum difference is indeed $a_n - a_{n-1}$.
        //
        // Example 1: n=1, a = [1, 1]. Sorted: [1, 1].
        // n-1 = 0, n = 1.
        // a[1] - a[0] = 1 - 1 = 0. Correct.
        //
        // Example 2: n=3, a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // n-1 = 2, n = 3.
        // a[3] - a[2] = 4 - 3 = 1. Correct.
        //
        // Example 3: n=5, a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16]. Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // n-1 = 4, n = 5.
        // a[5] - a[4] = 13 - 8 = 5. Correct.
        //
        // The logic seems solid. Sort the array and output a[n] - a[n-1].

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available: (c + m + x) / 3
        // 2. The number of coders available: c
        // 3. The number of mathematicians available: m
        // So, an initial upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'low' for binary search.
        // The actual answer 'ans' will be between 0 and this value.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams, we need 'mid' coders and 'mid' mathematicians
            // as a minimum.
            // The remaining students (c - mid) coders, (m - mid) mathematicians,
            // and x students without specialization can be used as the third member
            // for the 'mid' teams.
            // Each of the 'mid' teams needs one 'third member'.
            // So, we need at least 'mid' students to fill these 'third member' slots.
            // The total number of students available for these 'third member' slots is:
            // (c - mid) + (m - mid) + x

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                // If we have enough coders, mathematicians, and enough
                // remaining students to fill the third slots for 'mid' teams,
                // then 'mid' teams are possible.
                // We try to achieve more teams.
                ans = mid;
                low = mid + 1;
            } else {
                // 'mid' teams are not possible. Try fewer teams.
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

