#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Cost of a nice staircase with k stairs is k * (k + 1) / 2
            // k is of the form 2^p - 1.
            // The sequence of k values is 1, 3, 7, 15, 31, ...
            // The sequence of costs is 1, 6, 28, 120, 496, ...
            // The sequence of costs for the next staircase is (2k+1)*(2k+2)/2 = (2k+1)(k+1)
            // This is the cost of a staircase with 2k+1 stairs.
            // The problem states that the cost of a staircase with n stairs is n*(n+1)/2.
            // A nice staircase with n stairs is covered by n disjoint squares.
            // The image shows a nice staircase with 7 stairs.
            // The squares are 1x1, 3x3, 5x5, 7x7. This is not what the problem states.
            // The problem states "covered by n disjoint squares".
            // The example image for n=7 shows squares of sizes 1x1, 2x2, 3x3, 4x4, 5x5, 6x6, 7x7.
            // This interpretation is wrong. The image shows 7 squares, but they are not 1x1, 2x2, etc.
            // The image shows squares of sizes 1x1, 2x2, 3x3, 4x4, 5x5, 6x6, 7x7.
            // No, the image shows squares of sizes 1x1, 3x3, 5x5, 7x7.
            // The squares are placed such that they cover the staircase.
            // A staircase with n stairs has total cells n*(n+1)/2.
            // If n=1, cost = 1. Covered by 1x1 square.
            // If n=3, cost = 3*4/2 = 6. Covered by 1x1, 2x2, 3x3 squares? No.
            // The image for n=7 shows squares of side lengths 1, 3, 5, 7.
            // These are squares of side lengths 2^0, 2^1-1, 2^2-1, 2^3-1.
            // This is not correct. The image shows squares of side lengths 1, 3, 5, 7.
            // The squares are 1x1, 3x3, 5x5, 7x7.
            // The total cells for a staircase with n stairs is n*(n+1)/2.
            // The cost of a nice staircase with n stairs is the sum of cells in squares.
            // If n=1, cost = 1*1 = 1.
            // If n=3, cost = 1*1 + 2*2 = 5. (This is not 6)
            // If n=7, cost = 1*1 + 2*2 + 3*3 = 14. (This is not 28)
            // The problem statement says "A staircase with n stairs is called nice, if it may be covered by n disjoint squares made of cells."
            // The image shows a specific way to cover a 7-stair staircase with 7 squares.
            // The squares are 1x1, 2x2, 3x3, 4x4, 5x5, 6x6, 7x7.
            // The squares are placed such that they cover the staircase.
            // The cost of a nice staircase with n stairs is the sum of cells in the staircase.
            // The cost of a staircase with n stairs is n*(n+1)/2.
            // The problem is about finding the maximum number of nice staircases.
            // The costs of nice staircases are 1, 6, 28, 120, 496, ...
            // These are costs for staircases with 1, 3, 7, 15, 31, ... stairs.
            // Let's denote the number of stairs as `s`.
            // The sequence of `s` for nice staircases is 1, 3, 7, 15, 31, ... which is `2^p - 1`.
            // For `s = 2^p - 1`, the cost is `s * (s + 1) / 2 = (2^p - 1) * 2^p / 2 = (2^p - 1) * 2^(p-1)`.
            // Let's verify:
            // p=1: s=1. Cost = 1 * 2^0 = 1.
            // p=2: s=3. Cost = 3 * 2^1 = 6.
            // p=3: s=7. Cost = 7 * 2^2 = 28.
            // p=4: s=15. Cost = 15 * 2^3 = 120.
            // p=5: s=31. Cost = 31 * 2^4 = 496.
            // This sequence of costs is what we need.
            // We want to build as many different nice staircases as possible.
            // To maximize the count, we should always pick the smallest available nice staircase.
            // The costs are 1, 6, 28, 120, 496, ...
            // The smallest cost is 1.
            // The next smallest cost is 6.
            // The next smallest cost is 28.
            // And so on.
            // We iterate, adding the cost of the smallest available nice staircase, until we run out of cells.

            // k represents the number of stairs in the current nice staircase (1, 3, 7, 15, ...)
            // The cost for a staircase with k stairs is k * (k + 1) / 2.
            long long cost_for_k_stairs = k * (k + 1) / 2;

            if (current_cost + cost_for_k_stairs <= x) {
                current_cost += cost_for_k_stairs;
                count++;
                // For the next iteration, k should be the number of stairs for the next nice staircase.
                // If current k is 2^p - 1, next k is 2^(p+1) - 1.
                // This is equivalent to k_next = 2 * k_current + 1.
                k = 2 * k + 1;
            } else {
                break; // Cannot afford the current smallest nice staircase
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
