int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m > n) {
        return 0;
    }

    long long k = n / m; // Number of multiples of m up to n

    // Calculate the sum of last digits for one full cycle of 10 multiples of m
    // i.e., (m*1)%10 + (m*2)%10 + ... + (m*10)%10
    long long cycle_sum = 0;
    for (int i = 1; i <= 10; ++i) {
        cycle_sum += (m * i) % 10;
    }

    // Number of full cycles of 10 multiples
    long long num_full_cycles = k / 10;

    // Sum from full cycles
    long long total_sum = num_full_cycles * cycle_sum;

    // Add the sum for the remaining multiples
    // These are (m * (num_full_cycles * 10 + 1)) % 10, ..., (m * k) % 10
    // Which is equivalent to (m * 1) % 10, ..., (m * (k % 10)) % 10
    for (long long i = 1; i <= (k % 10); ++i) {
        total_sum += (m * i) % 10;
    }

    return total_sum;
}

