#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-increasing.
    // This means a[p] >= a[p+1] >= ... >= a[n-1].
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // If p is 0, the entire array is non-increasing.
    // This means a[0...n-1] is non-increasing.
    // In this case, we can pick elements from right to left to form a non-decreasing sequence.
    // So, the array is good, and we erase 0 elements.
    if (p == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Now, a[p-1] < a[p].
    // We need to find the rightmost index `q` such that a[q...p-1] is non-decreasing.
    // This means a[q] <= a[q+1] <= ... <= a[p-1].
    // Note that a[p-1] is the peak.
    // We are looking for the start of the "valley" before the peak.
    int q = p - 1;
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }

    // The elements from index `q` to `n-1` form the suffix we are interested in.
    // The prefix to erase has length `q`.
    std::cout << q << std::endl;
}

