#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // If d < 4 (and d > 0), there are no real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Quadratic equation: a^2 - d*a + d = 0
            // Solutions for a: (d +/- sqrt(d^2 - 4d)) / 2
            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a, b >= 0.
            // Since d >= 4, d^2 - 4d >= 0, so sqrt_discriminant is real.
            // Also, d >= sqrt(d^2 - 4d) because d^2 >= d^2 - 4d (since 4d >= 0).
            // So, d - sqrt_discriminant >= 0.
            // Thus, both a1 and b1 are non-negative.
            // We can print either (a1, b1) or (b1, a1).
            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // For 0-indexed array, this is the middle element

    // The median element a[median_idx] must become s.
    // Cost for this is abs(a[median_idx] - s).
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median (a[0]...a[median_idx-1])
    // must be <= s. If any a[i] > s, we must decrease it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median (a[median_idx+1]...a[n-1])
    // must be >= s. If any a[i] < s, we must increase it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

