int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());

    int count = 0;
    int left_ptr = 0; // Pointer for the elements we are trying to "beat" (smaller elements)
    int right_ptr = 0; // Pointer for the elements we are using to "beat" (larger elements)

    while (right_ptr < n) {
        // If the current element a[right_ptr] is greater than a[left_ptr],
        // we can use a[right_ptr] to replace a[left_ptr].
        // This increases our count of successful replacements.
        // Then we move both pointers forward.
        if (a[right_ptr] > a[left_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[right_ptr] is not greater than a[left_ptr],
            // we cannot use a[right_ptr] to replace a[left_ptr] to satisfy the condition.
            // We must try a larger element for a[left_ptr].
            // So, we only move right_ptr forward to find a potentially larger element.
            right_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the minimum possible values for the left increasing part
    // b[i] = minimum value a[i] can take to satisfy a[0] < a[1] < ... < a[i]
    // assuming a[0] = 0.
    // So, b[i] = i.
    // We must have a[i] >= b[i] for all i.
    // If a[i] < i for any i, it's impossible to make a[i] >= i.
    // This means we need a[i] >= i for all i in the increasing part.
    // Let's find the first index `i` from the left where `a[i] < i`.
    // If such an `i` exists, then `a[0], ..., a[i]` cannot form a strictly increasing sequence
    // starting from 0, because `a[i]` would need to be at least `i`.
    // So, the increasing part can only extend up to `i-1`.
    int left_limit = n;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_limit = i;
            break;
        }
    }

    // Calculate the minimum possible values for the right decreasing part
    // c[i] = minimum value a[i] can take to satisfy a[i] > a[i+1] > ... > a[n-1]
    // assuming a[n-1] = 0.
    // So, c[i] = (n-1) - i.
    // We must have a[i] >= c[i] for all i.
    // If a[i] < (n-1)-i for any i, it's impossible to make a[i] >= (n-1)-i.
    // This means we need a[i] >= (n-1)-i for all i in the decreasing part.
    // Let's find the first index `i` from the right where `a[i] < (n-1)-i`.
    // If such an `i` exists, then `a[i], ..., a[n-1]` cannot form a strictly decreasing sequence
    // ending at 0, because `a[i]` would need to be at least `(n-1)-i`.
    // So, the decreasing part can only extend up to `i+1`.
    int right_limit = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1) - i) {
            right_limit = i;
            break;
        }
    }

    // For an array to be sharpened, there must exist a peak `k` (1-indexed)
    // such that a_1 < ... < a_k and a_k > ... > a_n.
    // In 0-indexed, this means a_0 < ... < a_{k-1} and a_{k-1} > ... > a_{n-1}.
    // The peak index is `k-1`.
    //
    // The left part `a_0, ..., a_{k-1}` must satisfy `a_i >= i` for all `0 <= i <= k-1`.
    // This means `k-1` must be less than `left_limit`. So `k <= left_limit`.
    //
    // The right part `a_{k-1}, ..., a_{n-1}` must satisfy `a_i >= (n-1)-i` for all `k-1 <= i <= n-1`.
    // This means `k-1` must be greater than `right_limit`. So `k-1 > right_limit`.
    //
    // Combining these, we need to find a `k-1` (0-indexed peak) such that:
    // `k-1 < left_limit` AND `k-1 > right_limit`.
    // This is equivalent to `right_limit < k-1 < left_limit`.
    // Such a `k-1` exists if and only if `right_limit < left_limit - 1`.
    // Or, `right_limit + 1 < left_limit`.
    //
    // Example: n=6, a = [100, 11, 15, 9, 7, 8]
    // left_limit:
    // a[0]=100 >= 0
    // a[1]=11 >= 1
    // a[2]=15 >= 2
    // a[3]=9 >= 3
    // a[4]=7 >= 4
    // a[5]=8 >= 5
    // No a[i] < i. So left_limit = 6.
    //
    // right_limit: (n-1)-i
    // i=5: a[5]=8 >= (6-1)-5 = 0
    // i=4: a[4]=7 >= (6-1)-4 = 1
    // i=3: a[3]=9 >= (6-1)-3 = 2
    // i=2: a[2]=15 >= (6-1)-2 = 3
    // i=1: a[1]=11 >= (6-1)-1 = 4
    // i=0: a[0]=100 >= (6-1)-0 = 5
    // No a[i] < (n-1)-i. So right_limit = -1.
    //
    // Check condition: right_limit < left_limit - 1
    // -1 < 6 - 1  => -1 < 5. This is true. So "Yes".
    //
    // Example: n=4, a = [0, 1, 1, 0]
    // left_limit:
    // a[0]=0 >= 0
    // a[1]=1 >= 1
    // a[2]=1 < 2. So left_limit = 2.
    //
    // right_limit: (n-1)-i
    // i=3: a[3]=0 >= (4-1)-3 = 0
    // i=2: a[2]=1 >= (4-1)-2 = 1
    // i=1: a[1]=1 < (4-1)-1 = 2. So right_limit = 1.
    //
    // Check condition: right_limit < left_limit - 1
    // 1 < 2 - 1 => 1 < 1. This is false. So "No".

    if (right_limit < left_limit - 1) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
