struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    // Create the result array A'
    std::vector<long long> a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th element of sorted B (b_elements[i]) corresponds to
        // the i-th element of sorted A (a_elements[i]).
        // The original index of b_elements[i] tells us where this pair should go in A'.
        a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation_prefix(const std::vector<int>& a, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (a[i] < 1 || a[i] > len) {
            return false;
        }
        if (seen[a[i]]) {
            return false;
        }
        seen[a[i]] = true;
        if (a[i] > max_val) {
            max_val = a[i];
        }
    }
    return max_val == len;
}

bool is_permutation_suffix(const std::vector<int>& a, int start_idx, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (a[start_idx + i] < 1 || a[start_idx + i] > len) {
            return false;
        }
        if (seen[a[start_idx + i]]) {
            return false;
        }
        seen[a[start_idx + i]] = true;
        if (a[start_idx + i] > max_val) {
            max_val = a[start_idx + i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix permutation validity
    std::vector<bool> is_prefix_perm(n + 1, false);
    if (n > 0) { // A prefix of length 0 is not a permutation
        std::vector<bool> seen_prefix(n + 1, false);
        int max_prefix_val = 0;
        bool prefix_valid_so_far = true;
        for (int l1 = 1; l1 <= n; ++l1) {
            int current_val = a[l1 - 1];
            if (!prefix_valid_so_far || current_val < 1 || current_val > l1 || seen_prefix[current_val]) {
                prefix_valid_so_far = false;
            } else {
                seen_prefix[current_val] = true;
                if (current_val > max_prefix_val) {
                    max_prefix_val = current_val;
                }
                if (max_prefix_val == l1) {
                    is_prefix_perm[l1] = true;
                }
            }
        }
    }

    // Precompute suffix permutation validity
    std::vector<bool> is_suffix_perm(n + 1, false);
    if (n > 0) { // A suffix of length 0 is not a permutation
        std::vector<bool> seen_suffix(n + 1, false);
        int max_suffix_val = 0;
        bool suffix_valid_so_far = true;
        for (int l2 = 1; l2 <= n; ++l2) {
            int current_val = a[n - l2];
            if (!suffix_valid_so_far || current_val < 1 || current_val > l2 || seen_suffix[current_val]) {
                suffix_valid_so_far = false;
            } else {
                seen_suffix[current_val] = true;
                if (current_val > max_suffix_val) {
                    max_suffix_val = current_val;
                }
                if (max_suffix_val == l2) {
                    is_suffix_perm[l2] = true;
                }
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

