#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count_after_a = 0; // Number of 'b's encountered to the right of the current 'a'
    long long power_of_2 = 1;      // Represents 2^k, where k is the number of 'b's this 'a' has passed
    const long long MOD = 1e9 + 7;

    // Iterate through the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we see a 'b', it contributes to the count of 'b's that 'a's to its left must pass.
            b_count_after_a = (b_count_after_a + power_of_2) % MOD;
        } else { // s[i] == 'a'
            // If we see an 'a', it needs to pass all 'b's to its right.
            // The number of steps for this 'a' is equal to the current b_count_after_a.
            total_steps = (total_steps + b_count_after_a) % MOD;

            // After this 'a' moves past all 'b's to its right, it effectively doubles
            // the number of 'b's that 'a's to its left will see (one original 'b' + one new 'b').
            // So, for the next 'a' to the left, the 'b's it needs to pass will be doubled.
            // This is equivalent to doubling the 'weight' of each 'b' for subsequent 'a's.
            power_of_2 = (power_of_2 * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append at most 3 elements.
        // Let's try to append 2 elements.
        // We want to find b1, b2 such that:
        // (current_sum + b1 + b2) = 2 * (current_xor ^ b1 ^ b2)
        // Let b1 = current_xor.
        // Then current_xor ^ b1 = current_xor ^ current_xor = 0.
        // The equation becomes:
        // (current_sum + current_xor + b2) = 2 * (0 ^ b2)
        // (current_sum + current_xor + b2) = 2 * b2
        // current_sum + current_xor = b2
        // So, b2 = current_sum + current_xor.

        // Let's verify this.
        // Appended elements: b1 = current_xor, b2 = current_sum + current_xor.
        // New sum S' = current_sum + current_xor + (current_sum + current_xor) = 2 * current_sum + 2 * current_xor.
        // New XOR X' = current_xor ^ current_xor ^ (current_sum + current_xor) = 0 ^ (current_sum + current_xor) = current_sum + current_xor.
        // We need S' = 2 * X'.
        // (2 * current_sum + 2 * current_xor) = 2 * (current_sum + current_xor).
        // This is always true.

        std::cout << 2 << std::endl;
        std::cout << current_xor << " " << current_sum + current_xor << std::endl;
    }
}

