    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1; // Opponent takes 1, game ends.
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                // If P1 takes N/2, remaining N/2 is odd.
                // P2 will take 1, leaving N/2 - 1 (even).
                // P1 will then take 1, leaving N/2 - 2 (even).
                // This seems to lead to P1 getting 1, P2 getting 1, P1 getting 1, P2 getting 1...
                // If P1 takes 1, remaining N-1 is odd.
                // P2 will take 1, leaving N-2 (even).
                // P1 will then take N/2 - 1 (if N-2 is even and N/2-1 is optimal for P1).
                // Let's analyze the N/2 odd case more carefully.
                // If N/2 is odd, and P1 takes N/2:
                //   P1 gets N/2. Remaining N/2.
                //   Now it's P2's turn with N/2 (odd). P2 must take 1.
                //   P2 gets 1. Remaining N/2 - 1 (even).
                //   Now it's P1's turn with N/2 - 1 (even).
                // If N/2 is odd, and P1 takes 1:
                //   P1 gets 1. Remaining N-1 (odd).
                //   Now it's P2's turn with N-1 (odd). P2 must take 1.
                //   P2 gets 1. Remaining N-2 (even).
                //   Now it's P1's turn with N-2 (even).
                //
                // Consider N = 6. N/2 = 3 (odd).
                // P1 takes N/2 = 3. P1 has 3. N=3.
                //   P2 takes 1. P2 has 1. N=2.
                //   P1 takes 1. P1 has 3+1=4. N=1.
                //   P2 takes 1. P2 has 1+1=2. N=0.
                //   P1 total: 4. P2 total: 2.
                // P1 takes 1. P1 has 1. N=5.
                //   P2 takes 1. P2 has 1. N=4.
                //   P1 takes N/2 = 2. P1 has 1+2=3. N=2.
                //   P2 takes 1. P2 has 1+1=2. N=1.
                //   P1 takes 1. P1 has 3+1=4. N=0.
                //   P1 total: 4. P2 total: 2.
                // In this specific case (N=6), both moves lead to the same outcome for P1.
                //
                // The general strategy for N even, N/2 odd:
                // P1 takes 1. N becomes N-1 (odd).
                // P2 takes 1. N becomes N-2 (even).
                // Now it's P1's turn with N-2.
                // This seems to be the optimal move for P1 to maximize their share when N/2 is odd.
                // If P1 takes N/2, P1 gets N/2. Remaining N/2 (odd).
                // P2 takes 1. P2 gets 1. Remaining N/2 - 1 (even).
                // P1 gets N/2. P2 gets 1.
                // If P1 takes 1, P1 gets 1. Remaining N-1 (odd).
                // P2 takes 1. P2 gets 1. Remaining N-2 (even).
                // P1 gets 1. P2 gets 1.
                //
                // The key is that if N/2 is odd, then N must be of the form 2 * (odd number).
                // This means N is 2 * (2k+1) = 4k+2.
                // If P1 takes N/2, P1 gets 2k+1. Remaining 2k+1.
                // P2 takes 1. P2 gets 1. Remaining 2k.
                // If P1 takes 1, P1 gets 1. Remaining 4k+1.
                // P2 takes 1. P2 gets 1. Remaining 4k.
                //
                // The problem states "both players will try to maximize the number of coins they have".
                // This implies a minimax approach.
                // If N is even and N/2 is odd (N = 4k+2):
                //   Option 1: P1 takes N/2. P1 gets N/2. Remaining N/2 (odd).
                //     P2's turn with N/2. P2 takes 1. P2 gets 1. Remaining N/2-1 (even).
                //     Now P1's turn with N/2-1.
                //   Option 2: P1 takes 1. P1 gets 1. Remaining N-1 (odd).
                //     P2's turn with N-1. P2 takes 1. P2 gets 1. Remaining N-2 (even).
                //     Now P1's turn with N-2.
                //
                // Let's consider the total coins P1 gets from the current state N.
                // If P1 takes N/2: P1 gets N/2 + (coins P1 gets from N/2-1)
                // If P1 takes 1: P1 gets 1 + (coins P1 gets from N-2)
                //
                // The opponent will try to minimize P1's future gains.
                // If N/2 is odd, P1 takes 1. This leaves N-1 (odd).
                // P2 must take 1. Leaves N-2 (even).
                // This seems to be the optimal strategy for P1 when N/2 is odd.
                // Example N=6:
                // P1 takes 1. P1 has 1. N=5.
                // P2 takes 1. P2 has 1. N=4.
                // P1 takes N/2=2. P1 has 1+2=3. N=2.
                // P2 takes 1. P2 has 1+1=2. N=1.
                // P1 takes 1. P1 has 3+1=4. N=0.
                // P1 total: 4. P2 total: 2.
                //
                // If P1 takes N/2=3. P1 has 3. N=3.
                // P2 takes 1. P2 has 1. N=2.
                // P1 takes 1. P1 has 3+1=4. N=1.
                // P2 takes 1. P2 has 1+1=2. N=0.
                // P1 total: 4. P2 total: 2.
                //
                // Both moves yield 4 for P1. So taking 1 is fine.
                // The logic for N/2 odd is to take 1.
                chanek_coins += 1;
                n -= 1;
            } else { // N/2 is even
                // If N/2 is even, then N must be a multiple of 4. N = 4k.
                // P1 takes N/2. P1 gets N/2. Remaining N/2 (even).
                // P2's turn with N/2 (even). P2 can take N/4 or 1.
                // P1 wants to maximize their coins. P1 takes N/2.
                chanek_coins += n / 2;
                n /= 2;
            }
        }
    }
    return chanek_coins;
}

