int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Count pairs sharing the same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Count pairs sharing the same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that share both x and y coordinates (i.e., are identical points)
    // These pairs were counted twice: once for sharing x, once for sharing y.
    // They should only be counted once if they are distinct points.
    // However, the problem asks for pairs (i, j) where i < j.
    // If points (x_k, y_k) and (x_l, y_l) are identical, they satisfy both conditions.
    // The logic for D_M = D_E implies (x1=x2 OR y1=y2).
    // If x1=x2 AND y1=y2, then the points are identical.
    // The problem statement says "Some positions may coincide."
    // If P_i = (X, Y) and P_j = (X, Y), then x_i=x_j and y_i=y_j.
    // This pair (i, j) satisfies both conditions (x_i=x_j) and (y_i=y_j).
    // It was counted in x_counts and in y_counts. So it was double counted.
    // We need to subtract these double-counted pairs.
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // Constraint for w_{i-x}
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            // Constraint for w_{i+x}
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s
    std::string s_prime(n, '0'); // Calculate s_prime based on w
    for (int i = 0; i < n; ++i) {
        // Check w_{i-x}
        if (i - x >= 0 && w[i - x] == '1') {
            s_prime[i] = '1';
        }
        // Check w_{i+x}
        if (i + x < n && w[i + x] == '1') {
            s_prime[i] = '1';
        }
    }

    if (s == s_prime) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

