// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // And "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we need to pad to a fixed length (18 for max 10^18-1) with '0's.
    // However, the map key should be canonical. The pattern matching rule implies that
    // 010 matches 92 (010), 2212 (0100), 50 (010), 414 (010).
    // The key idea is that the pattern is always compared from right to left.
    // So, if we store the pattern as a string of length 18, padding with '0's on the left,
    // it will correctly represent the "parity of the i-th from the right digit".
    // Example: 92 -> 01. Padded to 18: 000000000000000010
    // Example: 2212 -> 0100. Padded to 18: 00000000000000000100
    // The query pattern '010' should be padded to 18: 000000000000000010
    // This way, direct string comparison (or map key lookup) works.

    // Reverse the pattern to get it in standard order (most significant digit first)
    std::reverse(pattern.begin(), pattern.end());

    // Pad with leading zeros to a fixed length (18, max digits for 10^18-1)
    // This ensures that all patterns have the same length for map keys.
    // The problem states "pattern of length no more than 18".
    // So, we should pad to 18.
    while (pattern.length() < 18) {
        pattern = '0' + pattern;
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with leading zeros to length 18
            while (s.length() < 18) {
                s = '0' + s;
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

