#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    for (int i = 0; i <= n; ++i) {
        // The number of items taken from the right will be n - i
        int j = n - i;

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for imbalance
        if (i > j) { // More items from left than right
            // The difference is i - j.
            // If i - j = 1, no extra penalty.
            // If i - j = 2, one extra left-hand action.
            // If i - j = 3, one extra left-hand action.
            // If i - j = 4, two extra left-hand actions.
            // The number of extra actions is (i - j - 1) / 2 if i - j is odd, or (i - j - 2) / 2 + 1 if i - j is even.
            // This simplifies to (i - j - 1) if i - j > 0.
            // The number of "extra" left-hand actions that are not balanced by a right-hand action is i - j - 1.
            // Each such "extra" action incurs Ql penalty.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // The number of "extra" right-hand actions that are not balanced by a left-hand action is j - i - 1.
            // Each such "extra" action incurs Qr penalty.
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
