int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        // The condition for infinite loop is that all 3-character substrings
        // are permutations of 'x', 'y', 'z' AND the counts of 'x', 'y', 'z'
        // in the entire substring are "balanced" enough that they can always
        // form such permutations.
        // Specifically, if the counts of 'x', 'y', 'z' differ by more than 1,
        // it's always possible to form a 3-character substring with duplicates,
        // which is not one of "zyx", "xzy", "yxz".
        // If such a substring exists, the algorithm can pick it, rearrange it
        // to something like "xxx", "xxy", etc., and then terminate.
        // The only case where it might loop infinitely is if all 3-character
        // substrings are permutations of 'x', 'y', 'z'. This implies that
        // the counts of 'x', 'y', 'z' in the entire substring must be very close.
        // If |count_x - count_y| > 1 or |count_y - count_z| > 1 or |count_x - count_z| > 1,
        // then it's guaranteed that there exists a 3-character substring with duplicates.
        // For example, if count_x = 5, count_y = 2, count_z = 2, then there must be
        // at least one 'x' that is not part of an 'xyz' permutation.
        // This 'x' must be adjacent to other 'x's or 'y's or 'z's in a way that forms
        // a duplicate substring.
        // More formally, if the counts differ by more than 1, say count_x >= count_y + 2,
        // then even if we try to make as many 'xyz' permutations as possible,
        // there will be at least two 'x's left over that must be adjacent or
        // separated by one character, forming a duplicate substring.
        // For example, if we have 'x' 'x' 'y' 'z' 'x', the counts are 3,1,1.
        // The difference is 2. The substring 'xxy' is not forbidden.
        // The condition for termination is that the counts of 'x', 'y', 'z'
        // in the substring s[l..r] are not "too balanced".
        // If they are "too balanced", meaning |count_x - count_y| <= 1,
        // |count_y - count_z| <= 1, and |count_x - count_z| <= 1,
        // then it's possible that all 3-character substrings are permutations of 'x', 'y', 'z'.
        // In this case, the algorithm will loop infinitely.
        // Otherwise, if any of these differences is > 1, it's guaranteed to terminate.

        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_y - count_z) <= 1 &&
            std::abs(count_x - count_z) <= 1) {
            std::cout << "NO\n";
        } else {
            std::cout << "YES\n";
        }
    }

    return 0;
}

