// Function to find prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let p = k * q.
        // We are looking for x = p / d such that x % q != 0.
        // This is equivalent to (p/d) % q != 0.
        // Or, p % (d*q) != 0.
        // We want to maximize x, which means minimizing d.
        // d must be a divisor of p.
        // The smallest d that makes p/d not divisible by q is what we need.

        // Consider prime factors of q.
        // If x is divisible by q, then x must contain all prime factors of q with at least the same exponents.
        // To make x not divisible by q, we must remove at least one prime factor of q (or reduce its exponent) from p.
        // We want to remove as little as possible from p to keep x large.

        // Let q = f1^e1 * f2^e2 * ... * fk^ek.
        // For each prime factor fi of q, we can try to divide p by fi until p is no longer divisible by fi^ei.
        // More precisely, we want to find a divisor d of p such that p/d is not divisible by q.
        // To maximize p/d, we need to minimize d.
        // The smallest d that makes p/d not divisible by q is found by considering each prime factor of q.

        // For each prime factor f of q:
        // Let p = f^a * P_rest and q = f^b * Q_rest, where P_rest and Q_rest are not divisible by f.
        // If we want x = p / (f^k) such that x % q != 0,
        // and we want to make x not divisible by f^b, we need to divide p by f^(a - (b-1)).
        // This means we divide p by f until its exponent of f is less than b.
        // The smallest factor to divide p by to achieve this is f^(a - (b-1)).
        // The resulting x would be p / (f^(a - (b-1))).
        // We need to do this for each prime factor of q.
        // The maximum x will be obtained by taking the minimum of these values.

        long long max_x = 0;
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            // int e_q = factor_pair.second; // exponent of f in q

            long long current_p = p;
            while (current_p % q == 0) { // Keep dividing current_p by f as long as p is divisible by q
                current_p /= f;
            }
            // After this loop, current_p is p / (f^k) for some k, such that (p / (f^k)) % q != 0.
            // This current_p is a candidate for x.
            // We want the maximum such current_p.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_prefix = "";
    std::set<char> visited_in_layout;

    // Find a starting character for the layout.
    // A starting character must be one that appears in 's' and has only one neighbor.
    // If all characters in 's' have two neighbors (e.g., 'abacaba'), then it forms a cycle or a path where endpoints have 1 neighbor.
    // If it's a path, we start from one of the endpoints.
    // If it's a cycle, any character can be a start.
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() <= 1) { // <= 1 because if it's a single char password, it has 0 neighbors
            start_char = c;
            break;
        }
    }

    // If no character with 1 or 0 neighbors is found, it means all characters in 's' have 2 neighbors.
    // This implies a cycle or a path where all internal nodes have 2 neighbors.
    // If it's a cycle, any character can be a start.
    // If it's a path, the above loop should have found an endpoint.
    // So, if start_char is still '\0', it means all characters in 's' have 2 neighbors, forming a cycle.
    // In this case, we can pick any character from 's' as a start.
    if (start_char == '\0' && !used_in_s.empty()) {
        start_char = *used_in_s.begin();
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // To keep track of the character we came from

        while (visited_in_layout.find(current_char) == visited_in_layout.end()) {
            layout_prefix += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
            if (current_char == '\0') break; // Reached end of path
        }
    }

    // Check if all characters from 's' that were supposed to be part of the path/cycle
    // were actually included in the layout_prefix.
    // If not, it means there are disconnected components in the graph formed by 's',
    // which is impossible for a single linear layout.
    if (layout_prefix.length() != used_in_s.size()) {
        std::cout << "NO\n";
        return;
    }

    std::string remaining_chars = "";
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            remaining_chars += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_prefix << remaining_chars << "\n";
}

