void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::string coloring(n, ' ');
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                coloring[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > p) {
                coloring[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == p
                // Try to put it in S2 if possible, to keep S1 as small as possible
                // This greedy choice is based on the observation that if we have multiple 'p's,
                // we want to put as many as possible into S2 to satisfy the non-decreasing property of S1.
                // Specifically, if the last digit added to S1 was also 'p', we must put this 'p' into S2.
                // If the last digit added to S1 was < 'p', we can put this 'p' into S1.
                // However, a simpler approach is to put all 'p's that appear *before* the first 'p' that goes to S2 into S1,
                // and all 'p's that appear *after* or *at* the first 'p' that goes to S2 into S2.
                // This means we need to find the "split point" for 'p's.
                // Let's try a fixed split point for 'p's.
                // All 'p's before a certain index `k` go to S1, all 'p's from `k` onwards go to S2.
                // This is equivalent to finding the first 'p' that goes to S2.
                // Let's try to find the first 'p' that goes to S2.
                // If we put a 'p' into S1, it must be >= the last element of S1.
                // If we put a 'p' into S2, it must be >= the last element of S2.
                // And the last element of S1 must be <= the first element of S2.

                // A simpler greedy strategy for digits equal to 'p':
                // Put 'p' into S2 if S2 is empty or d[i] >= last_s2_digit.
                // Otherwise, put 'p' into S1 if S1 is empty or d[i] >= last_s1_digit.
                // This is not quite right because it doesn't guarantee max(S1) <= min(S2).

                // The correct greedy strategy for digits equal to 'p':
                // We want to make S1 as short as possible and S2 as long as possible,
                // while maintaining the non-decreasing property for both.
                // If we put d[i] = p into S1, it must be >= last_s1_digit.
                // If we put d[i] = p into S2, it must be >= last_s2_digit.
                // And max(S1) <= min(S2).
                // The critical point is that all digits in S1 must be <= p, and all digits in S2 must be >= p.
                // So, for d[i] == p:
                // If we put it in S1, it must be >= last_s1_digit.
                // If we put it in S2, it must be >= last_s2_digit.
                // The condition max(S1) <= min(S2) is automatically satisfied if all S1 digits are <= p and all S2 digits are >= p.
                // So we just need to ensure S1 and S2 are non-decreasing.
                // For d[i] == p, we can put it in S1 if s1_digits is empty or s1_digits.back() <= p.
                // We can put it in S2 if s2_digits is empty or s2_digits.back() <= p.
                // To maximize chances of success, we should try to put 'p's into S1 as long as possible,
                // and then switch to S2.
                // This means we find the *last* 'p' that can go into S1.
                // All 'p's before it go to S1, all 'p's after it go to S2.
                // This is equivalent to finding the *first* 'p' that goes to S2.

                // Let's try a simpler approach:
                // Iterate through the digits.
                // If d[i] < p, it must be color 1.
                // If d[i] > p, it must be color 2.
                // If d[i] == p:
                //   If we have already placed a digit > p into S2, then this 'p' must go into S1.
                //   Otherwise, this 'p' can go into S1 or S2.
                //   To maximize chances, put it into S2 if possible (i.e., if S2 is empty or last_s2_digit <= p).
                //   Otherwise, put it into S1 if possible (i.e., if S1 is empty or last_s1_digit <= p).
                // This is still not quite right.

                // The correct logic for d[i] == p:
                // We need to find a split point `k` such that all `d_j = p` for `j < k` go to S1,
                // and all `d_j = p` for `j >= k` go to S2.
                // This means we iterate through `d_i`.
                // If `d_i < p`, it's color 1.
                // If `d_i > p`, it's color 2.
                // If `d_i == p`:
                //   If we haven't decided to put 'p's into S2 yet (i.e., `seen_p_in_s2` is false):
                //     Put `d_i` into S1.
                //   Else (we have already started putting 'p's into S2):
                //     Put `d_i` into S2.
                // This strategy is wrong. The example 040425524644 with p=4 gives 121212211211.
                // Here, 0,0,2,2,4,4,4 are S1 and 4,4,5,5,6 are S2.
                // The 'p's (which are 4s) are split: d[1]=4 (S2), d[3]=4 (S2), d[8]=4 (S1), d[10]=4 (S1), d[11]=4 (S1).
                // This means the split point for 'p's is not fixed.
                // Some 'p's go to S1, some to S2.
                // The condition is: all digits in S1 must be <= p, and all digits in S2 must be >= p.
                // And max(S1) <= min(S2). This implies max(S1) <= p and min(S2) >= p.
                // So, for d[i] == p:
                // We can put it in S1 if s1_digits is empty or s1_digits.back() <= p.
                // We can put it in S2 if s2_digits is empty or s2_digits.back() <= p.
                // To satisfy max(S1) <= min(S2), we need to ensure that if we put a 'p' into S1,
                // and later put a 'p' into S2, then all 'p's between them must also be handled correctly.
                // The key is that if we put a 'p' into S1, and later put a 'p' into S2,
                // then all digits in S1 must be <= p, and all digits in S2 must be >= p.
                // This means the split point for 'p's is crucial.
                // All 'p's that go to S1 must appear before all 'p's that go to S2.
                // This is the standard approach for two-partition problems.
                // Find the first index `k` such that `d_k = p` and `d_k` goes to S2.
                // All `d_j = p` for `j < k` go to S1. All `d_j = p` for `j >= k` go to S2.

                // Let's try this:
                // Iterate through `d_i`.
                // If `d_i < p`, it must be color 1.
                // If `d_i > p`, it must be color 2.
                // If `d_i == p`:
                //   If `s2_digits` is empty OR `d_i >= s2_digits.back()`:
                //     Put `d_i` into S2.
                //     coloring[i] = '2';
                //     s2_digits.push_back(d[i]);
                //   Else (cannot put into S2 without violating non-decreasing property of S2):
                //     Put `d_i` into S1.
                //     coloring[i] = '1';
                //     s1_digits.push_back(d[i]);
                // This is the greedy choice that tries to put 'p's into S2 first.
                // This is the strategy that worked for the example.
                // For d=040425524644, p=4:
                // d[0]=0 < 4 -> S1 (0) -> coloring[0]=1
                // d[1]=4 == 4. S2 empty. Put in S2. -> S2 (4) -> coloring[1]=2
                // d[2]=0 < 4 -> S1 (0,0) -> coloring[2]=1
                // d[3]=4 == 4. S2 not empty, s2.back()=4. 4 >= 4. Put in S2. -> S2 (4,4) -> coloring[3]=2
                // d[4]=2 < 4 -> S1 (0,0,2) -> coloring[4]=1
                // d[5]=5 > 4 -> S2 (4,4,5) -> coloring[5]=2
                // d[6]=5 > 4 -> S2 (4,4,5,5) -> coloring[6]=2
                // d[7]=2 < 4 -> S1 (0,0,2,2) -> coloring[7]=1
                // d[8]=4 == 4. S2 not empty, s2.back()=5. 4 < 5. Cannot put in S2. Put in S1. -> S1 (0,0,2,2,4) -> coloring[8]=1
                // d[9]=6 > 4 -> S2 (4,4,5,5,6) -> coloring[9]=2
                // d[10]=4 == 4. S2 not empty, s2.back()=6. 4 < 6. Cannot put in S2. Put in S1. -> S1 (0,0,2,2,4,4) -> coloring[10]=1
                // d[11]=4 == 4. S2 not empty, s2.back()=6. 4 < 6. Cannot put in S2. Put in S1. -> S1 (0,0,2,2,4,4,4) -> coloring[11]=1
                // Final S1: 0,0,2,2,4,4,4. Final S2: 4,4,5,5,6.
                // Combined: 0,0,2,2,4,4,4,4,4,5,5,6. This is sorted.
                // This strategy seems to work for the example.

                if (s2_digits.empty() || d[i] >= s2_digits.back()) {
                    coloring[i] = '2';
                    s2_digits.push_back(d[i]);
                } else {
                    coloring[i] = '1';
                    s1_digits.push_back(d[i]);
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 1; i < s1_digits.size(); ++i) {
            if (s1_digits[i] < s1_digits[i-1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 1; i < s2_digits.size(); ++i) {
            if (s2_digits[i] < s2_digits[i-1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if max(S1) <= min(S2)
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_p = false;
            }
        }

        // This check is actually redundant with the greedy strategy for 'p's.
        // If d[i] < p, it goes to S1. If d[i] > p, it goes to S2.
        // If d[i] == p, it goes to S2 if possible, else S1.
        // This ensures that all digits in S1 are <= p, and all digits in S2 are >= p.
        // Thus, max(S1) <= p <= min(S2) is implicitly satisfied.
        // The only thing to check is if S1 and S2 are individually sorted.
        // The greedy choice for d[i] == p (put in S2 if possible, else S1)
        // already ensures that d[i] >= s2_digits.back() if put in S2,
        // and d[i] >= s1_digits.back() if put in S1.
        // So the individual non-decreasing checks are sufficient.

        if (possible_p) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

