int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_k = sum_{k=1 to a} k
    // Sum_k = a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = (sum_k * ((MOD + 1) / 2)) % MOD;

    // Sum_r = sum_{r=1 to b-1} r
    // Sum_r = (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * ((MOD + 1) / 2)) % MOD;

    // Sum_kr = sum_{k=1 to a} sum_{r=1 to b-1} k*r
    // Sum_kr = (sum_{k=1 to a} k) * (sum_{r=1 to b-1} r)
    long long sum_kr = (sum_k * sum_r) % MOD;

    // Total sum = sum_{k=1 to a} sum_{r=1 to b-1} (k*r*b + r)
    // Total sum = sum_{k=1 to a} sum_{r=1 to b-1} (k*r*b) + sum_{k=1 to a} sum_{r=1 to b-1} (r)
    // Total sum = b * (sum_{k=1 to a} sum_{r=1 to b-1} k*r) + a * (sum_{r=1 to b-1} r)
    // Total sum = b * Sum_kr + a * Sum_r

    long long term1 = (b % MOD * sum_kr) % MOD;
    long long term2 = (a % MOD * sum_r) % MOD;

    long long total_sum = (term1 + term2) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

