int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute character occurrences
    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    // Iterate over all possible first characters t_0
    for (char c_0_char = 'a'; c_0_char <= 'z'; ++c_0_char) {
        int char_code = c_0_char - 'a';
        const std::vector<int>& possible_k_for_c0 = char_indices[char_code];

        if (possible_k_for_c0.empty()) {
            continue; // This character never appears as s[k], so it can't be t_0.
        }

        // If only one k is possible for this c_0, Vasya wins for sure.
        if (possible_k_for_c0.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // If multiple k's are possible, Vasya needs to choose p.
        // Find the best p for this c_0.
        int max_wins_for_c0 = 0;

        // Iterate over all possible second positions p (from 1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed c_0 and p, count how many k's lead to a unique (k, t_p) pair.
            int current_p_wins = 0;
            std::map<std::pair<char, char>, std::vector<int>> outcomes;

            for (int k_val : possible_k_for_c0) {
                char t_0_val = s[k_val];
                char t_p_val = s[(k_val + p) % L];
                outcomes[{t_0_val, t_p_val}].push_back(k_val);
            }

            for (const auto& pair_entry : outcomes) {
                if (pair_entry.second.size() == 1) {
                    current_p_wins++;
                }
            }
            max_wins_for_c0 = std::max(max_wins_for_c0, current_p_wins);
        }
        total_win_prob += static_cast<double>(max_wins_for_c0) / possible_k_for_c0.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

