    //   (0 & A_k) | B_k ^ C_k = 1 => B_k ^ C_k = 1
    //   (1 & A_k) | B_k ^ C_k = 0 => A_k | B_k ^ C_k = 0 => A_k | 1 = 0 (impossible)
    //   This means the form (x & A) | B ^ C is not general enough if we restrict A, B, C to 0 or 1 for each bit.
    //   The problem is that A_k | 1 = 0 is impossible.
    //   This implies that A_k must be 0 for this bit.
    //   If A_k=0: (x_k & 0) | B_k ^ C_k = B_k ^ C_k. This must be ~x_k.
    //   But B_k ^ C_k is constant, while ~x_k is not. So this form doesn't work for negation.
    //
    // Let's use the standard approach for bitwise functions:
    // Any function f(x) can be represented as (x & A) | (x | B) ^ C.
    // Or more simply, by tracking the effect on 0 and 1023.
    // Let `val_0` be the result of applying all operations to `0`.
    // Let `val_1` be the result of applying all operations to `1023`.
    //
    // For each bit `k`:
    // `bit_0 = (val_0 >> k) & 1`
    // `bit_1 = (val_1 >> k) & 1`
    //
    // We want to find `A_k, B_k, C_k` such that `(x_k & A_k) | B_k ^ C_k` matches `(bit_0, bit_1)` behavior.
    //
    // Let's define `A_final`, `B_final`, `C_final` for the operations `& A_final`, `| B_final`, `^ C_final`.
    //
    // `A_final` will be the mask for `&`.
    // `B_final` will be the mask for `|`.
    // `C_final` will be the mask for `^`.
    //
    // Initialize `A_final = 1023`, `B_final = 0`, `C_final = 0`.
    //
    // For each bit `k` from 0 to 9:
    //   `f_k(0) = (current_or_mask >> k) & 1`
    //   `f_k(1) = (current_and_mask >> k) & 1`
    //
    //   If `f_k(0) == 0` and `f_k(1) == 0`: // Output is always 0
    //     `A_final &= ~(1 << k);` // Force bit to 0 with AND
    //     `B_final &= ~(1 << k);` // Ensure OR doesn't set it
    //     `C_final &= ~(1 << k);` // Ensure XOR doesn't flip it
    //
    //   If `f_k(0) == 0` and `f_k(1) == 1`: // Output is x_k (identity)
    //     `A_final |= (1 << k);`  // Allow bit to pass through AND
    //     `B_final &= ~(1 << k);` // Ensure OR doesn't set it
    //     `C_final &= ~(1 << k);` // Ensure XOR doesn't flip it
    //
    //   If `f_k(0) == 1` and `f_k(1) == 0`: // Output is ~x_k (negation)
    //     `A_final |= (1 << k);`  // Allow bit to pass through AND
    //     `B_final &= ~(1 << k);` // Ensure OR doesn't set it
    //     `C_final |= (1 << k);`  // Flip the bit with XOR
    //
    //   If `f_k(0) == 1` and `f_k(1) == 1`: // Output is always 1
    //     `A_final |= (1 << k);`  // Allow bit to pass through AND
    //     `B_final |= (1 << k);`  // Force bit to 1 with OR
    //     `C_final &= ~(1 << k);` // Ensure XOR doesn't flip it
    //
    // This logic is for the sequence `(x & A_final) | B_final ^ C_final`.
    // Let's verify this.
    //
    // For input `x`:
    // `res = x & A_final`
    // `res = res | B_final`
    // `res = res ^ C_final`
    //
    // Let's check for each bit `k`:
    //
    // Case 1: `f_k(0)=0, f_k(1)=0` => `A_k=0, B_k=0, C_k=0`
    //   `res_k = (x_k & 0) | 0 ^ 0 = 0 | 0 ^ 0 = 0`. Correct.
    //
    // Case 2: `f_k(0)=0, f_k(1)=1` => `A_k=1, B_k=0, C_k=0`
    //   `res_k = (x_k & 1) | 0 ^ 0 = x_k | 0 ^ 0 = x_k`. Correct.
    //
    // Case 3: `f_k(0)=1, f_k(1)=0` => `A_k=1, B_k=0, C_k=1`
    //   `res_k = (x_k & 1) | 0 ^ 1 = x_k | 0 ^ 1 = x_k ^ 1 = ~x_k`. Correct.
    //
    // Case 4: `f_k(0)=1, f_k(1)=1` => `A_k=1, B_k=1, C_k=0`
    //   `res_k = (x_k & 1) | 1 ^ 0 = x_k | 1 ^ 0 = 1 ^ 0 = 1`. Correct.
    //
    // This set of `A_final`, `B_final`, `C_final` values correctly implements the function for each bit.
    // The order of operations must be `&`, then `|`, then `^`.

    int A_final = 0; // Mask for &
    int B_final = 0; // Mask for |
    int C_final = 0; // Mask for ^

    for (int k = 0; k < 10; ++k) {
        int f0_k = (current_or_mask >> k) & 1;
        int f1_k = (current_and_mask >> k) & 1;

        if (f0_k == 0 && f1_k == 0) { // Output 0
            // A_k=0, B_k=0, C_k=0
            // (x_k & 0) | 0 ^ 0 = 0
        } else if (f0_k == 0 && f1_k == 1) { // Output x_k
            // A_k=1, B_k=0, C_k=0
            // (x_k & 1) | 0 ^ 0 = x_k
            A_final |= (1 << k);
        } else if (f0_k == 1 && f1_k == 0) { // Output ~x_k
            // A_k=1, B_k=0, C_k=1
            // (x_k & 1) | 0 ^ 1 = ~x_k
            A_final |= (1 << k);
            C_final |= (1 << k);
        } else if (f0_k == 1 && f1_k == 1) { // Output 1
            // A_k=1, B_k=1, C_k=0
            // (x_k & 1) | 1 ^ 0 = 1
            A_final |= (1 << k);
            B_final |= (1 << k);
        }
    }

    std::vector<std::pair<char, int>> final_ops;
    if (A_final != 1023) { // If A_final is not all ones, we need an AND operation
        final_ops.push_back({'&', A_final});
    }
    if (B_final != 0) { // If B_final is not all zeros, we need an OR operation
        final_ops.push_back({'|', B_final});
    }
    if (C_final != 0) { // If C_final is not all zeros, we need an XOR operation
        final_ops.push_back({'^', C_final});
    }

    std::cout << final_ops.size() << "\n";
    for (const auto& op : final_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i + 1; // 1-indexed pile number
        long long distance = pile_idx - 1; // distance to pile 1

        if (distance <= d) {
            // We can move haybales from this pile to pile 1
            // Each haybale costs 'distance' days
            long long haybales_can_move = d / distance;

            long long haybales_to_move = std::min(a[i], haybales_can_move);

            current_a1 += haybales_to_move;
            d -= haybales_to_move * distance;
        }
        // If distance > d, we cannot move any haybale from this pile to pile 1
        // because even one haybale costs more days than available.
    }

    std::cout << current_a1 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for differences (strawberry - blueberry)
    // For left side (indices 0 to n-1), iterate from right to left (n-1 down to 0)
    // For right side (indices n to 2n-1), iterate from left to right (n up to 2n-1)

    // Left side: jars n-1, n-2, ..., 0
    // We are interested in the balance of jars *removed* from the left.
    // Let diff_L[k] be the balance of the first k jars removed from the left (jars n-1, n-2, ..., n-k).
    // This is equivalent to the balance of prefix sums from index n-1 down to n-k.
    // Or, more simply, let's calculate the balance of the *remaining* jars on the left.
    // Let balance_L[i] be the balance of jars a[0]...a[i-1].
    // So, balance_L[0] = 0 (no jars)
    // balance_L[1] = (a[0]==1 ? 1 : -1)
    // balance_L[i] = balance_L[i-1] + (a[i-1]==1 ? 1 : -1)
    // We need to store the balance of jars a[0]...a[i-1] for i from 0 to n.
    // This means we are considering keeping i jars on the left.
    std::vector<int> balance_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_L[i + 1] = balance_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Right side: jars n, n+1, ..., 2n-1
    // We need to store the balance of jars a[j]...a[2n-1] for j from n to 2n.
    // This means we are considering keeping 2n-j jars on the right.
    // Let balance_R[j] be the balance of jars a[j]...a[2n-1].
    // balance_R[2n] = 0 (no jars)
    // balance_R[2n-1] = (a[2n-1]==1 ? 1 : -1)
    // balance_R[j] = balance_R[j+1] + (a[j]==1 ? 1 : -1)
    std::vector<int> balance_R(2 * n + 1, 0);
    for (int i = 2 * n - 1; i >= n; --i) {
        balance_R[i] = balance_R[i + 1] + (a[i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the right
    // to achieve a certain balance.
    // key: balance_R[n+k_R] (balance of remaining jars on the right)
    // value: k_R (number of jars removed from the right)
    std::map<int, int> right_removed_map;
    // k_R can range from 0 to n.
    // If k_R jars are removed from the right, the remaining jars are a[n+k_R]...a[2n-1].
    // The balance of these remaining jars is balance_R[n+k_R].
    // We want to store the minimum k_R for each balance.
    // Since we iterate k_R from 0 to n, the first time we see a balance, it will be the minimum k_R.
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_balance_R = balance_R[n + k_R];
        if (right_removed_map.find(current_balance_R) == right_removed_map.end()) {
            right_removed_map[current_balance_R] = k_R;
        }
    }

    int min_total_removed = 2 * n; // Max possible jars to remove

    // Iterate over k_L, the number of jars removed from the left.
    // k_L can range from 0 to n.
    // If k_L jars are removed from the left, the remaining jars are a[0]...a[n-k_L-1].
    // The balance of these remaining jars is balance_L[n-k_L].
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_balance_L = balance_L[n - k_L];
        // We need total_balance_rem = 0.
        // total_balance_rem = current_balance_L + current_balance_R
        // So, we need current_balance_R = -current_balance_L.
        int target_balance_R = -current_balance_L;

        if (right_removed_map.count(target_balance_R)) {
            int k_R = right_removed_map[target_balance_R];
            min_total_removed = std::min(min_total_removed, k_L + k_R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Initialize with a very large value

    // Process operations in reverse to determine upper bounds for initial_a
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1: a[j] = a[j] + d_i
            // If we know a[j] after this operation, then a[j] before was a[j] - d_i.
            // This means the upper bound for initial_a[j] should be reduced by d_i.
            // Or, more precisely, if initial_a[j] (current estimate for initial value)
            // is affected by this operation, its value should be adjusted.
            // This is tricky because initial_a[j] is an upper bound for the *initial* value.
            // Let's re-think.
            // If we have an upper bound for A_j + sum_of_d_up_to_k,
            // and we encounter an operation (l,r,d) at index i,
            // then for j in [l,r], A_j + sum_of_d_up_to_i-1 + d <= current_upper_bound_for_A_j_plus_sum_of_d_up_to_i-1_plus_d
            // This means A_j + sum_of_d_up_to_i-1 <= current_upper_bound_for_A_j_plus_sum_of_d_up_to_i-1_plus_d - d
            // So, we should subtract d from the current upper bounds for A_j + sum_of_d_up_to_i-1.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (initial_a[j] != LLONG_MAX) { // Only adjust if an upper bound has been set
                    initial_a[j] -= ops[i].val;
                }
            }
        } else {
            // Type 2: max_{j=l_i}^{r_i} a[j] = m_i
            // This means for all j in [l_i, r_i], a[j] <= m_i.
            // So, for all j in [l_i, r_i], initial_a[j] (which is an upper bound for A_j + sum_of_d_up_to_i-1)
            // must be at most m_i.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val);
            }
        }
    }

    // If any initial_a[j] is still LLONG_MAX, it means no type 2 operation constrained it.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == LLONG_MAX) {
            initial_a[j] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> current_a = initial_a;
    std::vector<long long> diff_prefix_sum(n + 1, 0); // For efficient range updates

    for (const auto& op : ops) {
        if (op.type == 1) {
            // Apply type 1 operation to current_a
            // This is for verification, so we apply it to the actual array values.
            // We use a difference array / prefix sum approach to simulate this efficiently.
            diff_prefix_sum[op.l] += op.val;
            if (op.r + 1 < n) {
                diff_prefix_sum[op.r + 1] -= op.val;
            }
        } else {
            // Verify type 2 operation
            long long max_val = LLONG_MIN;
            long long current_add = 0;
            for (int j = 0; j < n; ++j) {
                current_add += diff_prefix_sum[j];
                if (j >= op.l && j <= op.r) {
                    max_val = std::max(max_val, initial_a[j] + current_add);
                }
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

