        // If a_i < prev_b and (a_i + x) % m < prev_b, then it's impossible.
        // This is the critical check.

        // Let's combine:
        // If a_i >= prev_b:
        //   We can potentially set b_i = prev_b. This requires k = (prev_b - a_i + m) % m.
        //   If k <= x, then we set prev_b = prev_b.
        //   Else (k > x), we must set b_i = a_i. So prev_b = a_i.
        // Else (a_i < prev_b):
        //   We must increment a_i.
        //   We need to reach at least prev_b.
        //   The required increment without wrap-around is prev_b - a_i.
        //   If prev_b - a_i <= x, then we can set b_i = prev_b. So prev_b remains prev_b.
        //   Else (prev_b - a_i > x):
        //     We cannot reach prev_b without wrapping.
        //     This means a_i + x < prev_b.
        //     In this situation, even with x increments, a_i cannot reach prev_b.
        //     So it's impossible. Return false.

        // This logic seems correct.
        if (current_a >= prev_b) {
            // We have two choices for b_i: a_i or prev_b.
            // We want to pick the smallest one that is achievable.
            // If we pick prev_b, the required increment is (prev_b - current_a + m) % m.
            // If this increment is <= x, then we can achieve prev_b.
            // Otherwise, we cannot achieve prev_b, so we must pick current_a.
            if (current_a + x < m + prev_b && current_a + x < prev_b) { // This condition is wrong.
                // If current_a + x < prev_b, it means we cannot reach prev_b even with x increments.
                // This can only happen if current_a < prev_b.
                // If current_a >= prev_b, then current_a + x >= prev_b is always true.
                // So if current_a >= prev_b, we can always achieve prev_b by incrementing current_a by (prev_b - current_a + m) % m.
                // The question is whether this increment is <= x.
                // Let k_to_prev_b = (prev_b - current_a + m) % m.
                // If k_to_prev_b <= x, then we can set b_i = prev_b.
                // Else, we must set b_i = current_a.
                long long k_to_prev_b = (prev_b - current_a + m) % m;
                if (k_to_prev_b > x) {
                    // Cannot make b_i = prev_b. Must use current_a.
                    prev_b = current_a;
                }
                // Else, prev_b remains prev_b.
            }
        } else { // current_a < prev_b
            // We must increment current_a.
            // We need to reach at least prev_b.
            // The required increment without wrap-around is prev_b - current_a.
            // If prev_b - current_a <= x, then we can set b_i = prev_b.
            // Else (prev_b - current_a > x):
            //   This means current_a + x < prev_b.
            //   We cannot reach prev_b even with x increments.
            //   So it's impossible.
            return false;
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations is m-1 (e.g., 0 -> m-1)
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

