// Function to calculate the number of '1's in a string
int count_ones(const std::string& s) {
    return std::count(s.begin(), s.end(), '1');
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If the initial string 'a' has an odd number of '1's,
    // we can effectively add one more '1' to its count by appending '1'.
    // This means the maximum possible number of '1's we can achieve
    // in any string derived from 'a' is ones_a + (ones_a % 2).
    // If ones_a is even, ones_a % 2 is 0, max_ones_a = ones_a.
    // If ones_a is odd, ones_a % 2 is 1, max_ones_a = ones_a + 1.
    // This is because appending '0' doesn't change the count of '1's,
    // and appending '1' increases it by one.
    // If we have an odd number of '1's, we can append '1'.
    // If we have an even number of '1's, we can append '0'.
    // To maximize '1's, we want to append '1' if possible.
    // If current '1's count is odd, we can append '1', making it even.
    // If current '1's count is even, we can append '0', keeping it even.
    // So, if we start with an odd count, we can reach an even count one higher.
    // If we start with an even count, we can only reach even counts.
    // The maximum number of '1's we can ever have in a string derived from 'a'
    // (by only appending '1's when possible) is `ones_a + (ones_a % 2)`.
    int max_ones_a_possible = ones_a + (ones_a % 2);

    // Condition 1: The number of '1's in 'b' must be less than or equal to
    // the maximum number of '1's we can possibly achieve from 'a'.
    // If ones_b > max_ones_a_possible, it's impossible.
    if (ones_b > max_ones_a_possible) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must be less than or equal to
    // the length of 'a' after potentially appending characters.
    // We can always make 'a' longer by appending characters.
    // We can always make 'a' shorter by removing characters.
    // The only constraint on length is that we can't make 'a' shorter than 'b'
    // if we need to match 'b'.
    // If |a| < |b|, we must append characters. This is always possible.
    // If |a| >= |b|, we might need to remove characters. This is always possible
    // as long as 'a' doesn't become empty before reaching length |b|.
    // Since |b| >= 1, we can always remove characters from 'a' until its length
    // is |b|, as long as |a| is initially at least |b|.
    // If |a| < |b|, we can append characters until |a| becomes |b|.
    // The only way it's impossible due to length is if we need to make 'a'
    // longer than its current maximum possible length, but there's no such limit.
    // So, length constraint is always satisfied as long as ones_b <= max_ones_a_possible.

    // If both conditions are met, it's always possible.
    // We can always remove leading characters from 'a' until its length is |b|-1.
    // Then, we can append the correct parity character to match 'b'.
    // If the current number of '1's is `c`, and we need `ones_b` '1's,
    // and `c <= max_ones_a_possible`, we can always achieve `ones_b`.
    // This is because we can always reduce the number of '1's by removing leading characters.
    // We can also increase the number of '1's by appending '1's (if parity is odd).
    // The key insight is that we can always reach any number of '1's `k` such that
    // `ones_b <= k <= max_ones_a_possible` and `k % 2 == ones_b % 2`
    // by strategically removing characters and appending parity.
    // Since we can always remove characters, we can always reduce the count of '1's.
    // Since we can always append '0' or '1' based on parity, we can always adjust the parity.
    // The only hard limit is `max_ones_a_possible`.

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // This child is now cured

        long long current_v_effect = children[i].v;
        long long total_d_effect_from_hall_cries = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effect from current child crying in office
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Apply cumulative effect from children crying in hall
            children[j].p -= total_d_effect_from_hall_cries;

            // Check if child j's confidence dropped below zero
            if (children[j].p < 0) {
                children[j].in_line = false; // Child j leaves the line
                total_d_effect_from_hall_cries += children[j].d; // Add j's hall cry to cumulative effect
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

