    // `memo[i]` will be `long long`. Initialize with `0` (uncomputed).
    // `memo[i] = -1` for loop. `memo[i] > 0` for terminating value.
    std::vector<long long> memo(n + 1, 0); // 0 means uncomputed, -1 means loop, >0 means result

    // Function to compute result for a given starting x and a_val array.
    // This function will use memoization for x >= 2.
    // For x=1, it will not use memoization directly, but will call itself for subsequent x values.
    // To detect cycles, we need a `visited` array for the current path.
    // `visited_path[x]` stores `true` if `x` is currently in the recursion stack.
    std::vector<bool> visited_path(n + 1, false);

    // `a_val_for_query` is the `a` array for the current query.
    // `a_val_for_query[1]` will be `k` for query `k`.
    // `a_val_for_query[j]` for `j >= 2` will be `a_val[j]` (from input).
    // This means `a_val` from input is `a_val_fixed`.
    std::vector<long long> a_val_fixed(n + 1);
    for (int i = 2; i <= n; ++i) {
        a_val_fixed[i] = a_val[i]; // Copy input a_val to a_val_fixed
    }

    // Recursive lambda function for DFS with memoization
    // `start_x`: the initial x for this subproblem
    // `current_a1_value`: the value of a[1] for the current query
    // `current_y_offset`: the y accumulated so far before reaching `start_x`
    // Returns the final y value, or -1 for non-termination.
    auto solve = [&](auto self, int start_x, long long current_a1_value) -> long long {
        // If start_x is out of bounds, it's a termination point.
        if (start_x <= 0 || start_x > n) {
            return 0; // Base case: no more y to add from this point.
        }

        // If start_x >= 2 and already memoized, return memoized value.
        if (start_x >= 2 && memo[start_x] != 0) {
            return memo[start_x];
        }

        // Cycle detection: if start_x is in current path, it's a loop.
        if (visited_path[start_x]) {
            return -1; // Indicate non-termination
        }

        visited_path[start_x] = true; // Mark as visited in current path

        long long current_a_x;
        if (start_x == 1) {
            current_a_x = current_a1_value;
        } else {
            current_a_x = a_val_fixed[start_x];
        }

        // Step 2: x = x + a_x, y = y + a_x
        long long x_after_step2 = start_x + current_a_x;
        long long y_added_step2 = current_a_x;

        long long result;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            // Terminates after step 2
            result = y_added_step2;
        } else {
            // Step 3: x = x - a_x, y = y + a_x
            long long a_x_for_step3;
            if (x_after_step2 == 1) {
                a_x_for_step3 = current_a1_value;
            } else {
                a_x_for_step3 = a_val_fixed[x_after_step2];
            }

            long long x_after_step3 = x_after_step2 - a_x_for_step3;
            long long y_added_step3 = a_x_for_step3;

            // Recursively call for the next state
            long long next_result = self(self, x_after_step3, current_a1_value);

            if (next_result == -1) {
                result = -1; // Propagate non-termination
            } else {
                result = y_added_step2 + y_added_step3 + next_result;
            }
        }

        visited_path[start_x] = false; // Unmark as visited in current path

        // Memoize result for x >= 2
        if (start_x >= 2) {
            memo[start_x] = result;
        }
        return result;
    };

    // For each query k from 1 to n-1:
    for (int k = 1; k <= n - 1; ++k) {
        // Reset visited_path for each query, as a_val[1] changes.
        // Only need to reset for x=1, as other x values are handled by memo.
        // But it's safer to reset all for clarity, though only x=1 will be the initial call.
        // The `visited_path` is for the current DFS path, not for global memoization.
        // So it must be reset for each top-level call.
        std::fill(visited_path.begin(), visited_path.end(), false);

        // Call solve for starting x=1 with a_val[1] = k
        long long final_y = solve(solve, 1, k);
        std::cout << final_y << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one partition (e.g., all in partition 1)
    // In this case, all f(a_i, a_j) = a_i + a_j.
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long min_goodness = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::fill(partition.begin(), partition.end(), 1);

    // Case 2: At least one element in each partition.
    // This means there will always be f values of type a_i + a_j + h.
    // The minimum possible f value is min(a_i + a_j, a_i + a_j + h) = a_0 + a_1.
    // The maximum possible f value is max(a_i + a_j, a_i + a_j + h) = a_{n-2} + a_{n-1} + h.
    // So, goodness = (a_{n-2} + a_{n-1} + h) - (a_0 + a_1).
    // This is the "default" goodness if both partitions are non-empty.
    long long default_goodness_both_non_empty = (elements[n - 2].value + elements[n - 1].value + h) - (elements[0].value + elements[1].value);

    // Consider a specific partition strategy:
    // Put elements[0] into partition 1.
    // Put elements[1] into partition 2.
    // Put elements[2] to elements[n-1] into partition 2.
    // S1 = {elements[0]}
    // S2 = {elements[1], elements[2], ..., elements[n-1]}
    //
    // f values:
    // 1. From S2: elements[i].value + elements[j].value for i,j in [1, n-1]
    //    Min: elements[1].value + elements[2].value
    //    Max: elements[n-2].value + elements[n-1].value
    // 2. Between S1 and S2: elements[0].value + elements[j].value + h for j in [1, n-1]
    //    Min: elements[0].value + elements[1].value + h
    //    Max: elements[0].value + elements[n-1].value + h
    //
    // Overall min_f: min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // Overall max_f: max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)
    //
    // This strategy is only better if the max_f is smaller than default_goodness_both_non_empty,
    // or if min_f is larger.
    //
    // Let's check the goodness for this specific partition.
    // min_f_candidate = min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    // max_f_candidate = max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    // goodness_candidate = max_f_candidate - min_f_candidate;
    //
    // This specific partition is only relevant if elements[0].value + elements[n-1].value + h is smaller than
    // elements[n-2].value + elements[n-1].value + h.
    // This happens if elements[0].value < elements[n-2].value.
    //
    // The key observation is that if we put elements[0] in one partition and the rest in another,
    // the maximum value of f will be max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h).
    // The minimum value of f will be min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h).
    //
    // The condition for this partition to be better than the "all in one" partition is:
    // (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value) >
    // max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h) -
    // min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //
    // This is equivalent to checking if elements[0].value + elements[1].value + h is "small enough"
    // compared to elements[1].value + elements[2].value.
    //
    // The critical condition is whether elements[0].value + elements[1].value + h is less than
    // elements[n-1].value + elements[n-2].value.
    // If elements[0].value + elements[1].value + h < elements[n-1].value + elements[n-2].value,
    // then the minimum f value could be elements[0].value + elements[1].value + h.
    //
    // The crucial comparison is between `elements[0].value + elements[1].value + h` and `elements[1].value + elements[2].value`.
    // If `elements[0].value + h < elements[2].value`, then `elements[0].value + elements[1].value + h < elements[1].value + elements[2].value`.
    // In this case, the minimum f value would be `elements[0].value + elements[1].value + h`.
    // The maximum f value would be `elements[0].value + elements[n-1].value + h` (since `elements[0].value + elements[n-1].value + h` is likely larger than `elements[n-2].value + elements[n-1].value`).
    //
    // Let's consider the partition where elements[0] is in S1 and all others are in S2.
    // min_f_alt = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    // max_f_alt = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    // goodness_alt = max_f_alt - min_f_alt;
    //
    // This is the goodness if we put elements[0] in one group and the rest in another.
    // This is only better than the "all in one" case if `elements[0].value + h` is small.
    // Specifically, if `elements[0].value + h < elements[n-1].value`.
    //
    // The condition for the alternative partition to be better is:
    // `elements[0].value + h < elements[n-1].value`
    // This means that `elements[0].value + elements[n-1].value + h` is not necessarily the largest value.
    //
    // Let's re-evaluate the two main scenarios:
    // Scenario A: All elements in one partition.
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[n-2].value + elements[n-1].value
    //   goodness_A = max_f - min_f
    //
    // Scenario B: At least one element in each partition.
    //   This implies that `h` terms are always present.
    //   The smallest possible `a_i + a_j` is `elements[0].value + elements[1].value`.
    //   The smallest possible `a_i + a_j + h` is `elements[0].value + elements[1].value + h`.
    //   So, `min_f` is always `elements[0].value + elements[1].value`.
    //   The largest possible `a_i + a_j` is `elements[n-2].value + elements[n-1].value`.
    //   The largest possible `a_i + a_j + h` is `elements[n-2].value + elements[n-1].value + h`.
    //   So, `max_f` is always `elements[n-2].value + elements[n-1].value + h`.
    //   goodness_B = (elements[n-2].value + elements[n-1].value + h) - (elements[0].value + elements[1].value)
    //
    // The only way to improve on goodness_B is if we can make `max_f` smaller or `min_f` larger.
    //
    // Consider the partition where `elements[0]` is in S1, and `elements[1], ..., elements[n-1]` are in S2.
    // Values generated:
    // 1. `elements[i].value + elements[j].value` for `i,j \in [1, n-1]`.
    //    Min: `elements[1].value + elements[2].value`
    //    Max: `elements[n-2].value + elements[n-1].value`
    // 2. `elements[0].value + elements[j].value + h` for `j \in [1, n-1]`.
    //    Min: `elements[0].value + elements[1].value + h`
    //    Max: `elements[0].value + elements[n-1].value + h`
    //
    // Overall min_f for this partition: `std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)`
    // Overall max_f for this partition: `std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)`
    //
    // Let's call this `goodness_C`.
    long long min_f_C = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    long long max_f_C = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    long long goodness_C = max_f_C - min_f_C;

    if (goodness_C < min_goodness) {
        min_goodness = goodness_C;
        partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition[elements[i].original_index] = 2;
        }
    }

    // The other symmetric case: elements[n-1] in S1, rest in S2.
    // This is symmetric to the previous case, and will yield the same goodness_C.
    // The only difference is which element is isolated.
    // The problem asks for *any* correct answer. So we don't need to check this explicitly.

    // What if n=2?
    // elements[0], elements[1]
    // Case A: All in one. S1={a0, a1}, S2={}. f(a0,a1) = a0+a1. min_f=max_f=a0+a1. goodness=0.
    // Case B: a0 in S1, a1 in S2. f(a0,a1) = a0+a1+h. min_f=max_f=a0+a1+h. goodness=0.
    // So for n=2, goodness is always 0.
    // My code:
    // min_goodness = (elements[0].value + elements[1].value) - (elements[0].value + elements[1].value) = 0. Correct.
    // goodness_C:
    // min_f_C = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    // This will access elements[2] which is out of bounds for n=2.
    // Need to handle n=2 separately or ensure indices are valid.
    // For n=2, elements[n-2] is elements[0], elements[n-1] is elements[1].
    // elements[1].value + elements[2].value is invalid.
    //
    // If n=2:
    // S1 = {elements[0], elements[1]}, S2 = {}
    // f values: {elements[0].value + elements[1].value}
    // min_f = max_f = elements[0].value + elements[1].value
    // goodness = 0
    //
    // S1 = {elements[0]}, S2 = {elements[1]}
    // f values: {elements[0].value + elements[1].value + h}
    // min_f = max_f = elements[0].value + elements[1].value + h
    // goodness = 0
    //
    // So for n=2, min_goodness is always 0.
    // The current code for n=2:
    // min_goodness = (elements[0].value + elements[1].value) - (elements[0].value + elements[1].value) = 0.
    // This is correct.
    // The goodness_C calculation needs to be conditional on n > 2.
    if (n > 2) {
        long long min_f_C_val = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        long long max_f_C_val = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
        long long goodness_C_val = max_f_C_val - min_f_C_val;

        if (goodness_C_val < min_goodness) {
            min_goodness = goodness_C_val;
            partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

long long N, M;
std::vector<long long> H, P;

bool check(long long T) {
    std::vector<long long> p_to_cover;
    std::set<long long> p_set(P.begin(), P.end());

    for (long long h_val : H) {
        if (p_set.count(h_val)) {
            p_set.erase(h_val);
        }
    }
    p_to_cover.assign(p_set.begin(), p_set.end());

    if (p_to_cover.empty()) {
        return true;
    }

    long long current_p_idx = 0;
    for (long long h_val : H) {
        if (current_p_idx >= p_to_cover.size()) {
            break;
        }

        long long p_start = p_to_cover[current_p_idx];

        // Case 1: Head moves left to cover p_start
        // Head moves from h_val to h_val - T. Covers [h_val - T, h_val].
        // If p_start is in this range, it's covered.
        // The rightmost point covered by this head is h_val.
        // The leftmost point covered by this head is h_val - T.
        // If p_start is covered, we can potentially cover more points to the right.
        // The head can move from h_val to h_val - T.
        // The range covered is [h_val - T, h_val].
        // If p_start is in this range, it's covered.
        // The head can also move from h_val to h_val + T.
        // The range covered is [h_val, h_val + T].
        // If p_start is in this range, it's covered.

        // We need to cover p_start.
        // The head h_val can cover any range [x, y] such that y - x <= T and x <= h_val <= y.
        // Or, if it moves only left, [h_val - k, h_val] where k <= T.
        // Or, if it moves only right, [h_val, h_val + k] where k <= T.
        // Or, if it moves left then right, or right then left, it covers [min_pos, max_pos].
        // The total distance moved is max_pos - min_pos.
        // The time taken is max(abs(h_val - min_pos), abs(h_val - max_pos)).
        // This is incorrect. The time taken is max(abs(h_val - min_pos), abs(h_val - max_pos)) if it moves to min_pos and max_pos.
        // If it moves from h_val to x, it takes abs(h_val - x) time.
        // If it moves from h_val to x, it covers [min(h_val, x), max(h_val, x)].
        // So, if it moves to x, it covers [min(h_val, x), max(h_val, x)].
        // The time taken is abs(h_val - x).
        // So, for a given T, a head at h_val can cover [h_val - T, h_val + T].
        // This is the range of points it can *reach*.
        // If it reaches x, it covers [min(h_val, x), max(h_val, x)].
        // The problem states: "A track is considered read if at least one head has visited this track."
        // "if a head moves from h to h', all tracks in [min(h, h'), max(h, h')] are read."
        // So, a head at h_val can move to x, taking abs(h_val - x) time.
        // If we want to cover a range [L, R], and h_val is in [L, R],
        // then the time taken is max(R - h_val, h_val - L).
        // If h_val < L, then it must move to L, and then to R. Time is R - h_val.
        // If h_val > R, then it must move to R, and then to L. Time is h_val - L.

        // The strategy for each head is to cover the leftmost uncovered point p_start,
        // and then extend its coverage as far right as possible.
        // If h_val is to the left of p_start (h_val < p_start):
        // The head must move at least to p_start. This takes p_start - h_val time.
        // If p_start - h_val > T, this head cannot cover p_start.
        // Otherwise, it has T - (p_start - h_val) time remaining for further movement.
        // It can move from h_val to p_start, and then further right to p_start + (T - (p_start - h_val)) = h_val + T.
        // So, it covers [h_val, h_val + T].
        // The actual range covered is [h_val, h_val + T].
        // The rightmost point covered is h_val + T.

        // If h_val is to the right of p_start (h_val > p_start):
        // The head must move at least to p_start. This takes h_val - p_start time.
        // If h_val - p_start > T, this head cannot cover p_start.
        // Otherwise, it has T - (h_val - p_start) time remaining for further movement.
        // It can move from h_val to p_start, and then further left to p_start - (T - (h_val - p_start)) = h_val - T.
        // So, it covers [h_val - T, h_val].
        // The actual range covered is [h_val - T, h_val].
        // The rightmost point covered is h_val.

        // If h_val is at p_start (h_val == p_start):
        // It takes 0 time to cover p_start.
        // It has T time remaining. It can move to h_val - T or h_val + T.
        // It can cover [h_val - T, h_val + T].
        // The rightmost point covered is h_val + T.

        // Combining these:
        // If h_val < p_start:
        //   If p_start - h_val > T, cannot cover p_start.
        //   Else, it covers [h_val, h_val + T]. Rightmost is h_val + T.
        // If h_val >= p_start:
        //   It can cover p_start by moving left. Time taken is h_val - p_start.
        //   If h_val - p_start > T, cannot cover p_start.
        //   Else, it covers [h_val - T, h_val + T - 2*(h_val - p_start)] if it moves to p_start and then extends.
        //   This is equivalent to saying it covers [h_val - T, h_val] if it moves left, or [h_val, h_val + T] if it moves right.
        //   The total range covered by a head at h_val in time T is [h_val - T, h_val + T].
        //   This is the range of points it can *reach*.
        //   If it reaches x, it covers [min(h_val, x), max(h_val, x)].
        //   To cover p_start, it must reach some x such that p_start is in [min(h_val, x), max(h_val, x)].
        //   And abs(h_val - x) <= T.

        // Let's simplify. A head at h_val can cover a segment [L, R] if:
        // 1. h_val is in [L, R]: time = max(R - h_val, h_val - L).
        // 2. h_val < L: time = R - h_val. (must move to L, then to R)
        // 3. h_val > R: time = h_val - L. (must move to R, then to L)
        // In all cases, the time taken is max(R - h_val, h_val - L, 0) if h_val is between L and R.
        // If h_val < L, time is R - h_val.
        // If h_val > R, time is h_val - L.
        // This is equivalent to saying:
        // If h_val is in [L, R], it can cover [L, R] if max(R - h_val, h_val - L) <= T.
        // If h_val < L, it can cover [L, R] if R - h_val <= T.
        // If h_val > R, it can cover [L, R] if h_val - L <= T.

        // We want to cover p_start.
        // The head h_val can cover a range [p_start, end_point].
        // We want to maximize end_point.
        // If h_val <= p_start:
        //   Time to reach p_start is p_start - h_val.
        //   Remaining time is T - (p_start - h_val).
        //   It can extend to the right by this remaining time.
        //   So, end_point = p_start + (T - (p_start - h_val)) = h_val + T.
        //   This is valid if p_start - h_val <= T.
        // If h_val > p_start:
        //   Time to reach p_start is h_val - p_start.
        //   Remaining time is T - (h_val - p_start).
        //   It can extend to the right by this remaining time, or to the left.
        //   To cover p_start and extend right, it moves from h_val to p_start, then to p_start + remaining_time.
        //   So, end_point = p_start + (T - (h_val - p_start)) = T + 2*p_start - h_val.
        //   This is valid if h_val - p_start <= T.

        long long current_coverage_right_end = -1;

        if (h_val <= p_start) {
            if (p_start - h_val <= T) {
                current_coverage_right_end = h_val + T;
            }
        } else { // h_val > p_start
            if (h_val - p_start <= T) {
                current_coverage_right_end = T + 2 * p_start - h_val;
            }
        }

        if (current_coverage_right_end == -1) { // This head cannot even reach p_start
            continue;
        }

        // This head covers [p_start, current_coverage_right_end].
        // Advance current_p_idx past all points covered by this head.
        while (current_p_idx < p_to_cover.size() && p_to_cover[current_p_idx] <= current_coverage_right_end) {
            current_p_idx++;
        }
    }

    return current_p_idx >= p_to_cover.size();
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N >> M;
    H.resize(N);
    P.resize(M);

    for (int i = 0; i < N; ++i) {
        std::cin >> H[i];
    }
    for (int i = 0; i < M; ++i) {
        std::cin >> P[i];
    }

    long long low = 0, high = 20000000000LL, ans = high; // Max diff is 10^10, so 2*10^10 is safe upper bound

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut, two pieces.
    // We can cut s into A and B, then form B+A.
    // We need B+A to be a palindrome and B+A != s.
    // The only way to get a different string B+A from A+B is if A != B.
