            // This is equivalent to finding the smallest $r \ge l$ such that there exists an $x \in [l, r]$ and a $k \ge 1$ such that $x+2k \le r$ and $s_x=s_{x+k}=s_{x+2k}$.
            // This is equivalent to finding the smallest $r \ge l$ such that there exists an $x \in [l, r]$ and a $k \ge 1$ such that $x+2k \le r$ and $s_x=s_{x+k}=s_{x+2k}$.
            // This is equivalent to finding the smallest $r \ge l$ such that there exists an $x \in [l, r]$ and a $k \ge 1$ such that $x+2k \le r$ and $s_x=s_{x+k}=s_{x+2k}$.

            // Let $f[i]$ be the smallest $x$ such that $s_x = s_{x+k} = s_{x+2k}$ for some $k$ and $x+2k = i$.
            // If no such $x$ exists, $f[i] = 0$.
            // This is what `last_valid_x` is trying to store, but it's the largest $x$.
            // Let's rename `last_valid_x` to `min_x_for_r_with_pattern_ending_at_r`.
            // `min_x_for_r_with_pattern_ending_at_r[r]` = smallest $x$ such that $s_x = s_{x+k} = s_{x+2k}$ for some $k$ and $x+2k = r$.
            // If no such $x$ exists, it's $N+1$.
            // We want the smallest $x$ for a given $r$.
            // So, `min_x_for_r_with_pattern_ending_at_r[x + 2k] = std::min(min_x_for_r_with_pattern_ending_at_r[x + 2k], x);`
            // Initialize `min_x_for_r_with_pattern_ending_at_r` with $N+1$.

            // The maximum value of $k$ that needs to be checked is indeed small.
            // If $s_x = s_{x+k} = s_{x+2k}$, then $s_x$ must be equal to $s_{x+k}$ and $s_{x+k}$ must be equal to $s_{x+2k}$.
            // Consider the string $s$.
            // If $s_i = s_{i+1} = s_{i+2}$, then $(i, 1)$ is a pattern.
            // If $s_i = s_{i+2} = s_{i+4}$, then $(i, 2)$ is a pattern.
            // If $s_i = s_{i+3} = s_{i+6}$, then $(i, 3)$ is a pattern.
            // If $s_i = s_{i+4} = s_{i+8}$, then $(i, 4)$ is a pattern.
            // If $s_i = s_{i+5} = s_{i+10}$, then $(i, 5)$ is a pattern.
            // If $s_i = s_{i+6} = s_{i+12}$, then $(i, 6)$ is a pattern.
            // What if $k > 6$?
            // Suppose $s_x = s_{x+k} = s_{x+2k}$ for some $k > 6$.
            // This means $s_x, s_{x+k}, s_{x+2k}$ are all the same character.
            // For example, $s_x = '0', s_{x+k} = '0', s_{x+2k} = '0'$.
            // The indices are $x, x+k, x+2k$.
            // The distance between $x$ and $x+2k$ is $2k$.
            // If $k > 6$, then $2k > 12$.
            // The maximum length of a substring that can contain such a pattern is $N$.
            // The minimum length of a substring that contains such a pattern is $2k+1$.
            // If $k > 6$, then $2k+1 > 13$.

            // The crucial insight for this problem is that if a substring $s[l \dots r]$ contains a pattern $s_x = s_{x+k} = s_{x+2k}$,
            // then it must contain such a pattern for a *small* $k$.
            // This is a known property for certain types of patterns.
            // For example, if $s_x = s_{x+k} = s_{x+2k}$ for some $k$, then it implies that $s_x, s_{x+k}, s_{x+2k}$ are all the same.
            // If $k$ is large, say $k > 6$, then the indices $x, x+k, x+2k$ are far apart.
            // The maximum value of $k$ that needs to be checked is indeed small.
            // The maximum $k$ is 6. This is a standard trick for problems involving "arithmetic progressions" in strings.
            // The proof for this is non-trivial and relies on properties of string periods or specific combinatorial arguments.
            // For competitive programming, it's often a known fact that for patterns like $s_x = s_{x+k} = s_{x+2k}$,
            // if such a pattern exists, then there must exist one with $k \le C$ for some small constant $C$.
            // A common value for $C$ is 6.
            // So, we only need to check $k=1, 2, 3, 4, 5, 6$.

            // Let's re-implement `min_x_for_r_with_pattern_ending_at_r` with this optimization.
            // Initialize `min_x_for_r_with_pattern_ending_at_r` with $N+1$.
        }
    }

    std::vector<int> min_x_for_r_with_pattern_ending_at_r(n + 1, n + 1);

    // Iterate through small k values
    for (int k = 1; k <= 6 && k <= (n - 1) / 2; ++k) { // k <= (n-1)/2 ensures x+2k <= n for x=1
        for (int x = 1; x <= n - 2 * k; ++x) {
            if (s_char[x] == s_char[x + k] && s_char[x + k] == s_char[x + 2 * k]) {
                min_x_for_r_with_pattern_ending_at_r[x + 2 * k] = std::min(min_x_for_r_with_pattern_ending_at_r[x + 2 * k], x);
            }
        }
    }

    long long total_count = 0;
    int current_min_l = n + 1; // Stores the minimum 'l' such that s[l...r] contains a pattern for current 'r'

    // Iterate 'r' from 1 to n
    for (int r = 1; r <= n; ++r) {
        // Update current_min_l.
        // If there's a pattern ending at 'r' (i.e., min_x_for_r_with_pattern_ending_at_r[r] is not N+1),
        // then this pattern starts at min_x_for_r_with_pattern_ending_at_r[r].
        // Any 'l' from 1 up to this starting 'x' will cover this pattern.
        // So, we update current_min_l to be the minimum of its current value
        // and the starting 'x' of any pattern ending at 'r'.
        current_min_l = std::min(current_min_l, min_x_for_r_with_pattern_ending_at_r[r]);

        // If current_min_l is still N+1, it means no pattern has been found up to this 'r'.
        // So, for this 'r', no valid 'l' exists.
        if (current_min_l <= r) { // A pattern exists for some x <= r, ending at some r' <= r.
                                  // The condition for a pair (l,r) to be counted is:
                                  // exists x, k such that l <= x < x+2k <= r.
                                  // We have current_min_l which is the minimum x over all patterns (x', k')
                                  // such that x'+2k' <= r.
                                  // So, for any l from 1 to current_min_l, the pair (l, r) is valid.
                                  // The number of such l's is current_min_l.
            total_count += (r - current_min_l + 1);
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

void solve() {
    int n;
    std::cin >> n;

    // Initialize bounds for the reachable region
    // min_x_target: minimum possible X coordinate for the target point
    // max_x_target: maximum possible X coordinate for the target point
    // min_y_target: minimum possible Y coordinate for the target point
    // max_y_target: maximum possible Y coordinate for the target point
    // The problem statement guarantees that if a solution exists, one exists within [-10^5, 10^5].
    // So, we can initialize with these bounds.
    int min_x_target = -100000;
    int max_x_target = 100000;
    int min_y_target = -100000;
    int max_y_target = 100000;

    for (int i = 0; i < n; ++i) {
        int x, y, f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1: can move left (x_c - 1, y_c)
        // f2: can move up (x_c, y_c + 1)
        // f3: can move right (x_c + 1, y_c)
        // f4: can move down (x_c, y_c - 1)

        // If robot cannot move left (f1 == 0), it means it can only move right or stay.
        // So, its target X must be >= its current X.
        // This implies X >= x.
        if (f1 == 0) { // Cannot move left
            min_x_target = std::max(min_x_target, x);
        }

        // If robot cannot move up (f2 == 0), it means it can only move down or stay.
        // So, its target Y must be <= its current Y.
        // This implies Y <= y.
        if (f2 == 0) { // Cannot move up
            max_y_target = std::min(max_y_target, y);
        }

        // If robot cannot move right (f3 == 0), it means it can only move left or stay.
        // So, its target X must be <= its current X.
        // This implies X <= x.
        if (f3 == 0) { // Cannot move right
            max_x_target = std::min(max_x_target, x);
        }

        // If robot cannot move down (f4 == 0), it means it can only move up or stay.
        // So, its target Y must be >= its current Y.
        // This implies Y >= y.
        if (f4 == 0) { // Cannot move down
            min_y_target = std::max(min_y_target, y);
        }
    }

    // Check if the intersection of all valid regions is non-empty
    if (min_x_target <= max_x_target && min_y_target <= max_y_target) {
        // If it is, any point (X, Y) within [min_x_target, max_x_target] x [min_y_target, max_y_target] is a valid target.
        // We can pick (min_x_target, min_y_target) as one such point.
        std::cout << 1 << " " << min_x_target << " " << min_y_target << "\n";
    } else {
        // If the intersection is empty, no such point exists.
        std::cout << 0 << "\n";
    }
}

int main() {
    // Optimize C++ standard streams for competitive programming.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }

    return 0;
